ing probability mass.\",\"maximum\":1,\"minimum\":0,\"title\":\"Top P\",\"type\":\"number\"}},\"required\":[\"prompt\",\"image\"],\"title\":\"ChatInput\",\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"system_prompt\",\"reasoning_mode\",\"max_tokens\",\"temperature\",\"top_p\",\"enable_sync_mode\"]}}]}', '{\"model_id\":\"nvidia/nemotron-3-nano-omni/vision\",\"name\":\"nvidia/nemotron-3-nano-omni/vision\",\"base_price\":0.006,\"formula\":\"{\\\"total_price\\\": base_price * $number(max_tokens) / 1000}\",\"description\":\"NVIDIA Nemotron 3 Nano Omni is an open, efficient reasoning model for enterprise agentic workflows, built on a 30B A3B hybrid Transformer-Mamba MoE architecture. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-text\",\"sort_order\":60,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/nvidia/nemotron-3-nano-omni/vision\",\"request_schema\":{\"properties\":{\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"image\":{\"description\":\"Image URL to analyze with the model.\",\"title\":\"Image\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"max_tokens\":{\"default\":1024,\"description\":\"Maximum number of tokens to generate.\",\"minimum\":1,\"title\":\"Max Tokens\",\"type\":\"integer\"},\"prompt\":{\"description\":\"Text prompt to send to the model. English only.\",\"title\":\"Prompt\",\"type\":\"string\"},\"reasoning_mode\":{\"default\":\"no_think\",\"description\":\"Whether the model should emit an explicit reasoning trace.\",\"enum\":[\"no_think\",\"think\"],\"title\":\"Reasoning Mode\",\"type\":\"string\"},\"system_prompt\":{\"description\":\"Optional system prompt to steer the model.\",\"title\":\"System Prompt\",\"type\":\"string\"},\"temperature\":{\"default\":0.7,\"description\":\"Sampling temperature. Lower values are more deterministic.\",\"minimum\":0,\"title\":\"Temperature\",\"type\":\"number\"},\"top_p\":{\"default\":0.95,\"description\":\"Nucleus sampling probability mass.\",\"maximum\":1,\"minimum\":0,\"title\":\"Top P\",\"type\":\"number\"}},\"required\":[\"prompt\",\"image\"],\"title\":\"ChatInput\",\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"system_prompt\",\"reasoning_mode\",\"max_tokens\",\"temperature\",\"top_p\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:07.733', '2026-06-09 08:56:07.733', '2026-06-09 08:56:07.733');
