 of image to use while generating the 3D model.\",\"type\":\"string\"},\"left_image_url\":{\"description\":\"URL of image to use while generating the 3D model.\",\"type\":\"string\"}},\"required\":[\"front_image_url\",\"back_image_url\",\"left_image_url\"],\"title\":\"Hunyuan3DInputMultiView\",\"type\":\"object\",\"x-order-properties\":[\"front_image_url\",\"back_image_url\",\"left_image_url\"]}}]}}', '2026-06-09 08:56:07.509', '2026-06-09 08:56:07.509', '2026-06-09 08:56:07.509');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('012c567e-3299-486f-9fd5-584ac27b41d0', NULL, 'cmq0hadjp0000si8dckyresaj', 'luma/modify-video', 'luma/modify-video', 'VIDEO', 0.095, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/luma/modify-video\",\"request_schema\":{\"properties\":{\"first_frame\":{\"description\":\"Optional modified version of the original first frame to guide the video transformation.\",\"format\":\"uri\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"mode\":{\"default\":\"adhere_1\",\"description\":\"Controls how closely the output follows the source video. Adhere: subtle enhancements staying very close to original. Flex: allows stylistic changes while keeping recognizable elements. Reimagine: dramatic transformations loosely following the source.\",\"enum\":[\"adhere_1\",\"adhere_2\",\"adhere_3\",\"flex_1\",\"flex_2\",\"flex_3\",\"reimagine_1\",\"reimagine_2\",\"reimagine_3\"],\"type\":\"string\"},\"prompt\":{\"description\":\"Text instruction to guide how the video should be modified or restyled.\",\"type\":\"string\"},\"video\":{\"description\":\"The source video to modify. Maximum file size is 100MB and maximum duration is 30 seconds.\",\"format\":\"uri\",\"type\":\"string\"}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"prompt\",\"mode\",\"first_frame\"]}}]}', '{\"model_id\":\"luma/modify-video\",\"name\":\"luma/modify-video\",\"base_price\":0.095,\"formula\":\"{\\\"total_price\\\": ( video and video != \\\"\\\" ? ( $number(get_duration_v3(video)) <= 5 ? $number(base_price) : ( $min([ $number(get_duration_v3(video)), 30 ]) / 5 * $number(base_price) ) ) : $number(base_price) )}\",\"description\":\"Transform and restyle existing videos with AI-powered modifications. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"video-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/luma/modify-video\",\"request_schema\":{\"properties\":{\"first_frame\":{\"description\":\"Optional modified version of the original first frame to guide the video transformation.\",\"format\":\"uri\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"mode\":{\"default\":\"adhere_1\",\"description\":\"Controls how closely the output follows the source video. Adhere: subtle enhancements staying very close to original. Flex: allows stylistic changes while keeping recognizable elements. Reimagine: dramatic transformations loosely following the source.\",\"enum\":[\"adhere_1\",\"adhere_2\",\"adhere_3\",\"flex_1\",\"flex_2\",\"flex_3\",\"reimagine_1\",\"reimagine_2\",\"reimagine_3\"],\"type\":\"string\"},\"prompt\":{\"description\":\"Text instruction to guide how the video should be modified or restyled.\",\"type\":\"string\"},\"video\":{\"description\":\"The source video to modify. Maximum file size is 100MB and maximum duration is 30 seconds.\",\"format\":\"uri\",\"type\":\"string\"}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"prompt\",\"mode\",\"first_frame\"]}}]}}', '2026-06-09 08:56:06.837', '2026-06-09 08:56:06.837', '2026-06-09 08:56:06.837');
