/5 : 1)}\",\"description\":\"Sourceful Riverflow 2.0 Pro Edit is an agentic image model optimized for robust, high-precision image editing and transformation. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/sourceful/riverflow-2.0-pro/edit\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"auto\",\"description\":\"Aspect ratio of the output image. Use \'auto\' to preserve source aspect ratio.\",\"enum\":[\"auto\",\"21:9\",\"16:9\",\"3:2\",\"4:3\",\"5:4\",\"1:1\",\"4:5\",\"3:4\",\"2:3\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"images\":{\"description\":\"Source images for editing (1-10 images required).\",\"items\":{\"format\":\"uri\",\"type\":\"string\"},\"maxItems\":10,\"minItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"prompt\":{\"description\":\"Text description of the edits you want to make to the source images.\",\"type\":\"string\"},\"resolution\":{\"default\":\"1k\",\"description\":\"Output image resolution. Higher resolution produces more detailed images but costs more.\",\"enum\":[\"1k\",\"2k\",\"4k\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"transparency\":{\"default\":false,\"description\":\"Enable transparent background when supported by the edited content.\",\"type\":\"boolean\"}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"resolution\",\"aspect_ratio\",\"transparency\"]}}]}}', '2026-06-09 08:56:07.029', '2026-06-09 08:56:07.029', '2026-06-09 08:56:07.029');
