40p\",\"720p\",\"1080p\"],\"type\":\"string\"}},\"required\":[\"images\",\"audio\"],\"type\":\"object\",\"x-order-properties\":[\"images\",\"audio\",\"prompt\",\"aspect_ratio\",\"resolution\",\"add_subtitle\"]}}]}}', '2026-06-09 08:56:06.968', '2026-06-09 08:56:06.968', '2026-06-09 08:56:06.968');
