e.\",\"enum\":[\"4k_Quad\",\"8k_Quad\",\"18k_Quad\",\"50k_Quad\",\"2K_Triangle\",\"20K_Triangle\",\"250K_Triangle\",\"500K_Triangle\"],\"type\":\"string\"},\"seed\":{\"description\":\"Seed for random number generator. Set to 0 to use a random seed.\",\"maximum\":65535,\"minimum\":0,\"type\":\"integer\"},\"ta_pose\":{\"description\":\"Control the generation result to T/A Pose.\",\"type\":\"boolean\"},\"use_original_alpha\":{\"description\":\"Used when processing the image.\",\"type\":\"boolean\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"material\",\"quality_and_mesh\",\"geometry_file_format\",\"addons\",\"bbox_condition\",\"ta_pose\",\"use_original_alpha\",\"preview_render\",\"seed\"]}}]}', '{\"model_id\":\"hyper3d/rodin-v2/text-to-3d\",\"name\":\"hyper3d/rodin-v2/text-to-3d\",\"base_price\":0.3,\"formula\":\"\",\"description\":\"Hyper3D Rodin v2 generates production-ready 3D assets from text prompts, delivering clean meshes with UVs and textures. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-3d\",\"sort_order\":2010,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/hyper3d/rodin-v2/text-to-3d\",\"request_schema\":{\"properties\":{\"addons\":{\"description\":\"Generate 4K resolution texture instead of the default 2K.\\nIf Quad mode, the number of faces will be ~16 times of the number of faces selected in the quality parameter.\",\"enum\":[\"HighPack\"],\"type\":\"string\"},\"bbox_condition\":{\"description\":\"This is a controlnet that controls the maxmimum sized of the generated model.\",\"items\":{\"properties\":{\"height\":{\"description\":\"Height(Y-axis)\",\"step\":1,\"type\":\"integer\"},\"length\":{\"description\":\"Length(Z-axis)\",\"step\":1,\"type\":\"integer\"},\"width\":{\"description\":\"Width(X-axis)\",\"step\":1,\"type\":\"integer\"}},\"required\":[\"width\",\"height\",\"length\"],\"type\":\"object\",\"x-order-properties\":[\"width\",\"height\",\"length\"]},\"type\":\"array\",\"x-hidden\":true,\"x-ui-component\":\"array\"},\"geometry_file_format\":{\"description\":\"The format of the output geometry file. \",\"enum\":[\"glb\",\"fbx\",\"obj\",\"stl\",\"usdz\"],\"type\":\"string\"},\"material\":{\"description\":\"The material type. \",\"enum\":[\"PBR\",\"All\",\"Shaded\"],\"type\":\"string\"},\"preview_render\":{\"description\":\"Provided in the download list.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"A textual prompt to guide the model generation.\",\"minLength\":1,\"type\":\"string\"},\"quality_and_mesh\":{\"description\":\"The generation quality and mesh mode.\",\"enum\":[\"4k_Quad\",\"8k_Quad\",\"18k_Quad\",\"50k_Quad\",\"2K_Triangle\",\"20K_Triangle\",\"250K_Triangle\",\"500K_Triangle\"],\"type\":\"string\"},\"seed\":{\"description\":\"Seed for random number generator. Set to 0 to use a random seed.\",\"maximum\":65535,\"minimum\":0,\"type\":\"integer\"},\"ta_pose\":{\"description\":\"Control the generation result to T/A Pose.\",\"type\":\"boolean\"},\"use_original_alpha\":{\"description\":\"Used when processing the image.\",\"type\":\"boolean\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"material\",\"quality_and_mesh\",\"geometry_file_format\",\"addons\",\"bbox_condition\",\"ta_pose\",\"use_original_alpha\",\"preview_render\",\"seed\"]}}]}}', '2026-06-09 08:56:05.980', '2026-06-09 08:56:05.980', '2026-06-09 08:56:05.980');
