INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('07e5edf4-e97b-49e9-b270-338e00353a1f', NULL, 'cmq0hadjp0000si8dckyresaj', 'mirelo-ai/sfx-1.6/extend-audio', 'mirelo-ai/sfx-1.6/extend-audio', 'AUDIO', 0.01, NULL, NULL, 1742, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/mirelo-ai/sfx-1.6/extend-audio\",\"request_schema\":{\"properties\":{\"ambience\":{\"default\":false,\"description\":\"When true, extend and stitch the result so the tile loops seamlessly.\",\"type\":\"boolean\",\"x-ui-component\":\"checkbox\"},\"append_duration\":{\"default\":10,\"description\":\"Seconds to add after the prefix. Total output is capped at 60 seconds.\",\"maximum\":57,\"minimum\":1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"audio\":{\"description\":\"Audio prefix to extend. Prefix duration must be 3 to 59 seconds, and total output is capped at 60 seconds.\",\"type\":\"string\",\"x-accept\":\"audio/mpeg,audio/mp3,audio/wav,audio/x-wav,audio/aac,audio/flac\",\"x-placeholder\":\"Upload or link to an audio file\",\"x-ui-component\":\"uploader\"},\"double_output\":{\"default\":false,\"description\":\"Only used when ambience is true: concatenate the loop with itself for a 2x-length output.\",\"type\":\"boolean\",\"x-ui-component\":\"checkbox\"},\"num_samples\":{\"default\":1,\"description\":\"Number of variations to generate.\",\"maximum\":4,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"prompt\":{\"description\":\"Optional text prompt guiding the extension.\",\"type\":\"string\",\"x-rows\":3,\"x-ui-component\":\"textarea\"}},\"required\":[\"audio\"],\"type\":\"object\",\"x-order-properties\":[\"audio\",\"prompt\",\"append_duration\",\"ambience\",\"double_output\",\"num_sam