INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('11b1f244-838b-4cd4-a8ec-d5541ade6eab', NULL, 'cmq0hadjp0000si8dckyresaj', 'alibaba/wan-2.7/video-edit', 'alibaba/wan-2.7/video-edit', 'VIDEO', 0.5, NULL, NULL, 6800, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.7/video-edit\",\"request_schema\":{\"properties\":{\"audio_setting\":{\"default\":\"auto\",\"description\":\"Audio setting. \'auto\' (default): model decides based on prompt content. \'origin\': keep original audio from input video.\",\"enum\":[\"auto\",\"origin\"],\"type\":\"string\"},\"duration\":{\"default\":0,\"description\":\"Duration of the output video in seconds. 0 means use input video length (max 10s). Set 2-10 to trim from 0s to specified length.\",\"maximum\":10,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"If set to true, the prompt optimizer will be enabled.\",\"type\":\"boolean\"},\"images\":{\"description\":\"List of reference images for video editing (0-3 images, optional).\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated video.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"video\":{\"description\":\"The source video to edit.\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"video/*\"}}},\"required\":[\"video\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"images\",\"negative_prompt\",\"resolution\",\"duration\",\"audio_setting\",\"enable_prompt_expansion\",\"seed\"]}}]}', '{\"model_id\":\"alibaba/wan-2.7/video-edit\",\"name\":\"alibaba/wan-2.7/video-edit\",\"base_price\":0.5,\"formula\":\"{\\\"total_price\\\": base_price * (($number(duration) = 0) ? $min([$max([get_duration_v3(video), 2]), 10]) : $min([$max([$number(duration), 2]), 10])) / 5 * ((resolution = \\\"1080p\\\") ? 1.5 : 1) }\",\"description\":\"Alibaba WAN 2.7 Video Edit performs prompt-driven video editing with multi-image reference support, supporting 720p/1080p output. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"video-to-video\",\"sort_order\":6800,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.7/video-edit\",\"request_schema\":{\"properties\":{\"audio_setting\":{\"default\":\"auto\",\"description\":\"Audio setting. \'auto\' (default): model decides based on prompt content. \'origin\': keep original audio from input video.\",\"enum\":[\"auto\",\"origin\"],\"type\":\"string\"},\"duration\":{\"default\":0,\"description\":\"Duration of the output video in seconds. 0 means use input video length (max 10s). Set 2-10 to trim from 0s to specified length.\",\"maximum\":10,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"If set to true, the prompt optimizer will be enabled.\",\"type\":\"boolean\"},\"images\":{\"description\":\"List of reference images for video editing (0-3 images, optional).\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated video.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"video\":{\"description\":\"The source video to edit.\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"video/*\"}}},\"required\":[\"video\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"images\",\"negative_prompt\",\"resolution\",\"duration\",\"audio_setting\",\"enable_prompt_expansion\",\"seed\"]}}]}}', '2026-06-09 08:56:05.664', '2026-06-09 08:56:05.664', '2026-06-09 08:56:05.664');
