"style\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"recraft-ai/recraft-v3\",\"name\":\"recraft-ai/recraft-v3\",\"base_price\":0.04,\"formula\":\"\",\"description\":\"Recraft V3 (red_panda) is a state-of-the-art text-to-image model that excels with long text prompts and generates diverse, high-fidelity images across many styles. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/recraft-ai/recraft-v3\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"1:1\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"16:9\",\"9:16\",\"4:3\",\"3:4\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"style\":{\"description\":\"Style of the generated image.\",\"enum\":[\"realistic_image\",\"digital_illustration\",\"digital_illustration/pixel_art\",\"digital_illustration/hand_drawn\",\"digital_illustration/grain\",\"digital_illustration/infantile_sketch\",\"digital_illustration/2d_art_poster\",\"digital_illustration/handmade_3d\",\"digital_illustration/hand_drawn_outline\",\"digital_illustration/engraving_color\",\"digital_illustration/2d_art_poster_2\",\"realistic_image/b_and_w\",\"realistic_image/hard_flash\",\"realistic_image/hdr\",\"realistic_image/natural_light\",\"realistic_image/studio_portrait\",\"realistic_image/enterprise\",\"realistic_image/motion_blur\"],\"type\":\"string\",\"x-placeholder\":\"Select the style\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\"],\"type\