\":60,\"description\":\"Audio length in seconds.\",\"maximum\":240,\"minimum\":5,\"type\":\"number\"},\"instrumental\":{\"default\":false,\"description\":\"Whether to generate an instrumental version.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"Prompt to control the style of the generated audio. This will be used to generate tags and lyrics.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed for reproducibility.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"instrumental\",\"duration\",\"seed\"]}}]}}', '2026-06-09 08:56:06.402', '2026-06-09 08:56:06.402', '2026-06-09 08:56:06.402');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('12c96680-c62c-4225-addf-caa4e80acd66', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/omnivoice/text-to-speech', 'wavespeed-ai/omnivoice/text-to-speech', 'AUDIO', 0.005, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/omnivoice/text-to-speech\",\"request_schema\":{\"properties\":{\"speed\":{\"default\":1,\"description\":\"Playback speed factor. 1.0 = normal speed. Values > 1.0 are faster, < 1.0 are slower.\",\"maximum\":5,\"minimum\":0.1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"text\":{\"description\":\"The text content to convert into speech. Supports 600+ languages.\",\"type\":\"string\",\"x-rows\":5,\"x-ui-component\":\"textarea\"},\"voice_description\":{\"description\":\"Comma-separated voice attributes. If omitted, a random voice is used. Valid English attributes: female, male, child, teenager, young adult, middle-aged, elderly, low pitch, moderate pitch, high pitch, very low pitch, very high pitch, whisper, american accent, australian accent, british accent, canadian accent, chinese accent, indian accent, japanese accent, korean accent, portuguese accent, russian accent. Example: \'female, low pitch, british accent\'.\",\"type\":\"string\",\"x-rows\":3,\"x-ui-component\":\"textarea\"}},\"required\":[\"text\"],\"type\":\"object\",\"x-order-properties\":[\"text\",\"voice_description\",\"speed\"]}}]}', '{\"model_id\":\"wavespeed-ai/omnivoice/text-to-speech\",\"name\":\"wavespeed-ai/omnivoice/text-to-speech\",\"base_price\":0.005,\"formula\":\"{\\\"total_price\\\": $length(text) < 100 ? base_price * 1.0 : base_price * $length(text) / 100}\",\"description\":\"OmniVoice: Massively multilingual zero-shot TTS supporting 600+ languages. Generate speech with auto voice or design custom voices using natural language descriptions. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"text-to-audio\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/omnivoice/text-to-speech\",\"request_schema\":{\"properties\":{\"speed\":{\"default\":1,\"description\":\"Playback speed factor. 1.0 = normal speed. Values > 1.0 are faster, < 1.0 are slower.\",\"maximum\":5,\"minimum\":0.1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"text\":{\"description\":\"The text content to convert into speech. Supports 600+ languages.\",\"type\":\"string\",\"x-rows\":5,\"x-ui-component\":\"textarea\"},\"voice_description\":{\"description\":\"Comma-separated voice attributes. If omitted, a random voice is used. Valid English attributes: female, male, child, teenager, young adult, middle-aged, elderly, low pitch, moderate pitch, high pitch, very low pitch, very high pitch, whisper, american accent, australian accent, british accent, canadian accent, chinese accent, indian accent, japanese accent, korean accent, portuguese accent, russian accent. Example: \'female, low pitch, british accent\'.\",\"type\":\"string\",\"x-rows\":3,\"x-ui-component\":\"textarea\"}},\"required\":[\"text\"],\"type\":\"object\",\"x-order-properties\":[\"text\",\"voice_description\",\"speed\"]}}]}}', '2026-06-09 08:56:07.383', '2026-06-09 08:56:07.383', '2026-06-09 08:56:07.383');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('12d306d1-be28-4705-bc5f-bc3b2c694c57', NULL, 'cmq0hadjp0000si8dckyresaj', 'sonilo/video-to-music', 'sonilo/video-to-music', 'VIDEO', 0.009, NULL, NULL, 10000, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/sonilo/video-to-music\",\"request_schema\":{\"properties\":{\"prompt\":{\"description\":\"Optional style prompt for the generated music.\",\"type\":\"string\",\"x-rows\":4,\"x-ui-component\":\"textarea\"},\"video\":{\"description\":\"Input video URL. Maximum supported video length is 360 seconds.\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"video/*\"}}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"prompt\"]}}]}', '{\"model_id\":\"sonilo/video-to-music\",\"name\":\"sonilo/video-to-music\",\"base_price\":0.009,\"formula\":\"{\\\"total_price\\\": base_price * $max([1, $ceil($min([$number(get_duration_v3(video)), 360]))])}\",\"description\":\"Sonilo Video-to-Music generates background music synced to an input video\'s mood, pacing, and scene transitions.\",\"type\":\"audio-to-video\",\"sort_order\":10000,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/sonilo/video-to-music\",\"request_schema\":{\"properties\":{\"prompt\":{\"description\":\"Optional style prompt for the generated music.\",\"type\":\"string\",\"x-rows\":4,\"x-ui-component\":\"textarea\"},\"video\":{\"description\":\"Input video URL. Maximum supported video length is 360 seconds.\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"video/*\"}}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"prompt\"]}}]}}', '2026-06-09 08:56:05.396', '2026-06-09 08:56:05.396', '2026-06-09 08:56:05.396');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('12ef03fe-cfa2-48c0-a29a-01f4b9d9b959', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/qwen-image/edit-multiple-angles', 'wavespeed-ai/qwen-image/edit-multiple-angles', 'IMAGE', 0.025, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/qwen-image/edit-multiple-angles\",\"request_schema\":{\"properties\":{\"distance\":{\"default\":1,\"description\":\"Camera distance/zoom level. 0 = close-up, 1 = medium shot, 2 = wide shot.\",\"maximum\":2,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"horizontal_angle\":{\"default\":0,\"description\":\"Horizontal rotation angle (azimuth) in degrees. Controls the camera\'s horizontal position around the subject. Values are rounded to the nearest valid angle: 0 (front), 45 (front-right), 90 (right), 135 (back-right), 180 (back), 225 (back-left), 270 (left), 315 (front-left).\",\"maximum\":359,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"images\":{\"description\":\"The input images. A maximum of 3 reference images can be uploaded.\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"minItems\":1,\"type\":\"array\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"Optional additional prompt to guide the generation. This is appended to the angle prompt.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\",\"x-hidden\":true},\"vertical_angle\":{\"default\":0,\"description\":\"Vertical tilt angle (elevation) in degrees. Controls the camera\'s vertical position. Values are rounded to the nearest valid angle: -30 (low angle), 0 (eye level), 30 (elevated), 60 (high angle).\",\"maximum\":60,\"minimum\":-30,\"type\":\"integer\",\"x-ui-component\":\"slider\"}},\"required\":[\"images\"],\"type\":\"object\",\"x-order-properties\":[\"images\",\"horizontal_angle\",\"vertical_angle\",\"distance\",\"prompt\",\"size\",\"seed\",\"output_format\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}', '{\"model_id\":\"wavespeed-ai/qwen-image/edit-multiple-angles\",\"name\":\"wavespeed-ai/qwen-image/edit-multiple-angles\",\"base_price\":0.025,\"formula\":\"\",\"description\":\"Qwen-Image-Edit Multiple Angles generates specific camera angles from a single image using a 96-pose camera system. Control horizontal rotation (azimuth), vertical tilt (elevation), and zoom level to create front, side, back views and more. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/qwen-image/edit-multiple-angles\",\"request_schema\":{\"properties\":{\"distance\":{\"default\":1,\"description\":\"Camera distance/zoom level. 0 = close-up, 1 = medium shot, 2 = wide shot.\",\"maximum\":2,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"horizontal_angle\":{\"default\":0,\"description\":\"Horizontal rotation angle (azimuth) in degrees. Controls the camera\'s horizontal position around the subject. Values are rounded to the nearest valid angle: 0 (front), 45 (front-right), 90 (right), 135 (back-right), 180 (back), 225 (back-left), 270 (left), 315 (front-left).\",\"maximum\":359,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"images\":{\"description\":\"The input images. A maximum of 3 reference images can be uploaded.\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"minItems\":1,\"type\":\"array\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"Optional additional prompt to guide the generation. This is appended to the angle prompt.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\",\"x-hidden\":true},\"vertical_angle\":{\"default\":0,\"description\":\"Vertical tilt angle (elevation) in degrees. Controls the camera\'s vertical position. Values are rounded to the nearest valid angle: -30 (low angle), 0 (eye level), 30 (elevated), 60 (high angle).\",\"maximum\":60,\"minimum\":-30,\"type\":\"integer\",\"x-ui-component\":\"slider\"}},\"required\":[\"images\"],\"type\":\"object\",\"x-order-properties\":[\"images\",\"horizontal_angle\",\"vertical_angle\",\"distance\",\"prompt\",\"size\",\"seed\",\"output_format\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:06.922', '2026-06-09 08:56:06.922', '2026-06-09 08:56:06.922');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('130ad3f0-0310-477b-8f42-c2c5d074d47c', NULL, 'cmq0hadjp0000si8dckyresaj', 'bytedance/seedance-v1.5-pro/text-to-video-fast', 'bytedance/seedance-v1.5-pro/text-to-video-fast', 'VIDEO', 0.2, NULL, NULL, 4350, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedance-v1.5-pro/text-to-video-fast\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"21:9\",\"16:9\",\"4:3\",\"1:1\",\"3:4\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"camera_fixed\":{\"default\":false,\"description\":\"Whether to fix the camera position.\",\"type\":\"boolean\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"maximum\":12,\"minimum\":4,\"step\":1,\"type\":\"integer\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate audio.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"duration\",\"resolution\",\"generate_audio\",\"camera_fixed\",\"seed\"]}}]}', '{\"model_id\":\"bytedance/seedance-v1.5-pro/text-to-video-fast\",\"name\":\"bytedance/seedance-v1.5-pro/text-to-video-fast\",\"base_price\":0.2,\"formula\":\"{\\\"total_price\\\":  base_price * $number(duration) / 5 *  ( resolution = \\\"720p\\\" ? 1 : 1.5 ) * ( generate_audio ? 1:0.5  )}\",\"description\":\"Seedance 1.5 Pro Fast (Text-to-Video) generates cinematic, live-action–leaning clips from text with strong prompt adherence, expressive motion, and stable aesthetics. It supports 4–12s duration control, multiple aspect ratios, and reproducible generation via seeds—ideal for ads and short-drama workflows.\",\"type\":\"text-to-video\",\"sort_order\":4350,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedance-v1.5-pro/text-to-video-fast\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"21:9\",\"16:9\",\"4:3\",\"1:1\",\"3:4\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"camera_fixed\":{\"default\":false,\"description\":\"Whether to fix the camera position.\",\"type\":\"boolean\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"maximum\":12,\"minimum\":4,\"step\":1,\"type\":\"integer\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate audio.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"duration\",\"resolution\",\"generate_audio\",\"camera_fixed\",\"seed\"]}}]}}', '2026-06-09 08:56:05.768', '2026-06-09 08:56:05.768', '2026-06-09 08:56:05.768');
