motion-control\",\"base_price\":0.336,\"formula\":\"{\\\"total_price\\\": $max([3, $min([$number(get_duration_v3(video)), 30])]) / 3 * base_price}\",\"description\":\"Kling 2.6 Pro delivers top-tier video-to-video generation with smooth motion, cinematic visuals, accurate prompt adherence, and native audio for ready-to-share clips. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"motion-control\",\"sort_order\":7600,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/kwaivgi/kling-v2.6-pro/motion-control\",\"request_schema\":{\"properties\":{\"character_orientation\":{\"default\":\"video\",\"description\":\"The duration of the generated media in seconds.\",\"enum\":[\"image\",\"video\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"image\":{\"description\":\"Supported image formats:.jpg /.jpeg /.png The size of the image file should not exceed 10MB, the width and height of the image should be no less than 300px, and the aspect ratio of the image should be between 1:2.5 and 2.5:1\",\"type\":\"string\"},\"keep_original_sound\":{\"default\":true,\"description\":\"Whether to retain the original video sound\",\"type\":\"boolean\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"video\":{\"description\":\"Supported video formats:.mp4/.mov The size of the video file should not exceed 10MB, the width and height of the video should be no less than 300px, and the aspect ratio of the video should be between 1:2.5 and 2.5:1\",\"type\":\"string\"}},\"required\":[\"image\",\"video\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"video\",\"character_orientation\",\"prompt\",\"negative_prompt\",\"keep_original_sound\"]}}]}}', '2026-06-09 08:56:05.644', '2026-06-09 08:56:05.644', '20