ired\":[\"prompt\",\"image\",\"last_image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"last_image\",\"duration\",\"resolution\",\"bgm\",\"movement_amplitude\",\"seed\"]}}]}}', '2026-06-09 08:56:07.017', '2026-06-09 08:56:07.017', '2026-06-09 08:56:07.017');
