INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('19e7c9b5-f26d-40ac-a6cf-8b96252de293', NULL, 'cmq0hadjp0000si8dckyresaj', 'google/nano-banana-pro/text-to-image-multi', 'google/nano-banana-pro/text-to-image-multi', 'IMAGE', 0.07, NULL, NULL, 3900, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/nano-banana-pro/text-to-image-multi\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"3:2\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"3:2\",\"2:3\",\"3:4\",\"4:3\"],\"type\":\"string\",\"x-placeholder\":\"Select aspect ratio\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API. Due to variability in Google’s underlying compute resources, inference times can fluctuate significantly. As a result, synchronous requests may hit timeouts.\",\"disabled\":true,\"type\":\"boolean\"},\"num_images\":{\"default\":2,\"description\":\"The number of images to generate.\",\"enum\":[2],\"maximum\":2,\"minimum\":2,\"type\":\"integer\"},\"output_format\":{\"default\":\"png\",\"description\":\"The format of the output image.\",\"enum\":[\"png\",\"jpeg\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"}},\"required\":[\"prompt\",\"aspect_ratio\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"num_images\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"google/nano-banana-pro/text-to-image-multi\",\"name\":\"google/nano-banana-pro/text-to-image-multi\",\"base_price\":0.07,\"formula\":\"{\\\"total_price\\\": base_price * num_images}\",\"description\":\"Google\'s Nano Banana Pro (Gemini 3.0 Pro Image) is a next-generation text-to-image model capable of generating multiple high-quality images in a single run. Extremely low cost — only $0.07 per image. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":3900,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/nano-banana-pro/text-to-image-multi\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"3:2\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"3:2\",\"2:3\",\"3:4\",\"4:3\"],\"type\":\"string\",\"x-placeholder\":\"Select aspect ratio\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API. Due to variability in Google’s underlying compute resources, inference times can fluctuate significantly. As a result, synchronous requests may hit timeouts.\",\"disabled\":true,\"type\":\"boolean\"},\"num_images\":{\"default\":2,\"description\":\"The number of images to generate.\",\"enum\":[2],\"maximum\":2,\"minimum\":2,\"type\":\"integer\"},\"output_format\":{\"default\":\"png\",\"description\":\"The format of the output image.\",\"enum\":[\"png\",\"jpeg\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"}},\"required\":[\"prompt\",\"aspect_ratio\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"num_images\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:05.799', '2026-06-09 08:56:05.799', '2026-06-09 08:56:05.799');
