otal_price\\\": ((generate_audio ? 1200000 : 800000) * $number(duration) / 8) }\",\"description\":\"Google Veo3 Fast provides faster, more cost-effective Image-to-Video generation vs Veo 3, with commercial use allowed and $0.25/sec pricing. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":220,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/veo3-fast/image-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"Aspect ratio of the video.\",\"enum\":[\"16:9\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"duration\":{\"default\":8,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[8,4,6],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate audio.\",\"type\":\"boolean\"},\"image\":{\"description\":\"The image to use for the generation.\",\"type\":\"string\"},\"negative_prompt\":{\"description\":\"Negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"Text prompt for generation; Positive text prompt.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"}},\"required\":[\"prompt\",\"image\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"aspect_ratio\",\"duration\",\"resolution\",\"generate_audio\",\"negative_prompt\",\"seed\"]}}]}}', '2026-06-09 08:56:06.208', '2026-06-09 08:56:06.208', '2026-06-09 08:56:06.208');
