INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('1b15653b-8d48-428d-bbd6-182bde88e5ef', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/soul-depart', 'video-effects/soul-depart', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/soul-depart\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single-person, two-person, group, pet, or object photos; 3. Best when sufficient space is left above the subject in the image; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/soul-depart\",\"name\":\"video-effects/soul-depart\",\"base_price\":0.2,\"formula\":\"\",\"description\":\"Create mystical Soul Depart Image-to-Video clips from photos with ethereal effects for artistic, spiritual, and fantasy themes. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/soul-depart\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single-person, two-person, group, pet, or object photos; 3. Best when sufficient space is left above the subject in the image; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.148', '2026-06-09 08:56:07.148', '2026-06-09 08:56:07.148');
