 image.\",\"enum\":[\"jpeg\",\"png\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\",\"x-rows\":10,\"x-ui-component\":\"textarea\"},\"size\":{\"description\":\"Specify the width and height pixel values of the generated image.\",\"maximum\":8192,\"minimum\":512,\"type\":\"string\",\"x-hidden\":true}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"size\",\"max_images\",\"output_format\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:05.600', '2026-06-09 08:56:05.600', '2026-06-09 08:56:05.600');
