INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('2518fce6-7d22-417c-8dd9-b0320403e84f', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/steady-dancer', 'wavespeed-ai/steady-dancer', 'IMAGE', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/steady-dancer\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"480p\",\"description\":\"The resolution of the output video.\",\"enum\":[\"480p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"video\":{\"description\":\"The video for generating the output.\",\"type\":\"string\"}},\"required\":[\"image\",\"video\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"video\",\"prompt\",\"resolution\",\"seed\"]}}]}', '{\"model_id\":\"wavespeed-ai/steady-dancer\",\"name\":\"wavespeed-ai/steady-dancer\",\"base_price\":0.2,\"formula\":\"{\\\"total_price\\\": $max([5, $min([$number(get_duration_v3(video)), 120])]) / 5 * base_price * (resolution = \\\"720p\\\" ? 2 : 1)}\",\"description\":\"SteadyDancer is a 14B-parameter human image animation framework that transforms static images into coherent dance videos. Features first-frame preservation, robust identity consistency, and temporal coherence for realistic motion generation. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"motion-control\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/steady-dancer\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"480p\",\"description\":\"The resolution of the output video.\",\"enum\":[\"480p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"video\":{\"description\":\"The video for generating the output.\",\"type\":\"string\"}},\"required\":[\"image\",\"video\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"video\",\"prompt\",\"resolution\",\"seed\"]}}]}}', '2026-06-09 08:56:06.692', '2026-06-09 08:56:06.692', '2026-06-09 08:56:06.692');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('254013e3-b100-4ded-8ba3-745cc9b50a7a', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/flower-receive', 'video-effects/flower-receive', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/flower-receive\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single-person, two-person, and group photos; 3. Best results are achieved when the main subject\'s upper body is clearly visible from the front; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/flower-receive\",\"name\":\"video-effects/flower-receive\",\"base_price\":0.2,\"formula\":\"\",\"description\":\"Convert photos into Flower Receive image-to-video clips with natural motion and romantic, expressive gestures. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/flower-receive\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single-person, two-person, and group photos; 3. Best results are achieved when the main subject\'s upper body is clearly visible from the front; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.337', '2026-06-09 08:56:07.337', '2026-06-09 08:56:07.337');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('257da24d-ff77-48fe-b912-c811b0fe0e50', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/z-image-turbo/controlnet', 'wavespeed-ai/z-image-turbo/controlnet', 'IMAGE', 0.012, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/z-image-turbo/controlnet\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If true, returns BASE64 encoded image instead of URL. API only.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If true, waits for generation to complete before returning. API only.\",\"disabled\":true,\"type\":\"boolean\"},\"image\":{\"description\":\"Reference image URL for ControlNet to extract structural guidance from.\",\"format\":\"uri\",\"type\":\"string\"},\"mode\":{\"default\":\"depth\",\"description\":\"ControlNet mode: \'depth\' for depth map guidance, \'canny\' for edge detection, \'pose\' for human pose estimation, \'none\' for no control.\",\"enum\":[\"depth\",\"canny\",\"pose\",\"none\"],\"type\":\"string\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"Output image format.\",\"enum\":[\"jpeg\",\"png\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"Text description of the image you want to generate.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"Random seed for reproducible generation. Use -1 for random seed.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"Output image size in pixels (width*height).\",\"type\":\"string\"},\"strength\":{\"default\":1,\"description\":\"Controls how strongly the ControlNet guidance affects the output (0-1). Higher values follow the control signal more strictly.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"mode\",\"size\",\"strength\",\"seed\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"wavespeed-ai/z-image-turbo/controlnet\",\"name\":\"wavespeed-ai/z-image-turbo/controlnet\",\"base_price\":0.012,\"formula\":\"\",\"description\":\"Z-Image-Turbo ControlNet generates images guided by structural control signals (depth, canny edge, pose) for precise composition control. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/z-image-turbo/controlnet\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If true, returns BASE64 encoded image instead of URL. API only.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If true, waits for generation to complete before returning. API only.\",\"disabled\":true,\"type\":\"boolean\"},\"image\":{\"description\":\"Reference image URL for ControlNet to extract structural guidance from.\",\"format\":\"uri\",\"type\":\"string\"},\"mode\":{\"default\":\"depth\",\"description\":\"ControlNet mode: \'depth\' for depth map guidance, \'canny\' for edge detection, \'pose\' for human pose estimation, \'none\' for no control.\",\"enum\":[\"depth\",\"canny\",\"pose\",\"none\"],\"type\":\"string\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"Output image format.\",\"enum\":[\"jpeg\",\"png\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"Text description of the image you want to generate.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"Random seed for reproducible generation. Use -1 for random seed.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"Output image size in pixels (width*height).\",\"type\":\"string\"},\"strength\":{\"default\":1,\"description\":\"Controls how strongly the ControlNet guidance affects the output (0-1). Higher values follow the control signal more strictly.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"mode\",\"size\",\"strength\",\"seed\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.878', '2026-06-09 08:56:06.878', '2026-06-09 08:56:06.878');
