INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('272b1291-36e1-4ac0-9c84-8eb5b1761b3c', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/flux-2-flex/edit', 'wavespeed-ai/flux-2-flex/edit', 'IMAGE', 0.12, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-2-flex/edit\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"images\":{\"description\":\"List of URLs of input images for editing. The maximum number of images is 3.\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"minItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\",\"x-hidden\":true}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"size\",\"seed\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"wavespeed-ai/flux-2-flex/edit\",\"name\":\"wavespeed-ai/flux-2-flex/edit\",\"base_price\":0.12,\"formula\":\"\",\"description\":\"FLUX.2 [flex] Edit delivers precise image-to-image editing from Black Forest Labs—apply natural-language instructions and exact hex color control for consistent, studio-quality results. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-2-flex/edit\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"images\":{\"description\":\"List of URLs of input images for editing. The maximum number of images is 3.\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"minItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\",\"x-hidden\":true}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"size\",\"seed\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.612', '2026-06-09 08:56:06.612', '2026-06-09 08:56:06.612');
