ent\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"audio/*\"}},\"image\":{\"description\":\"Input image URL.\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"prompt\":{\"description\":\"Text prompt describing the scene, action, camera, or avatar behavior.\",\"type\":\"string\",\"x-rows\":4,\"x-ui-component\":\"textarea\"}},\"required\":[\"prompt\",\"image\",\"audio\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"audio\"]}}]}}', '2026-06-09 08:56:05.380', '2026-06-09 08:56:05.380', '2026-06-09 08:56:05.380');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('27d7b96b-8306-4591-a1ae-0486551085b2', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/pixel-me', 'video-effects/pixel-me', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/pixel-me\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single-person photos, two-person group photos, or multi-person group photos; 3. Best results when the main subject shows a frontal upper body or full body; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/pixel-me\",\"name\":\"video-effects/pixel-me\",\"base_price\":0.2,\"formula\":\"\",\"description\":\"Convert photos to pixel-art videos (image-to-video) with natural motion and preserved emotion for expressive, stylized outputs. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/pixel-me\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single-person photos, two-person group photos, or multi-person group photos; 3. Best results when the main subject shows a frontal upper body or full body; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.324', '2026-06-09 08:56:07.324', '2026-06-09 08:56:07.324');
