ema\":{\"properties\":{\"duration\":{\"default\":4,\"description\":\"The duration of the generated video in seconds.\",\"enum\":[4,8,12,16,20],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated video.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"image\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"resolution\",\"duration\"]}}]}}', '2026-06-09 08:56:07.208', '2026-06-09 08:56:07.208', '2026-06-09 08:56:07.208');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('2842d17b-0dc0-4565-a284-6ead9dcde83f', NULL, 'cmq0hadjp0000si8dckyresaj', 'google/veo3.1/text-to-video', 'google/veo3.1/text-to-video', 'VIDEO', 3.2, NULL, NULL, 7000, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/veo3.1/text-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"Aspect ratio of the video.\",\"enum\":[\"16:9\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"duration\":{\"default\":8,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[8,4,6],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate audio.\",\"type\":\"boolean\"},\"negative_prompt\":{\"description\":\"Negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"Text prompt for generation; Positive text prompt.\",\"type\":\"string\"},\"resolution\":{\"default\":\"1080p\",\"description\":\"Video resolution.\",\"enum\":[\"720p\",\"1080p\",\"4k\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"duration\",\"resolution\",\"generate_audio\",\"negative_prompt\",\"seed\"]}}]}', '{\"model_id\":\"google/veo3.1/text-to-video\",\"name\":\"google/veo3.1/text-to-video\",\"base_price\":3.2,\"formula\":\"{ \\\"total_price\\\": ((generate_audio ? 3200000 : 1600000) * $number(duration) / 8) }\",\"description\":\"Google Veo 3.1 converts text prompts into videos with synchronized audio at native 1080p for high-quality outputs. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-video\",\"sort_order\":7000,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/veo3.1/text-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"Aspect ratio of the video.\",\"enum\":[\"16:9\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"duration\":{\"default\":8,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[8,4,6],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate audio.\",\"type\":\"boolean\"},\"negative_prompt\":{\"description\":\"Negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"Text prompt for generation; Positive text prompt.\",\"type\":\"string\"},\"resolution\":{\"default\":\"1080p\",\"description\":\"Video resolution.\",\"enum\":[\"720p\",\"1080p\",\"4k\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"duration\",\"resolution\",\"generate_audio\",\"negative_prompt\",\"seed\"]}}]}}', '2026-06-09 08:56:05.658', '2026-06-09 08:56:05.658', '2026-06-09 08:56:05.658');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('29cc930f-9ddb-4072-ac04-7c1d81037872', NULL, 'cmq0hadjp0000si8dckyresaj', 'elevenlabs/eleven-v3', 'elevenlabs/eleven-v3', 'IMAGE', 0.1, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/elevenlabs/eleven-v3\",\"request_schema\":{\"properties\":{\"similarity\":{\"default\":1,\"description\":\"High enhancement boosts overall voice clarity and target speaker similarity. Very high values can cause artifacts, so adjusting this setting to find the optimal value is encouraged.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"stability\":{\"default\":0.5,\"description\":\"Voice stability (0-1) Default value: 0.5\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"text\":{\"default\":\"Welcome to our advanced text-to-speech system! Experience high-quality voice synthesis with natural pronunciation and clear articulation.\",\"description\":\"Text to convert to speech. Every character is 1 token. Maximum 10000 characters. Use <#x#> between words to control pause duration (0.01-99.99s).\",\"maxLength\":10000,\"type\":\"string\",\"x-rows\":5,\"x-ui-component\":\"textarea\"},\"use_speaker_boost\":{\"default\":true,\"description\":\"This parameter supports English text normalization, which improves performance in number-reading scenarios.\",\"type\":\"boolean\"},\"voice_id\":{\"default\":\"Alice\",\"description\":\"The voice to use for speech generation\",\"type\":\"string\",\"x-enum\":[\"Aria\",\"Roger\",\"Sarah\",\"Laura\",\"Charlie\",\"George\",\"Callum\",\"River\",\"Liam\",\"Charlotte\",\"Alice\",\"Matilda\",\"Will\",\"Jessica\",\"Eric\",\"Chris\",\"Brian\",\"Daniel\",\"Lily\",\"Bill\"],\"x-placeholder\":\"Please input your custom voice ID\",\"x-ui-component\":\"command\"}},\"required\":[\"text\",\"voice_id\"],\"type\":\"object\",\"x-order-properties\":[\"text\",\"voice_id\",\"similarity\",\"stability\",\"use_speaker_boost\"]}}]}', '{\"model_id\":\"elevenlabs/eleven-v3\",\"name\":\"elevenlabs/eleven-v3\",\"base_price\":0.1,\"formula\":\"{\\\"total_price\\\": base_price * $ceil($length(text) / 1000)}\",\"description\":\"ElevenLabs eleven-v3 is a text-to-speech model available as a hosted endpoint; requests cost $0.1 per 1000 characters. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-audio\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/elevenlabs/eleven-v3\",\"request_schema\":{\"properties\":{\"similarity\":{\"default\":1,\"description\":\"High enhancement boosts overall voice clarity and target speaker similarity. Very high values can cause artifacts, so adjusting this setting to find the optimal value is encouraged.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"stability\":{\"default\":0.5,\"description\":\"Voice stability (0-1) Default value: 0.5\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"text\":{\"default\":\"Welcome to our advanced text-to-speech system! Experience high-quality voice synthesis with natural pronunciation and clear articulation.\",\"description\":\"Text to convert to speech. Every character is 1 token. Maximum 10000 characters. Use <#x#> between words to control pause duration (0.01-99.99s).\",\"maxLength\":10000,\"type\":\"string\",\"x-rows\":5,\"x-ui-component\":\"textarea\"},\"use_speaker_boost\":{\"default\":true,\"description\":\"This parameter supports English text normalization, which improves perfo