:\"Ideogram V4 generates high-quality images, posters, and logos from text prompts with strong typography, sharp detail, and controllable rendering speed.\",\"type\":\"text-to-image\",\"sort_order\":10000,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/ideogram-ai/ideogram-v4\",\"request_schema\":{\"properties\":{\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the generated image.\",\"enum\":[\"jpeg\",\"png\"],\"title\":\"Output Format\",\"type\":\"string\",\"x-ui-component\":\"select\"},\"prompt\":{\"description\":\"Text prompt describing the image to generate.\",\"maxLength\":4096,\"minLength\":1,\"title\":\"Prompt\",\"type\":\"string\",\"x-rows\":4,\"x-ui-component\":\"textarea\"},\"rendering_speed\":{\"default\":\"BALANCED\",\"description\":\"Rendering speed and quality tier. Faster speeds use fewer denoising steps.\",\"enum\":[\"TURBO\",\"BALANCED\",\"QUALITY\"],\"title\":\"Rendering Speed\",\"type\":\"string\",\"x-ui-component\":\"select\"},\"size\":{\"default\":\"1:1\",\"description\":\"Output image size preset.\",\"enum\":[\"1:1\",\"3:4\",\"9:16\",\"4:3\",\"16:9\"],\"title\":\"Size\",\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"rendering_speed\",\"output_format\"]}}]}}', '2026-06-09 08:56:05.421', '2026-06-09 08:56:05.421', '2026-06-09 08:56:05.421');
