, '2026-06-09 08:56:07.103');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('362808df-3e57-49dc-b2ae-0ae330a8afa9', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/dreamy-wedding', 'video-effects/dreamy-wedding', 'VIDEO', 0.3, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/dreamy-wedding\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports two-person photos only; 3. Best for front-facing subjects with clear face visibility above neck and no hair accessories; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/dreamy-wedding\",\"name\":\"video-effects/dreamy-wedding\",\"base_price\":0.3,\"formula\":\"\",\"description\":\"Image-to-Video model converting couple photos into cinematic wedding videos with AI-generated dresses, suits, and emotional scenery. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/dreamy-wedding\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports two-person photos only; 3. Best for front-facing subjects with clear face visibility above neck and no hair accessories; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.122', '2026-06-09 08:56:07.122', '2026-06-09 08:56:07.122');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('3631d1c5-fefe-4262-afb8-5699b77c13f3', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/song-generation', 'wavespeed-ai/song-generation', 'IMAGE', 0.05, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/song-generation\",\"request_schema\":{\"properties\":{\"description\":{\"description\":\"Song Description (Optional). Describe the gender, timbre, genre, emotion, instrument and bpm of the song. Only English is supported currently.\",\"type\":\"string\",\"x-ui-component\":\"textarea\"},\"genre\":{\"default\":\"Auto\",\"description\":\"Genre Select (Optional). Choose a genre for the song.\",\"enum\":[\"Pop\",\"R&B\",\"Dance\",\"Jazz\",\"Folk\",\"Rock\",\"Chinese Style\",\"Chinese Tradition\",\"Metal\",\"Reggae\",\"Chinese Opera\",\"Auto\"],\"type\":\"string\"},\"guidance_scale\":{\"default\":1.5,\"description\":\"The guidance scale to use for the generation.\",\"maximum\":3,\"minimum\":0.1,\"step\":0.1,\"type\":\"number\"},\"lyric\":{\"description\":\"Each paragraph represents a segment starting with a structure tag and ending with a blank line, each line is a sentence without punctuation, segments [intro], [inst], [outro] should not contain lyrics, while [verse], [chorus], and [bridge] require lyrics.\",\"type\":\"string\",\"x-ui-component\":\"textarea\"},\"prompt_audio\":{\"description\":\"Prompt Audio (Optional). Provide a URL to an audio file that serves as a prompt for the genre of the song generation.\",\"type\":\"string\",\"x-placeholder\":\"Upload your audio file\",\"x-ui-component\":\"uploader\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"temperature\":{\"default\":0.9,\"description\":\"The temperature to use for the generation. A higher value means more randomness in the output.\",\"maximum\":2,\"minimum\":0.1,\"step\":0.1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"top_k\":{\"default\":50,\"description\":\"The top-k value to use for the generation. This controls the number of highest probability vocabulary tokens to keep for top-k-filtering.\",\"maximum\":100,\"minimum\":1,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"}},\"required\":[\"lyric\"],\"type\":\"object\",\"x-order-properties\":[\"lyric\",\"description\",\"prompt_audio\",\"genre\",\"guidance_scale\",\"temperature\",\"top_k\",\"seed\"]}}]}', '{\"model_id\":\"wavespeed-ai/song-generation\",\"name\":\"wavespeed-ai/song-generation\",\"base_price\":0.05,\"formula\":\"\",\"description\":\"SongGeneration (LeVo) is an open-source text-to-song model that turns lyrics and optional audio or text prompts into high-quality songs. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-audio\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/song-generation\",\"request_schema\":{\"properties\":{\"description\":{\"description\":\"Song Description (Optional). Describe the gender, timbre, genre, emotion, instrument and bpm of the song. Only English is supported currently.\",\"type\":\"string\",\"x-ui-component\":\"textarea\"},\"genre\":{\"default\":\"Auto\",\"description\":\"Genre Select (Optional). Choose a genre for the song.\",\"enum\":[\"Pop\",\"R&B\",\"Dance\",\"Jazz\",\"Folk\",\"Rock\",\"Chinese Style\",\"Chinese Tradition\",\"Metal\",\"Reggae\",\"Chinese Opera\",\"Auto\"],\"type\":\"string\"},\"guidance_scale\":{\"default\":1.5,\"description\":\"The guidance scale to use for the generation.\",\"maximum\":3,\"minimum\":0.1,\"step\":0.1,\"type\":\"number\"},\"lyric\":{\"description\":\"Each paragraph represents a segment starting with a structure tag and ending with a blank line, each line is a sentence without punctuation, segments [intro], [inst], [outro] should not contain lyrics, while [verse], [chorus], and [bridge] require lyrics.\",\"type\":\"string\",\"x-ui-component\":\"textarea\"},\"prompt_audio\":{\"description\":\"Prompt Audio (Optional). Provide a URL to an audio file that serves as a prompt for the genre of the song generation.\",\"type\":\"string\",\"x-placeholder\":\"Upload your audio file\",\"x-ui-component\":\"uploader\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"temperature\":{\"default\":0.9,\"description\":\"The temperature to use for the generation. A higher value means more randomness in the output.\",\"maximum\":2,\"minimum\":0.1,\"step\":0.1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"top_k\":{\"default\":50,\"description\":\"The top-k value to use for the generation. This controls the number of highest probability vocabulary tokens to keep for top-k-filtering.\",\"maximum\":100,\"minimum\":1,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"}},\"required\":[\"lyric\"],\"type\":\"object\",\"x-order-properties\":[\"lyric\",\"description\",\"prompt_audio\",\"genre\",\"guidance_scale\",\"temperature\",\"top_k\",\"seed\"]}}]}}', '2026-06-09 08:56:06.314', '2026-06-09 08:56:06.314', '2026-06-09 08:56:06.314');
