) / 5 ) * ( $number(base_price) * 1000000 ) * ( resolution = \\\"720p\\\" ? 1 : resolution = \\\"1080p\\\" ? 2 : 6/13 ) * ( generate_audio ? 1 : 1/2 ) / 1000000 }\",\"description\":\"Seedance 1.5 Pro (Text-to-Video) generates cinematic, live-action–leaning clips from text with strong prompt adherence, expressive motion, and stable aesthetics. It supports 4–12s duration control (including Smart Duration), multiple aspect ratios (including adaptive), and reproducible generation via seeds—ideal for ads and short-drama workflows.\",\"type\":\"text-to-video\",\"sort_order\":4250,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedance-v1.5-pro/text-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"21:9\",\"16:9\",\"4:3\",\"1:1\",\"3:4\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"camera_fixed\":{\"default\":false,\"description\":\"Whether to fix the camera position.\",\"type\":\"boolean\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"maximum\":12,\"minimum\":4,\"step\":1,\"type\":\"integer\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate audio.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Video resolution.\",\"enum\":[\"480p\",\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"duration\",\"resolution\",\"generate_audio\",\"camera_fixed\",\"seed\"]}}]}}', '2026-06-09 08:56:05.773', '2026-06-09 08:56:05.773',