\"description\":\"Text prompt for the generated image.\",\"maxLength\":10000,\"title\":\"Prompt\",\"type\":\"string\",\"x-rows\":4,\"x-ui-component\":\"textarea\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image_size\"]}}]}}', '2026-06-09 08:56:05.463', '2026-06-09 08:56:05.463', '2026-06-09 08:56:05.463');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('3c234a82-8948-4f9e-a92e-d175b29dce80', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/flux-dev-lora-trainer', 'wavespeed-ai/flux-dev-lora-trainer', 'IMAGE', 1, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-dev-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"URL to zip archive with images. Try to use at least 4 images in general the more the better.\\n\\n        In addition to images the archive can contain text files with captions. Each text file should have the same name as the image file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing images.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0004,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":16,\"maximum\":64,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":1000,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":10000,\"minimum\":500,\"step\":10,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"Trigger word to be used in the captions. If None, a trigger word will not be used.\\n        If no captions are provide the trigger_word will be used instead of captions. If captions are the trigger word will not be used.\",\"nullable\":true,\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}', '{\"model_id\":\"wavespeed-ai/flux-dev-lora-trainer\",\"name\":\"wavespeed-ai/flux-dev-lora-trainer\",\"base_price\":1,\"formula\":\"{\\\"total_price\\\":base_price * (steps / 1000)}\",\"description\":\"Flux-dev LoRA Trainer – train custom FLUX styles from your own dataset, with zip uploads, auto-tuned defaults and fast iteration for brand, character or IP looks.\",\"type\":\"training\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-dev-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"URL to zip archive with images. Try to use at least 4 images in general the more the better.\\n\\n        In addition to images the archive can contain text files with captions. Each text file should have the same name as the image file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing images.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0004,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":16,\"maximum\":64,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":1000,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":10000,\"minimum\":500,\"step\":10,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"Trigger word to be used in the captions. If None, a trigger word will not be used.\\n        If no captions are provide the trigger_word will be used instead of captions. If captions are the trigger word will not be used.\",\"nullable\":true,\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}}', '2026-06-09 08:56:07.609', '2026-06-09 08:56:07.609', '2026-06-09 08:56:07.609');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('3c558532-4b77-45bf-bc63-200dcdb7bea3', NULL, 'cmq0hadjp0000si8dckyresaj', 'google/gemini-3-pro-image/text-to-image', 'google/gemini-3-pro-image/text-to-image', 'IMAGE', 0.14, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/gemini-3-pro-image/text-to-image\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"3:2\",\"2:3\",\"3:4\",\"4:3\",\"4:5\",\"5:4\",\"9:16\",\"16:9\",\"21:9\"],\"type\":\"string\",\"x-placeholder\":\"Select aspect ratio\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"output_format\":{\"default\":\"png\",\"description\":\"The format of the output image.\",\"enum\":[\"png\",\"jpeg\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"1k\",\"description\":\"The resolution of the output image.\",\"enum\":[\"1k\",\"2k\",\"4k\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"resolution\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"google/gemini-3-pro-image/text-to-image\",\"name\":\"google/gemini-3-pro-image/text-to-image\",\"base_price\":0.14,\"formula\":\"{\\\"total_price\\\": base_price * (resolution = \\\"2k\\\" ? 1 : (resolution = \\\"4k\\\" ? 12/7 : 1))}\",\"description\":\"Google\'s Gemini 3.0 Pro (Gemini 3.0 Pro Preview) is a cutting-edge text-to-image model enabling high-res 4K image generation optimized for phones. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/gemini-3-pro-image/text-to-image\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"3:2\",\"2:3\",\"3:4\",\"4:3\",\"4:5\",\"5:4\",\"9:16\",\"16:9\",\"21:9\"],\"type\":\"string\",\"x-placeholder\":\"Select aspect ratio\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"output_format\":{\"default\":\"png\",\"description\":\"The format of the output image.\",\"enum\":[\"png\",\"jpeg\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"1k\",\"description\":\"The resolution of the output image.\",\"enum\":[\"1k\",\"2k\",\"4k\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"resolution\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.577', '2026-06-09 08:56:06.577', '2026-06-09 08:56:06.577');
