\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/wan-2.2/i2v-720p\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[5,8],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"last_image\":{\"description\":\"The last image for generating the output.\",\"type\":\"string\",\"x-accept\":\"image/*\",\"x-ui-component\":\"uploader\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"negative_prompt\",\"last_image\",\"duration\",\"seed\"]}}]}}', '2026-06-09 08:56:07.722', '2026-06-09 08:56:07.722', '2026-06-09 08:56:07.722');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('3d1abb6a-b059-436f-a1df-17c69ee4138a', NULL, 'cmq0hadjp0000si8dckyresaj', 'x-ai/grok-imagine-video/edit-video', 'x-ai/grok-imagine-video/edit-video', 'VIDEO', 0.065, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/x-ai/grok-imagine-video/edit-video\",\"request_schema\":{\"properties\":{\"prompt\":{\"description\":\"Text description of the desired edit.\",\"maxLength\":4096,\"type\":\"string\"},\"resolution\":{\"default\":\"480p\",\"description\":\"Resolution of the output video.\",\"enum\":[\"480p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"video\":{\"description\":\"URL of the input video to edit. Video will be resized to max 854x480 pixels and truncated to 8 seconds.\",\"format\":\"uri\",\"type\":\"string\"}},\"required\":[\"prompt\",\"video\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"resolution\"]}}]}', '{\"model_id\":\"x-ai/grok-imagine-video/edit-video\",\"name\":\"x-ai/grok-imagine-video/edit-video\",\"base_price\":0.065,\"formula\":\"{\\\"total_price\\\": $max([1, $min([$number(get_duration_v3(video)), 8])]) * base_price}\",\"description\":\"Edit videos using xAI\'s Grok Imagine Video model. Transform and modify existing videos with text prompts.\",\"type\":\"video-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/x-ai/grok-imagine-video/edit-video\",\"request_schema\":{\"properties\":{\"prompt\":{\"description\":\"Text description of the desired edit.\",\"maxLength\":4096,\"type\":\"string\"},\"resolution\":{\"default\":\"480p\",\"description\":\"Resolution of the output video.\",\"enum\":[\"480p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"video\":{\"description\":\"URL of the input video to edit. Video will be resized to max 854x480 pixels and truncated to 8 seconds.\",\"format\":\"uri\",\"type\":\"string\"}},\"required\":[\"prompt\",\"video\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"resolution\"]}}]}}', '2026-06-09 08:56:06.232', '2026-06-09 08:56:06.232', '2026-06-09 08:56:06.232');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('3d3bec77-8271-4515-8557-935f2117600b', NULL, 'cmq0hadjp0000si8dckyresaj', 'kwaivgi/kling-v2.6/create-voice', 'kwaivgi/kling-v2.6/create-voice', 'IMAGE', 0.035, NULL, NULL, 1450, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/kwaivgi/kling-v2.6/create-voice\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"The voice needs to be clean and free of noise, with only one type of human voice present, with a duration of no less than 5 seconds and no longer than 30 seconds.\",\"type\":\"string\"}},\"required\":[\"audio\"],\"type\":\"object\",\"x-order-properties\":[\"audio\"]}}]}', '{\"model_id\":\"kwaivgi/kling-v2.6/create-voice\",\"name\":\"kwaivgi/kling-v2.6/create-voice\",\"base_price\":0.035,\"formula\":\"\",\"description\":\"Create Voices to be used with Kling 2.6 Voice Control\",\"type\":\"audio-to-audio\",\"sort_order\":1450,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/kwaivgi/kling-v2.6/create-voice\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"The voice needs to be clean and free of noise, with only one type of human voice present, with a duration of no less than 5 seconds and no longer than 30 seconds.\",\"type\":\"string\"}},\"required\":[\"audio\"],\"type\":\"object\",\"x-order-properties\":[\"audio\"]}}]}}', '2026-06-09 08:56:06.057', '2026-06-09 08:56:06.057', '2026-06-09 08:56:06.057');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('3d55c9f2-f7da-4151-af43-822a64950315', NULL, 'cmq0hadjp0000si8dckyresaj', 'minimax/hailuo-02/standard', 'minimax/hailuo-02/standard', 'IMAGE', 0.23, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/hailuo-02/standard\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":6,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[6,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"The model automatically optimizes incoming prompts to enhance output quality. This also activates the safety checker, which ensures content safety by detecting and filtering potential risks.\",\"type\":\"boolean\"},\"end_image\":{\"description\":\"The model generates video with the picture passed in as the last frame.Base64 encoded strings in data:image/jpeg; base64,{data} format for incoming images, or URLs accessible via the public network. The uploaded image needs to meet the following conditions: Format is JPG/JPEG/PNG; The aspect ratio is greater than 2:5 and less than 5:2; Short side pixels greater than 300px; The image file size cannot exceed 20MB.\",\"type\":\"string\"},\"image\":{\"description\":\"The model generates video with the picture passed in as the first frame.Base64 encoded strings in data:image/jpeg; base64,{data} format for incoming images, or URLs accessible via the public network. The uploaded image needs to meet the following conditions: Format is JPG/JPEG/PNG; The aspect ratio is greater than 2:5 and less than 5:2; Short side pixels greater than 300px; The image file size cannot exceed 20MB.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"maxLength\":2000,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"end_image\",\"duration\",\"enable_prompt_expansion\"]}}]}', '{\"model_id\":\"minimax/hailuo-02/standard\",\"name\":\"minimax/hailuo-02/standard\",\"base_price\":0.23,\"formula\":\"{\\\"total_price\\\": (duration = 10) ? 560000 : 230000}\",\"description\":\"Hailuo 02 is an AI video-generation model delivering 768P output with fast responsiveness and strong handling of complex physics scenes. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/hailuo-02/standard\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":6,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[6,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"The model automatically optimizes incoming prompts to enhance output quality. This also activates the safety checker, which ensures content safety by detecting and filtering potential risks.\",\"type\":\"boolean\"},\"end_image\":{\"description\":\"The model generates video with the picture passed in as the last frame.Base64 encoded strings in data:image/jpeg; base64,{data} format for incoming images, or URLs accessible via the public network. The uploaded image needs to meet the following conditions: Format is JPG/JPEG/PNG; The aspect ratio is greater than 2:5 and less than 5:2; Short side pixels greater than 300px; The image file size cannot exceed 20MB.\",\"type\":\"string\"},\"image\":{\"description\":\"The model generates video with the picture passed in as the first frame.Base64 encoded strings in data:image/jpeg; base64,{data} format for incoming images, or URLs accessible via the public network. The uploaded image needs to meet the following conditions: Format is JPG/JPEG/PNG; The aspect ratio is greater than 2:5 and less than 5:2; Short side pixels greater than 300px; The image file size cannot exceed 20MB.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"maxLength\":2000,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"end_image\",\"duration\",\"enable_prompt_expansion\"]}}]}}', '2026-06-09 08:56:07.461', '2026-06-09 08:56:07.461', '2026-06-09 08:56:07.461');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('3dd011ec-0460-480f-bba4-26c78876b99a', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/kandinsky5-pro/text-to-video', 'wavespeed-ai/kandinsky5-pro/text-to-video', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/kandinsky5-pro/text-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"3:2\",\"description\":\"Aspect ratio of the generated video.\",\"enum\":[\"3:2\",\"1:1\",\"2:3\"],\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"Video duration in seconds (currently only 5s is supported).\",\"enum\":[5],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"prompt\":{\"description\":\"The text prompt to guide video generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"512p\",\"description\":\"Video resolution quality.\",\"enum\":[\"512p\",\"1024p\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"resolution\",\"aspect_ratio\",\"duration\"]}}]}', '{\"model_id\":\"wavespeed-ai/kandinsky5-pro/text-to-video\",\"name\":\"wavespeed-ai/kandinsky5-pro/text-to-video\",\"base_price\":0.2,\"formula\":\"{\\\"total_price\\\": base_price * (resolution = \'1024P\' ? 3 : 1) / 5 * duration}\",\"description\":\"Kandinsky 5 Pro Text-to-Video generation model. Create dynamic 5-second videos from text prompts. Supports 512P and 1024P resolutions with multiple aspect ratios. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"text-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/kandinsky5-pro/text-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"3:2\",\"description\":\"Aspect ratio of the generated video.\",\"enum\":[\"3:2\",\"1:1\",\"2:3\"],\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"Video duration in seconds (currently only 5s is supported).\",\"enum\":[5],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"prompt\":{\"description\":\"The text prompt to guide video generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"512p\",\"description\":\"Video resolution quality.\",\"enum\":[\"512p\",\"1024p\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"resolution\",\"aspect_ratio\",\"duration\"]}}]}}', '2026-06-09 08:56:06.803', '2026-06-09 08:56:06.803', '2026-06-09 08:56:06.803');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('3e4955e3-0f3a-4158-843e-8e99906b347b', NULL, 'cmq0hadjp0000si8dckyresaj', 'vidu/reference-to-video-2.0', 'vidu/reference-to-video-2.0', 'VIDEO', 0.2, NULL, NULL, 240, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/vidu/reference-to-video-2.0\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"16:9\",\"9:16\",\"1:1\"],\"type\":\"string\"},\"images\":{\"description\":\"The model will use the provided images as references to generate a video with consistent subjects. For fields that accept images: Accepts 1 to 3 images; Images Assets can be provided via URLs or Base64 encode; You must use one of the following codecs: PNG, JPEG, JPG, WebP; The dimensions of the images must be at least 128*128 pixels; The aspect ratio of the images must be less than 1:4 or 4:1; All images are limited to 50MB; The length of the base64 decode must be under 50MB, and it must include an appropriate content type string.\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"minItems\":1,\"type\":\"array\"},\"movement_amplitude\":{\"default\":\"auto\",\"description\":\"The movement amplitude of objects in the frame. Defaults to auto, accepted value: auto, small, medium, large.\",\"enum\":[\"auto\",\"small\",\"medium\",\"large\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":0,\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"aspect_ratio\",\"movement_amplitude\",\"seed\"]}}]}', '{\"model_id\":\"vidu/reference-to-video-2.0\",\"name\":\"vidu/reference-to-video-2.0\",\"base_price\":0.2,\"formula\":\"{\\\"total_price\\\": (duration = 8) ? 500000 : 200000}\",\"description\":\"Vidu Reference-to-Video 2.0 turns references into videos that preserve characters, objects, and environments with Multi-Entity Consistency. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":240,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/vidu/reference-to-video-2.0\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"16:9\",\"9:16\",\"1:1\"],\"type\":\"string\"},\"images\":{\"description\":\"The model will use the provided images as references to generate a video with consistent subjects. For fields that accept images: Accepts 1 to 3 images; Images Assets can be provided via URLs or Base64 encode; You must use one of the following codecs: PNG, JPEG, JPG, WebP; The dimensions of the images must be at least 128*128 pixels; The aspect ratio of the images must be less than 1:4 or 4:1; All images are limited to 50MB; The length of the base64 decode must be under 50MB, and it must include an appropriate content type string.\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"minItems\":1,\"type\":\"array\"},\"movement_amplitude\":{\"default\":\"auto\",\"description\":\"The movement amplitude of objects in the frame. Defaults to auto, accepted value: auto, small, medium, large.\",\"enum\":[\"auto\",\"small\",\"medium\",\"large\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":0,\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"aspect_ratio\",\"movement_amplitude\",\"seed\"]}}]}}', '2026-06-09 08:56:06.204', '2026-06-09 08:56:06.204', '2026-06-09 08:56:06.204');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('3e63c1e3-39ec-40ad-a193-655dca456010', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/flashvsr', 'wavespeed-ai/flashvsr', 'IMAGE', 0.05, NULL, NULL, 2800, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flashvsr\",\"request_schema\":{\"properties\":{\"target_resolution\":{\"default\":\"1080p\",\"description\":\"Target resolution to upscale to.\",\"enum\":[\"720p\",\"1080p\",\"2k\",\"4k\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"video\":{\"description\":\"The video to upscale.\",\"type\":\"string\"}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"target_resolution\"]}}]}', '{\"model_id\":\"wavespeed-ai/flashvsr\",\"name\":\"wavespeed-ai/flashvsr\",\"base_price\":0.05,\"formula\":\"{\\\"total_price\\\": $min([$max([get_duration_v3(video),5]),600]) / 5 * (target_resolution=\\\"4k\\\" ? 160000 : target_resolution=\\\"2k\\\" ? 120000 : target_resolution=\\\"1080p\\\" ? 90000 : 60000)}\",\"description\":\"FlashVSR is a fast, high-quality video upscaler that boosts resolution and restores clarity for low-resolution or blurry footage. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"upscaler\",\"sort_order\":2800,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flashvsr\",\"request_schema\":{\"properties\":{\"target_resolution\":{\"default\":\"1080p\",\"description\":\"Target resolution to upscale to.\",\"enum\":[\"720p\",\"1080p\",\"2k\",\"4k\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"video\":{\"description\":\"The video to upscale.\",\"type\":\"string\"}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"target_resolution\"]}}]}}', '2026-06-09 08:56:05.893', '2026-06-09 08:56:05.893', '2026-06-09 08:56:05.893');
