INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('43384b5c-eabd-4fa5-b932-dc8978785031', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/subject-3', 'video-effects/subject-3', 'VIDEO', 0.4, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/subject-3\",\"request_schema\":{\"properties\":{\"bgm\":{\"default\":true,\"description\":\"Enable or disable background music for the video.\",\"type\":\"boolean\"},\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Only single-person photos are supported; 3. Better results when the main subject is shown facing forward with upper body or full body visible; 4. Only images with an aspect ratio between 1:2 and 1:1.2 are supported; 5. Images can be provided via URLs or Base64 encode; 6. Supported codecs: PNG, JPEG, JPG, WebP; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\",\"bgm\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"bgm\"]}}]}', '{\"model_id\":\"video-effects/subject-3\",\"name\":\"video-effects/subject-3\",\"base_price\":0.4,\"formula\":\"\",\"description\":\"Subject-3 Dance Video Effect converts photos into image-to-video dance clips with natural motion and background music. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/subject-3\",\"request_schema\":{\"properties\":{\"bgm\":{\"default\":true,\"description\":\"Enable or disable background music for the video.\",\"type\":\"boolean\"},\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Only single-person photos are supported; 3. Better results when the main subject is shown facing forward with upper body or full body visible; 4. Only images with an aspect ratio between 1:2 and 1:1.2 are supported; 5. Images can be provided via URLs or Base64 encode; 6. Supported codecs: PNG, JPEG, JPG, WebP; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\",\"bgm\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"bgm\"]}}]}}', '2026-06-09 08:56:07.022', '2026-06-09 08:56:07.022', '2026-06-09 08:56:07.022');
