INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('44782239-5752-48b9-9277-f377038fee81', NULL, 'cmq0hadjp0000si8dckyresaj', 'nvidia/nemotron-3-nano-omni/video', 'nvidia/nemotron-3-nano-omni/video', 'VIDEO', 0.006, NULL, NULL, 60, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/nvidia/nemotron-3-nano-omni/video\",\"request_schema\":{\"properties\":{\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"max_tokens\":{\"default\":1024,\"description\":\"Maximum number of tokens to generate.\",\"minimum\":1,\"title\":\"Max Tokens\",\"type\":\"integer\"},\"prompt\":{\"description\":\"Text prompt to send to the model. English only.\",\"title\":\"Prompt\",\"type\":\"string\"},\"reasoning_mode\":{\"default\":\"no_think\",\"description\":\"Whether the model should emit an explicit reasoning trace.\",\"enum\":[\"no_think\",\"think\"],\"title\":\"Reasoning Mode\",\"type\":\"string\"},\"system_prompt\":{\"description\":\"Optional system prompt to steer the model.\",\"title\":\"System Prompt\",\"type\":\"string\"},\"temperature\":{\"default\":0.7,\"description\":\"Sampling temperature. Lower values are more deterministic.\",\"minimum\":0,\"title\":\"Temperature\",\"type\":\"number\"},\"top_p\":{\"default\":0.95,\"description\":\"Nucleus sampling probability mass.\",\"maximum\":1,\"minimum\":0,\"title\":\"Top P\",\"type\":\"number\"},\"video_url\":{\"description\":\"URL of the video to reason about.\",\"title\":\"Video URL\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"video/*\"}}},\"required\":[\"prompt\",\"video_url\"],\"title\":\"ChatInput\",\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video_url\",\"system_prompt\",\"reasoning_mode\",\"max_tokens\",\"temperature\",\"top_p\",\"enable_sync_mode\"]}}]}', '{\"model_id\":\"nvidia/nemotron-3-nano-omni/video\",\"name\":\"nvidia/nemotron-3-nano-omni/video\",\"base_price\":0.006,\"formula\":\"{\\\"total_price\\\": base_price * $number(max_tokens) / 1000}\",\"description\":\"NVIDIA Nemotron 3 Nano Omni is an open, efficient reasoning model for enterprise agentic workflows, built on a 30B A3B hybrid Transformer-Mamba MoE architecture. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-to-text\",\"sort_order\":60,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/nvidia/nemotron-3-nano-omni/video\",\"request_schema\":{\"properties\":{\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"max_tokens\":{\"default\":1024,\"description\":\"Maximum number of tokens to generate.\",\"minimum\":1,\"title\":\"Max Tokens\",\"type\":\"integer\"},\"prompt\":{\"description\":\"Text prompt to send to the model. English only.\",\"title\":\"Prompt\",\"type\":\"string\"},\"reasoning_mode\":{\"default\":\"no_think\",\"description\":\"Whether the model should emit an explicit reasoning trace.\",\"enum\":[\"no_think\",\"think\"],\"title\":\"Reasoning Mode\",\"type\":\"string\"},\"system_prompt\":{\"description\":\"Optional system prompt to steer the model.\",\"title\":\"System Prompt\",\"type\":\"string\"},\"temperature\":{\"default\":0.7,\"description\":\"Sampling temperature. Lower values are more deterministic.\",\"minimum\":0,\"title\":\"Temperature\",\"type\":\"number\"},\"top_p\":{\"default\":0.95,\"description\":\"Nucleus sampling probability mass.\",\"maximum\":1,\"minimum\":0,\"title\":\"Top P\",\"type\":\"number\"},\"video_url\":{\"description\":\"URL of the video to reason about.\",\"title\":\"Video URL\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"video/*\"}}},\"required\":[\"prompt\",\"video_url\"],\"title\":\"ChatInput\",\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video_url\",\"system_prompt\",\"reasoning_mode\",\"max_tokens\",\"temperature\",\"top_p\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:07.735', '2026-06-09 08:56:07.735', '2026-06-09 08:56:07.735');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('44bd49ca-7701-44b8-bd5e-c37a22ed4376', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/pinch', 'video-effects/pinch', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/pinch\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single/dual/multi-subject for people, and single subject for animals and objects; 3. Best for waist-up or full-body shots of people, and single independent objects or animals; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/pinch\",\"name\":\"video-effects/pinch\",\"base_price\":0.2,\"formula\":\"\",\"description\":\"Turn photos into humorous pinch-and-squeeze videos that warp faces and objects into playful short clips great for social sharing. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/pinch\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single/dual/multi-subject for people, and single subject for animals and objects; 3. Best for waist-up or full-body shots of people, and single independent objects or animals; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.085', '2026-06-09 08:56:07.085', '2026-06-09 08:56:07.085');
