tion\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"},\"strength\":{\"default\":0.8,\"description\":\"Strength indicates extent to transform the reference image.\",\"maximum\":1,\"minimum\":0,\"step\":0.1,\"type\":\"number\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"mask_image\",\"strength\",\"size\",\"num_inference_steps\",\"seed\",\"guidance_scale\",\"num_images\",\"output_format\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}', '{\"model_id\":\"wavespeed-ai/flux-dev-ultra-fast\",\"name\":\"wavespeed-ai/flux-dev-ultra-fast\",\"base_price\":0.005,\"formula\":\"{\\\"total_price\\\":base_price * num_images}\",\"description\":\"FLUX.1 [dev] is a 12B rectified-flow transformer for high-quality text-to-image generation, optimized for ultra-fast inference. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-dev-ultra-fast\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows 