onent-props\":{\"accept\":\"video/*\"}}},\"required\":[\"videos\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"videos\",\"prompt\",\"negative_prompt\",\"audio\",\"size\",\"duration\",\"shot_type\",\"enable_prompt_expansion\",\"seed\"]}}]}', '{\"model_id\":\"alibaba/wan-2.6/reference-to-video\",\"name\":\"alibaba/wan-2.6/reference-to-video\",\"base_price\":0.5,\"formula\":\"{\\\"total_price\\\": base_price * $number(duration + 5) / 5 * ((size = \\\"1920*1080\\\" or size = \\\"1080*1920\\\") ? 1.5 : 1)}\",\"description\":\"Alibaba WAN 2.6 Reference-to-Video turns character, prop, or scene references—single or multi-view—into new video shots with preserved identity, style, and layout plus smooth, coherent motion. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":5950,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.6/reference-to-video\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"Audio URL to guide generation (optional).\",\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[5,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"If set to true, the prompt optimizer will be enabled.\",\"type\":\"boolean\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"shot_type\":{\"default\":\"single\",\"description\":\"The type of shots to generate.\",\"enum\":[\"single\",\"multi\"],\"type\":\"string\"},\"size\":{\"default\":\"1280*720\",\"description\":\"The size of the generated media in pixels (width*height).\",\"enum\":[\"1280*720\",\"720*1280\",\"1920*1080\",\"1080*1920\"],\"type\":\"string\"},\"videos\":{\"description\":\"Array of URLs to reference videos.\",\"items\":{\"description\":\"Array of URLs to reference videos. Maximum 2 videos allowed.\",\"type\":\"string\"},\"maxItems\":3,\"minItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"video/*\"}}},\"required\":[\"videos\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"videos\",\"prompt\",\"negative_prompt\",\"audio\",\"size\",\"duration\",\"shot_type\",\"enable_prompt_expansion\",\"seed\"]}}]}}', '2026-06-09 08:56:05.700', '2026-06-09 08:56:05.700', '2026-06-09 08:56:05.700');
