itch ? 100000 : 0) + (generate_multi_clip_switch ? 300000 : 0) }\",\"description\":\"Create smooth morph transitions between two images into 5s , 8s or 10s videos at 360p, 540p, 720p, or 1080p—perfect for logo reveals, before-and-after shots, and social posts. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/pixverse/pixverse-v5.5-transition\",\"request_schema\":{\"allOf\":[{\"if\":{\"properties\":{\"resolution\":{\"const\":\"1080p\"}},\"required\":[\"resolution\"]},\"then\":{\"properties\":{\"duration\":{\"default\":5,\"enum\":[5,8],\"type\":\"integer\"}}}},{\"if\":{\"properties\":{\"resolution\":{\"enum\":[\"360p\",\"540p\",\"720p\"]}},\"required\":[\"resolution\"]},\"then\":{\"properties\":{\"duration\":{\"default\":5,\"enum\":[5,8,10],\"type\":\"integer\"}}}}],\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"16:9\",\"1:1\",\"4:3\",\"3:4\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"duration\":{\"default\":5,\"description\":\"Video duration in seconds.\",\"enum\":[5,8,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"end_image\":{\"description\":\"The model generates video with the picture passed in as the last frame.Base64 encoded strings in data:image/jpeg; base64,{data} format for incoming images, or URLs accessible via the public network. The uploaded image needs to meet the following conditions: Format is JPG/JPEG/PNG; The aspect ratio is greater than 2:5 and less than 5:2; Short side pixels greater than 300px; The image file size cannot exceed 20MB.\",\"type\":\"string\"},\"image\":{\"description\":\"The model generates video with the picture passed in as the first frame.Base64 encoded strings in data:image/jpeg; base64,{data} for