i.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/image-captioner\",\"request_schema\":{\"properties\":{\"detail_level\":{\"default\":\"medium\",\"description\":\"Level of detail for the caption.\",\"enum\":[\"low\",\"medium\",\"high\"],\"type\":\"string\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"focus\":{\"description\":\"Specific area or subject to focus on in the caption (optional).\",\"type\":\"string\",\"x-ui-component\":\"textarea\"},\"image\":{\"description\":\"Image to caption\",\"type\":\"string\"}},\"type\":\"object\",\"x-order-properties\":[\"image\",\"detail_level\",\"focus\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:06.560', '2026-06-09 08:56:06.560', '2026-06-09 08:56:06.560');
