,\"title\":\"Reference\",\"type\":\"array\",\"x-ui-component\":\"array\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"creativity\",\"reference\"]}}]}', '{\"model_id\":\"wavespeed-ai/krea-v2-medium/text-to-image\",\"name\":\"wavespeed-ai/krea-v2-medium/text-to-image\",\"base_price\":0.03,\"formula\":\"{\\\"total_price\\\": base_price + (($exists(reference) and $count(reference) > 0) ? 5000 : 0)}\",\"description\":\"Krea 2 Medium Text to Image generates high-quality images from text prompts with aspect ratio, creativity, and optional style reference controls.\",\"type\":\"text-to-image\",\"sort_order\":10000,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/krea-v2-medium/text-to-image\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"1:1\",\"description\":\"Aspect ratio of the generated image.\",\"enum\":[\"1:1\",\"4:3\",\"3:2\",\"16:9\",\"2.35:1\",\"4:5\",\"2:3\",\"9:16\"],\"title\":\"Aspect Ratio\",\"type\":\"string\",\"x-ui-component\":\"select\"},\"creativity\":{\"default\":\"medium\",\"description\":\"Controls how loosely the model interprets the prompt.\",\"enum\":[\"raw\",\"low\",\"medium\",\"high\"],\"title\":\"Creativity\",\"type\":\"string\",\"x-ui-component\":\"select\"},\"prompt\":{\"description\":\"Text description of the image to generate.\",\"maxLength\":5000,\"minLength\":1,\"title\":\"Prompt\",\"type\":\"string\",\"x-rows\":4,\"x-ui-component\":\"textarea\"},\"reference\":{\"description\":\"Optional reference images that guide the style of the generated image.\",\"items\":{\"properties\":{\"image_url\":{\"description\":\"Reference image URL.\",\"format\":\"uri\",\"title\":\"Image\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"strength\":{\"default\":1,\"description\":\"How strongly the reference image influences the generated image.\",\"maximum\":2,\"minimum\":-2,\"step\":0.1,\"title\":\"Strength\",\"type\":\"number\"}},\"required\":[\"image_url\"],\"type\":\"object\",\"x-order-properties\":[\"image_url\",\"strength\"]},\"maxItems\":10,\"title\":\"Reference\",\"type\":\"array\",\"x-ui-component\":\"array\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"creativity\",\"reference\"]}}]}}', '2026-06-09 08:56:05.405', '2026-06-09 08:56:05.405', '2026-06-09 08:56:05.405');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('4976ff77-4303-444f-a0f8-5f921b7c5e35', NULL, 'cmq0hadjp0000si8dckyresaj', 'bytedance/seedance-2.0/text-to-video-turbo', 'bytedance/seedance-2.0/text-to-video-turbo', 'VIDEO', 0.7, NULL, NULL, 7400, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedance-2.0/text-to-video-turbo\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated video.\",\"enum\":[\"16:9\",\"9:16\",\"4:3\",\"3:4\",\"1:1\",\"21:9\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated video in seconds (4-15s).\",\"maximum\":15,\"minimum\":4,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_web_search\":{\"default\":false,\"description\":\"Enable web search for real-time information.\",\"type\":\"boolean\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate native audio synchronized with the output video. Defaults to true.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"Describe the scene, action, camera movement, and mood for the video.\",\"type\":\"string\"},\"reference_audios\":{\"description\":\"Reference audio URLs (total length must not exceed 15 seconds).\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"audio/*\"}},\"reference_images\":{\"description\":\"Reference image URLs to guide visual style, characters, or scene composition.\",\"items\":{\"type\":\"string\"},\"maxItems\":9,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"reference_videos\":{\"description\":\"Reference video URLs (total length must not exceed 15 seconds).\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"video/*\"}},\"resolution\":{\"default\":\"720p\",\"description\":\"The output video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"reference_images\",\"reference_videos\",\"reference_audios\",\"aspect_ratio\",\"resolution\",\"duration\",\"enable_web_search\",\"generate_audio\"]}}]}', '{\"model_id\":\"bytedance/seedance-2.0/text-to-video-turbo\",\"name\":\"bytedance/seedance-2.0/text-to-video-turbo\",\"base_price\":0.7,\"formula\":\"{\\\"total_price\\\": (($count(reference_videos) > 0 ? 1200000 : 600000) + (resolution = \\\"1080p\\\" ? 150000 : 100000)) * $number(duration) / 5}\",\"description\":\"Seedance 2.0 (Text-to-Video Turbo) generates cinematic videos from text prompts at 720p and 1080p with native audio-visual synchronization, director-level camera and lighting control, and exceptional motion stability — optimized for turbo output. Built on ByteDance Seed\'s unified multimodal architecture. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"text-to-video\",\"sort_order\":7400,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedance-2.0/text-to-video-turbo\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated video.\",\"enum\":[\"16:9\",\"9:16\",\"4:3\",\"3:4\",\"1:1\",\"21:9\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated video in seconds (4-15s).\",\"maximum\":15,\"minimum\":4,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_web_search\":{\"default\":false,\"description\":\"Enable web search for real-time information.\",\"type\":\"boolean\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate native audio synchronized with the output video. Defaults to true.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"Describe the scene, action, camera movement, and mood for the video.\",\"type\":\"string\"},\"reference_audios\":{\"description\":\"Reference audio URLs (total length must not exceed 15 seconds).\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"audio/*\"}},\"reference_images\":{\"description\":\"Reference image URLs to guide visual style, characters, or scene composition.\",\"items\":{\"type\":\"string\"},\"maxItems\":9,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"reference_videos\":{\"description\":\"Reference video URLs (total length must not exceed 15 seconds).\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"video/*\"}},\"resolution\":{\"default\":\"720p\",\"description\":\"The output video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"reference_images\",\"reference_videos\",\"reference_audios\",\"aspect_ratio\",\"resolution\",\"duration\",\"enable_web_search\",\"generate_audio\"]}}]}}', '2026-06-09 08:56:05.650', '2026-06-09 08:56:05.650', '2026-06-09 08:56:05.650');
