scription\":\"List of LoRAs to apply (maximum 3).\",\"items\":{\"$ref\":\"#/components/schemas/LoraWeight\"},\"maxItems\":3,\"type\":\"array\"},\"negative_prompt\":{\"default\":\"\",\"description\":\"The negative prompt for the generation. Describes what you don\'t want in the image.\",\"type\":\"string\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"},\"strength\":{\"default\":0.6,\"description\":\"Controls the strength of the transformation. Higher values produce outputs more different from the input image.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"negative_prompt\",\"image\",\"loras\",\"size\",\"strength\",\"seed\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.961', '2026-06-09 08:56:06.961', '2026-06-09 08:56:06.961');
