oduction-ready outputs, API access, and open access.\",\"type\":\"text-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/ltx-2.3/text-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"Aspect ratio of the video.\",\"enum\":[\"16:9\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"maximum\":20,\"minimum\":5,\"type\":\"integer\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Video resolution.\",\"enum\":[\"480p\",\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"resolution\",\"aspect_ratio\",\"duration\",\"seed\"]}}]}}', '2026-06-09 08:56:07.179', '2026-06-09 08:56:07.179', '2026-06-09 08:56:07.179');
