, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":2100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/image-zoom-out\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"image\":{\"description\":\"The image to generate an image from.\",\"type\":\"string\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\",\"webp\"],\"type\":\"string\"},\"size\":{\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\",\"x-hidden\":true}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"size\",\"output_format\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:05.973', '2026-06-09 08:56:05.973', '2026-06-09 08:56:05.973');
