,\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"size\",\"max_images\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}', '{\"model_id\":\"bytedance/seedream-v4/edit-sequential\",\"name\":\"bytedance/seedream-v4/edit-sequential\",\"base_price\":0.027,\"formula\":\"{\\\"total_price\\\":base_price * max_images}\",\"description\":\"Seedream 4.0 by ByteDance: 4K image generation and editing with character and object consistency and sequential multi-image outputs. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":3450,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedream-v4/edit-sequential\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"images\":{\"description\":\"The images to edit. A maximum of 10 reference images can be uploaded.\",\"items\":{\"type\":\"string\"},\"maxItems\":10,\"minItems\":1,\"type\":\"array\"},\"max_images\":{\"default\":1,\"description\":\"The maximum number of images that can be generated (up to 15). This value must align with the number of images specified in the prompt above.\",\"maximum\":15,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\",\"x-rows\":10,\"x-ui-component\":\"textarea\"},\"size\":{\"description\":\"The size of the generated media in pixels (width*height).\",\"maximum\":8192,\"minimum\":512,\"type\":\"string\",\"x-hidden\":true}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"size\",\"max_images\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:05.824', '2026-06-09 08:56:05.824', '2026-06-09 08:56:05.824');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('4dc298b7-a023-4224-9dc3-5d83b6fa76ad', NULL, 'cmq0hadjp0000si8dckyresaj', 'elevenlabs/dubbing', 'elevenlabs/dubbing', 'IMAGE', 0.9, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/elevenlabs/dubbing\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"URL of the audio file to dub. Either video or audio must be provided.\",\"type\":\"string\"},\"source_lang\":{\"default\":\"Auto\",\"description\":\"Source language. Select \'Auto\' for automatic detection.\",\"type\":\"string\",\"x-enum\":[\"Auto\",\"English\",\"Spanish\",\"French\",\"German\",\"Italian\",\"Portuguese\",\"Chinese\",\"Japanese\",\"Korean\",\"Russian\",\"Arabic\",\"Hindi\",\"Dutch\",\"Polish\",\"Turkish\",\"Vietnamese\",\"Thai\",\"Indonesian\"],\"x-ui-component\":\"command\"},\"target_lang\":{\"description\":\"Target language for dubbing\",\"type\":\"string\",\"x-enum\":[\"English\",\"Spanish\",\"French\",\"German\",\"Italian\",\"Portuguese\",\"Chinese\",\"Japanese\",\"Korean\",\"Russian\",\"Arabic\",\"Hindi\",\"Dutch\",\"Polish\",\"Turkish\",\"Vietnamese\",\"Thai\",\"Indonesian\"],\"x-ui-component\":\"command\"},\"video\":{\"description\":\"URL of the video file to dub. Either video or audio must be provided. If both are provided, video takes priority.\",\"type\":\"string\"}},\"required\":[\"target_lang\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"audio\",\"target_lang\",\"source_lang\"]}}]}', '{\"model_id\":\"elevenlabs/dubbing\",\"name\":\"elevenlabs/dubbing\",\"base_price\":0.9,\"formula\":\"{\\\"total_price\\\": $max([1, $ceil($min([($number(get_duration_v3(video)) + $number(get_duration_v3(audio))), 600]) / 60)]) * base_price}\",\"description\":\"ElevenLabs Dubbing automatically translates and dubs video/audio content into different languages while preserving the original speakers\' voices. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"video-dubbing\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/elevenlabs/dubbing\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"URL of the audio file to dub. Either video or audio must be provided.\",\"type\":\"string\"},\"source_lang\":{\"default\":\"Auto\",\"description\":\"Source language. Select \'Auto\' for automatic detection.\",\"type\":\"string\",\"x-enum\":[\"Auto\",\"English\",\"Spanish\",\"French\",\"German\",\"Italian\",\"Portuguese\",\"Chinese\",\"Japanese\",\"Korean\",\"Russian\",\"Arabic\",\"Hindi\",\"Dutch\",\"Polish\",\"Turkish\",\"Vietnamese\",\"Thai\",\"Indonesian\"],\"x-ui-component\":\"command\"},\"target_lang\":{\"description\":\"Target language for dubbing\",\"type\":\"string\",\"x-enum\":[\"English\",\"Spanish\",\"French\",\"German\",\"Italian\",\"Portuguese\",\"Chinese\",\"Japanese\",\"Korean\",\"Russian\",\"Arabic\",\"Hindi\",\"Dutch\",\"Polish\",\"Turkish\",\"Vietnamese\",\"Thai\",\"Indonesian\"],\"x-ui-component\":\"command\"},\"video\":{\"description\":\"URL of the video file to dub. Either video or audio must be provided. If both are provided, video takes priority.\",\"type\":\"string\"}},\"required\":[\"target_lang\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"audio\",\"target_lang\",\"source_lang\"]}}]}}', '2026-06-09 08:56:06.883', '2026-06-09 08:56:06.883', '2026-06-09 08:56:06.883');
