x-order-properties\":[\"prompt\",\"image\",\"audio\",\"negative_prompt\",\"resolution\",\"duration\",\"shot_type\",\"enable_prompt_expansion\",\"seed\"]}}]}}', '2026-06-09 08:56:05.705', '2026-06-09 08:56:05.705', '2026-06-09 08:56:05.705');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('4e34e8c9-0bba-42b1-84e1-b13f3244cc4c', NULL, 'cmq0hadjp0000si8dckyresaj', 'minimax/speech-2.8-turbo', 'minimax/speech-2.8-turbo', 'AUDIO', 0.06, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/speech-2.8-turbo\",\"request_schema\":{\"properties\":{\"bitrate\":{\"description\":\"Bitrate of generated sound.\",\"enum\":[32000,64000,128000,256000],\"type\":\"integer\",\"x-placeholder\":\"Select the bitrate\"},\"channel\":{\"description\":\"The number of channels of the generated audio. 1: mono, 2: stereo.\",\"enum\":[\"1\",\"2\"],\"type\":\"string\",\"x-placeholder\":\"Select the channel\"},\"emotion\":{\"default\":\"happy\",\"description\":\"The emotion of the generated speech.\",\"enum\":[\"happy\",\"sad\",\"angry\",\"fearful\",\"disgusted\",\"surprised\",\"neutral\"],\"type\":\"string\",\"x-placeholder\":\"Select the emotion\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"english_normalization\":{\"default\":false,\"description\":\"This parameter supports English text normalization, which improves performance in number-reading scenarios.\",\"type\":\"boolean\"},\"format\":{\"description\":\"Format of generated