INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('50da95eb-c713-4b11-920d-1676f5234af0', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/ace-step/audio-inpaint', 'wavespeed-ai/ace-step/audio-inpaint', 'AUDIO', 0.0002, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/ace-step/audio-inpaint\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"Audio file to transcribe. Provide an HTTPS URL or upload a file (MP3, WAV, FLAC up to 60 minutes).\",\"type\":\"string\",\"x-accept\":\"audio/mpeg,audio/mp3,audio/wav,audio/x-wav,audio/flac\",\"x-placeholder\":\"Upload or link to an audio file\",\"x-ui-component\":\"uploader\"},\"end_time\":{\"default\":30,\"description\":\"End time in seconds.\",\"maximum\":240,\"minimum\":0,\"type\":\"number\"},\"end_time_relative_to\":{\"default\":\"start\",\"description\":\"Reference point for end time.\",\"enum\":[\"start\",\"end\"],\"type\":\"string\"},\"lyrics\":{\"default\":\"\",\"description\":\"Lyrics to be sung in the audio. Use [inst] or [instrumental] for no vocals.\",\"type\":\"string\",\"x-rows\":5,\"x-ui-component\":\"textarea\"},\"seed\":{\"default\":-1,\"description\":\"The random seed for reproducibility.\",\"type\":\"integer\"},\"start_time\":{\"default\":0,\"description\":\"Start time in seconds.\",\"maximum\":240,\"minimum\":0,\"type\":\"number\"},\"start_time_relative_to\":{\"default\":\"start\",\"description\":\"Reference point for start time.\",\"enum\":[\"start\",\"end\"],\"type\":\"string\"},\"tags\":{\"description\":\"Comma-separated list of genre tags to control the style.\",\"type\":\"string\"}},\"required\":[\"audio\",\"tags\"],\"type\":\"object\",\"x-order-properties\":[\"audio\",\"tags\",\"start_time_relative_to\",\"start_time\",\"end_time_relative_to\",\"end_time\",\"lyrics\",\"seed\"]}}]}', '{\"model_id\":\"wavespeed-ai/ace-step/audio-inpaint\",\"name\":\"wavespeed-ai/ace-step/audio-inpaint\",\"base_price\":0.0002,\"formula\":\"{\\\"total_price\\\": $number(get_duration_v3(audio)) * base_price}\",\"description\":\"ACE-Step Audio Inpaint edits a specific audio segment to change lyrics or style while preserving the surrounding audio. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"audio-to-audio\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/ace-step/audio-inpaint\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"Audio file to transcribe. Provide an HTTPS URL or upload a file (MP3, WAV, FLAC up to 60 minutes).\",\"type\":\"string\",\"x-accept\":\"audio/mpeg,audio/mp3,audio/wav,audio/x-wav,audio/flac\",\"x-placeholder\":\"Upload or link to an audio file\",\"x-ui-component\":\"uploader\"},\"end_time\":{\"default\":30,\"description\":\"End time in seconds.\",\"maximum\":240,\"minimum\":0,\"type\":\"number\"},\"end_time_relative_to\":{\"default\":\"start\",\"description\":\"Reference point for end time.\",\"enum\":[\"start\",\"end\"],\"type\":\"string\"},\"lyrics\":{\"default\":\"\",\"description\":\"Lyrics to be sung in the audio. Use [inst] or [instrumental] for no vocals.\",\"type\":\"string\",\"x-rows\":5,\"x-ui-component\":\"textarea\"},\"seed\":{\"default\":-1,\"description\":\"The random seed for reproducibility.\",\"type\":\"integer\"},\"start_time\":{\"default\":0,\"description\":\"Start time in seconds.\",\"maximum\":240,\"minimum\":0,\"type\":\"number\"},\"start_time_relative_to\":{\"default\":\"start\",\"description\":\"Reference point for start time.\",\"enum\":[\"start\",\"end\"],\"type\":\"string\"},\"tags\":{\"description\":\"Comma-separated list of genre tags to control the style.\",\"type\":\"string\"}},\"required\":[\"audio\",\"tags\"],\"type\":\"object\",\"x-order-properties\":[\"audio\",\"tags\",\"start_time_relative_to\",\"start_time\",\"end_time_relative_to\",\"end_time\",\"lyrics\",\"seed\"]}}]}}', '2026-06-09 08:56:06.407', '2026-06-09 08:56:06.407', '2026-06-09 08:56:06.407');
