INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('512d878a-3841-4e11-82c0-739e856a930a', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/hunyuan3d-v3/text-to-3d', 'wavespeed-ai/hunyuan3d-v3/text-to-3d', '3D', 0.25, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/hunyuan3d-v3/text-to-3d\",\"request_schema\":{\"properties\":{\"enable_pbr\":{\"default\":false,\"description\":\"Whether to enable PBR material generation\",\"type\":\"boolean\"},\"face_count\":{\"default\":500000,\"description\":\"Target face count. Range: 40000-1500000\",\"maximum\":1500000,\"minimum\":40000,\"title\":\"Face Count\",\"type\":\"integer\"},\"generate_type\":{\"default\":\"Normal\",\"description\":\"Generation type. Normal: textured model. LowPoly: polygon reduction. Geometry: white model without texture.\",\"enum\":[\"Normal\",\"LowPoly\",\"Geometry\"],\"type\":\"string\"},\"polygon_type\":{\"default\":\"triangle\",\"description\":\"Polygon type. Only takes effect when GenerateType is LowPoly.\",\"enum\":[\"triangle\",\"quadrilateral\"],\"type\":\"string\"},\"prompt\":{\"description\":\"Text description of the 3D content to generate. Supports up to 1024 UTF-8 characters.\",\"maxLength\":1024,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"enable_pbr\",\"polygon_type\",\"face_count\",\"generate_type\"]}}]}', '{\"model_id\":\"wavespeed-ai/hunyuan3d-v3/text-to-3d\",\"name\":\"wavespeed-ai/hunyuan3d-v3/text-to-3d\",\"base_price\":0.25,\"formula\":\"{\\\"total_price\\\": (generate_type= \\\"LowPoly\\\") ? 450000: ((generate_type = \\\"Geometry\\\") ? 250000 : 375000)}\",\"description\":\"Turn text prompts into detailed, fully-textured 3D models with Tencent\'s Hunyuan3D V3. Generate high-quality 3D assets with PBR materials from simple descriptions, ready for Unity, Unreal, and Blender. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-3d\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/hunyuan3d-v3/text-to-3d\",\"request_schema\":{\"properties\":{\"enable_pbr\":{\"default\":false,\"description\":\"Whether to enable PBR material generation\",\"type\":\"boolean\"},\"face_count\":{\"default\":500000,\"description\":\"Target face count. Range: 40000-1500000\",\"maximum\":1500000,\"minimum\":40000,\"title\":\"Face Count\",\"type\":\"integer\"},\"generate_type\":{\"default\":\"Normal\",\"description\":\"Generation type. Normal: textured model. LowPoly: polygon reduction. Geometry: white model without texture.\",\"enum\":[\"Normal\",\"LowPoly\",\"Geometry\"],\"type\":\"string\"},\"polygon_type\":{\"default\":\"triangle\",\"description\":\"Polygon type. Only takes effect when GenerateType is LowPoly.\",\"enum\":[\"triangle\",\"quadrilateral\"],\"type\":\"string\"},\"prompt\":{\"description\":\"Text description of the 3D content to generate. Supports up to 1024 UTF-8 characters.\",\"maxLength\":1024,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"enable_pbr\",\"polygon_type\",\"face_count\",\"generate_type\"]}}]}}', '2026-06-09 08:56:06.747', '2026-06-09 08:56:06.747', '2026-06-09 08:56:06.747');
