pe\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/happyhorse-1.0/video-extend\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"Total duration of the final output video in seconds (3-15).\",\"maximum\":15,\"minimum\":3,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"prompt\":{\"description\":\"Text description of the desired continuation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Output video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"description\":\"Random seed for reproducibility.\",\"type\":\"integer\"},\"video\":{\"description\":\"The source video to extend.\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"video/*\"}}},\"required\":[\"video\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"resolution\",\"duration\",\"seed\"]}}]}}', '2026-06-09 08:56:05.365', '2026-06-09 08:56:05.365', '2026-06-09 08:56:05.365');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('5158dfc3-7b09-4041-a3bb-4a7c352ee0c5', NULL, 'cmq0hadjp0000si8dckyresaj', 'clarity-ai/crystal-upscaler', 'clarity-ai/crystal-upscaler', 'IMAGE', 0.03, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/clarity-ai/crystal-upscaler\",\"request_schema\":{\"properties\":{\"creativity\":{\"default\":0,\"description\":\"Negative values stay stricter to the source; positive values add more generated detail.\",\"maximum\":10,\"minimum\":-10,\"step\":0.1,\"title\":\"Creativity\",\"type\":\"number\",\"x-ui-component\":\"slider\"},\"image\":{\"description\":\"Input image to upscale.\",\"title\":\"Image\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"target_megapixels\":{\"default\":4,\"description\":\"Requested output size in megapixels. The backend prepares the input so the output lands near this target. Range: 1-200 MP.\",\"maximum\":200,\"minimum\":1,\"step\":1,\"title\":\"Target Megapixels\",\"type\":\"number\",\"x-ui-component\":\"slider\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"target_megapixels\",\"creativity\"]}}]}', '{\"model_id\":\"clarity-ai/crystal-upscaler\",\"name\":\"clarity-ai/crystal-upscaler\",\"base_price\":0.03,\"formula\":\"{   \\\"total_price\\\": 1000000 * (     (target_megapixels <= 4) ? 0.05 :     (target_megapixels > 4 and target_megapixels <= 8) ? 0.10 :     (target_megapixels > 8 and target_megapixels <= 16) ? 0.20 :     (target_megapixels > 16 and target_megapixels <= 25) ? 0.40 :     (target_megapixels > 25 and target_megapixels <= 50) ? 0.80 :     (target_megapixels > 50 and target_megapixels <= 100) ? 1.60 :     3.20   ) }\",\"description\":\"Clarity AI Crystal Upscaler boosts image resolution with AI upscaling and adjustable detail for portraits and landscapes. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"upscaler\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/clarity-ai/crystal-upscaler\",\"request_schema\":{\"properties\":{\"creativity\":{\"default\":0,\"description\":\"Negative values stay stricter to the source; positive values add more generated detail.\",\"maximum\":10,\"minimum\":-10,\"step\":0.1,\"title\":\"Creativity\",\"type\":\"number\",\"x-ui-component\":\"slider\"},\"image\":{\"description\":\"Input image to upscale.\",\"title\":\"Image\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"target_megapixels\":{\"default\":4,\"description\":\"Requested output size in megapixels. The backend prepares the input so the output lands near this target. Range: 1-200 MP.\",\"maximum\":200,\"minimum\":1,\"step\":1,\"title\":\"Target Megapixels\",\"type\":\"number\",\"x-ui-component\":\"slider\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"target_megapixels\",\"creativity\"]}}]}}', '2026-06-09 08:56:06.513', '2026-06-09 08:56:06.513', '2026-06-09 08:56:06.513');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('5170ed3c-c0b9-4135-afa3-2a1a81a4b0f5', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/wan-2.2-image-lora-trainer', 'wavespeed-ai/wan-2.2-image-lora-trainer', 'IMAGE', 3, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/wan-2.2-image-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"To train a WAN T2V LoRA, you need to upload a zip file containing at least 10 images. In addition to images the archive can contain text files with captions. Each text file should have the same name as the image file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing images.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0002,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":32,\"maximum\":128,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":1000,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":10000,\"minimum\":1000,\"step\":10,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"The phrase that will trigger the model to generate an video.\",\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}', '{\"model_id\":\"wavespeed-ai/wan-2.2-image-lora-trainer\",\"name\":\"wavespeed-ai/wan-2.2-image-lora-trainer\",\"base_price\":3,\"formula\":\"{\\\"total_price\\\":base_price * (steps / 2000)}\",\"description\":\"Train custom Wan 2.2 character/style LoRA models 10x faster. Style training, character training, object training. From concept to model in minutes, not hours. Upload a ZIP file containing images to start!\",\"type\":\"training\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/wan-2.2-image-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"To train a WAN T2V LoRA, you need to upload a zip file containing at least 10 images. In addition to images the archive can contain text files with captions. Each text file should have the same name as the image file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing images.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0002,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":32,\"maximum\":128,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":1000,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":10000,\"minimum\":1000,\"step\":10,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"The phrase that will trigger the model to generate an video.\",\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}}', '2026-06-09 08:56:07.369', '2026-06-09 08:56:07.369', '2026-06-09 08:56:07.369');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('51891c79-6129-42ec-b3b4-701f0587fb35', NULL, 'cmq0hadjp0000si8dckyresaj', 'minimax/hailuo-02/fast', 'minimax/hailuo-02/fast', 'IMAGE', 0.1, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/hailuo-02/fast\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":6,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[6,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":true,\"description\":\"The model automatically optimizes incoming prompts to enhance output quality. This also activates the safety checker, which ensures content safety by detecting and filtering potential risks.\",\"type\":\"boolean\"},\"go_fast\":{\"default\":true,\"description\":\"Prioritize faster video generation speed with a moderate trade-off in visual quality\",\"type\":\"boolean\"},\"image\":{\"description\":\"The model generates video with the picture passed in as the first frame.Base64 encoded strings in data:image/jpeg; base64,{data} format for incoming images, or URLs accessible via the public network. The uploaded image needs to meet the following conditions: Format is JPG/JPEG/PNG; The aspect ratio is greater than 2:5 and less than 5:2; Short side pixels greater than 300px; The image file size cannot exceed 20MB.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"maxLength\":2000,\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"prompt\",\"duration\",\"enable_prompt_expansion\",\"go_fast\"]}}]}', '{\"model_id\":\"minimax/hailuo-02/fast\",\"name\":\"minimax/hailuo-02/fast\",\"base_price\":0.1,\"formula\":\"{\\\"total_price\\\": (duration = 10) ? 150000: 100000}\",\"description\":\"Hailuo 02 Fast is a minimax image-to-video model that creates high-quality 6s and 10s clips at 512p for creators and marketers. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/hailuo-02/fast\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":6,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[6,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":true,\"description\":\"The model automatically optimizes incoming prompts to enhance output quality. This also activates the safety checker, which ensures content safety by detecting and filtering potential risks.\",\"type\":\"boolean\"},\"go_fast\":{\"default\":true,\"description\":\"Prioritize faster video generation speed with a moderate trade-off in visual quality\",\"type\":\"boolean\"},\"image\":{\"description\":\"The model generates video with the picture passed in as the first frame.Base64 encoded strings in data:image/jpeg; base64,{data} format for incoming images, or URLs accessible via the public network. The uploaded image needs to meet the following conditions: Format is JPG/JPEG/PNG; The aspect ratio is greater than 2:5 and less than 5:2; Short side pixels greater than 300px; The image file size cannot exceed 20MB.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"maxLength\":2000,\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"prompt\",\"duration\",\"enable_prompt_expansion\",\"go_fast\"]}}]}}', '2026-06-09 08:56:07.540', '2026-06-09 08:56:07.540', '2026-06-09 08:56:07.540');
