t Megapixels\",\"type\":\"number\",\"x-ui-component\":\"slider\"},\"video\":{\"description\":\"Input video to upscale.\",\"title\":\"Video\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"video/*\"}}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"target_megapixels\"]}}]}}', '2026-06-09 08:56:06.131', '2026-06-09 08:56:06.131', '2026-06-09 08:56:06.131');
