tput.\",\"type\":\"string\"}},\"required\":[\"video\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"resolution\",\"duration\",\"loras\",\"high_noise_loras\",\"low_noise_loras\",\"seed\"]}}]}}', '2026-06-09 08:56:06.423', '2026-06-09 08:56:06.423', '2026-06-09 08:56:06.423');
