e\":0.56,\"formula\":\"{\\\"total_price\\\": $number(duration) / 5  * base_price }\",\"description\":\"Kling Omni Video O1 Image-to-Video transforms static images into dynamic cinematic videos using MVL (Multi-modal Visual Language) technology. Maintains subject consistency while adding natural motion, physics simulation, and seamless scene dynamics. Ready-to-use REST API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":2600,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/kwaivgi/kling-video-o1/image-to-video\",\"request_schema\":{\"else\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"The duration of the generated media. Only 5s or 10s are supported when last_image is not used.\",\"enum\":[5,10],\"type\":\"integer\",\"x-ui-component\":\"select\"}}},\"if\":{\"properties\":{\"last_image\":{\"minLength\":1,\"type\":\"string\"}},\"required\":[\"last_image\"]},\"properties\":{\"duration\":{\"default\":5,\"description\":\"The duration of the generated media. Only 5s or 10s are supported when last_image is not used.\",\"enum\":[3,4,5,6,7,8,9,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"image\":{\"description\":\"first_frame is the first frame\",\"type\":\"string\",\"x-ui-component\":\"uploader\"},\"last_image\":{\"description\":\"last_frame is the last frame.\",\"type\":\"string\",\"x-ui-component\":\"uploader\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"}},\"required\":[\"prompt\",\"image\"],\"then\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"The duration of the generated media.\",\"enum\":[3,4,5,6,7,8,9,10],\"type\":\"integer\",\"x-ui-component\":\"select\"}}},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"last_image\",\"duration\"]}}]}}', '2026-06-09 08:56:05.913', '2026-06-09 08:56:05.913', '2026-06-09 08:56:05.9