INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('56241e68-76e6-489f-9e43-92539bb1c169', NULL, 'cmq0hadjp0000si8dckyresaj', 'elevenlabs/eleven-v3/timing', 'elevenlabs/eleven-v3/timing', 'IMAGE', 0.1, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/elevenlabs/eleven-v3/timing\",\"request_schema\":{\"properties\":{\"similarity\":{\"default\":1,\"description\":\"High enhancement boosts overall voice clarity and target speaker similarity. Very high values can cause artifacts, so adjusting this setting to find the optimal value is encouraged.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"stability\":{\"default\":0.5,\"description\":\"Voice stability (0-1) Default value: 0.5\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"text\":{\"default\":\"Welcome to our advanced text-to-speech system! Experience high-quality voice synthesis with natural pronunciation and clear articulation.\",\"description\":\"Text to convert to speech. Every character is 1 token. Maximum 10000 characters. Use <#x#> between words to control pause duration (0.01-99.99s).\",\"maxLength\":10000,\"type\":\"string\",\"x-rows\":5,\"x-ui-component\":\"textarea\"},\"use_speaker_boost\":{\"default\":true,\"description\":\"This parameter supports English text normalization, which improves performance in number-reading scenarios.\",\"type\":\"boolean\"},\"voice_id\":{\"default\":\"Alice\",\"description\":\"The voice to use for speech generation\",\"type\":\"string\",\"x-enum\":[\"Aria\",\"Roger\",\"Sarah\",\"Laura\",\"Charlie\",\"George\",\"Callum\",\"River\",\"Liam\",\"Charlotte\",\"Alice\",\"Matilda\",\"Will\",\"Jessica\",\"Eric\",\"Chris\",\"Brian\",\"Daniel\",\"Lily\",\"Bill\"],\"x-placeholder\":\"Please input your custom voice ID\",\"x-ui-component\":\"command\"}},\"required\":[\"text\",\"voice_id\"],\"type\":\"object\",\"x-order-properties\":[\"text\",\"voice_id\",\"similarity\",\"stability\",\"use_speaker_boost\"]}}]}', '{\"model_id\":\"elevenlabs/eleven-v3/timing\",\"name\":\"elevenlabs/eleven-v3/timing\",\"base_price\":0.1,\"formula\":\"{\\\"total_price\\\": base_price * $ceil($length(text) / 1000)}\",\"description\":\"ElevenLabs Eleven-V3 Timing converts text to natural speech and returns alignment metadata—character/word timestamps in JSON—for precise subtitles, karaoke effects, and lip-sync. Supports voice_id, similarity/stability, and optional Speaker Boost. Priced at $0.10 per 1,000 characters. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"text-to-audio\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/elevenlabs/eleven-v3/timing\",\"request_schema\":{\"properties\":{\"similarity\":{\"default\":1,\"description\":\"High enhancement boosts overall voice clarity and target speaker similarity. Very high values can cause artifacts, so adjusting this setting to find the optimal value is encouraged.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"stability\":{\"default\":0.5,\"description\":\"Voice stability (0-1) Default value: 0.5\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"text\":{\"default\":\"Welcome to our advanced text-to-speech system! Experience high-quality voice synthesis with natural pronunciation and clear articulation.\",\"description\":\"Text to convert to speech. Every character is 1 token. Maximum 10000 characters. Use <#x#> between words to control pause duration (0.01-99.99s).\",\"maxLength\":10000,\"type\":\"string\",\"x-rows\":5,\"x-ui-component\":\"textarea\"},\"use_speaker_boost\":{\"default\":true,\"description\":\"This parameter supports English text normalization, which improves performance in number-reading scenarios.\",\"type\":\"boolean\"},\"voice_id\":{\"default\":\"Alice\",\"description\":\"The voice to use for speech generation\",\"type\":\"string\",\"x-enum\":[\"Aria\",\"Roger\",\"Sarah\",\"Laura\",\"Charlie\",\"George\",\"Callum\",\"River\",\"Liam\",\"Charlotte\",\"Alice\",\"Matilda\",\"Will\",\"Jessica\",\"Eric\",\"Chris\",\"Brian\",\"Daniel\",\"Lily\",\"Bill\"],\"x-placeholder\":\"Please input your custom voice ID\",\"x-ui-component\":\"command\"}},\"required\":[\"text\",\"voice_id\"],\"type\":\"object\",\"x-order-properties\":[\"text\",\"voice_id\",\"similarity\",\"stability\",\"use_speaker_boost\"]}}]}}', '2026-06-09 08:56:06.643', '2026-06-09 08:56:06.643', '2026-06-09 08:56:06.643');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('5624a4ef-8a9a-4e78-ad27-292b8b7407b7', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/instant-character', 'wavespeed-ai/instant-character', 'IMAGE', 0.1, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/instant-character\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"The image URL to generate an image from. Needs to match the dimensions of the mask.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"size\",\"seed\"]}}]}', '{\"model_id\":\"wavespeed-ai/instant-character\",\"name\":\"wavespeed-ai/instant-character\",\"base_price\":0.1,\"formula\":\"\",\"description\":\"Instant Character transforms an uploaded character image and a text prompt into styled, action- and mood-driven character renders. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/instant-character\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"The image URL to generate an image from. Needs to match the dimensions of the mask.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"size\",\"seed\"]}}]}}', '2026-06-09 08:56:07.622', '2026-06-09 08:56:07.622', '2026-06-09 08:56:07.622');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('56afe960-3264-4886-bc22-496ef28ac84c', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/fairy-me', 'video-effects/fairy-me', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/fairy-me\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Only supports single-person female photos; 3. Better results when the subject is standing, holding no props, and the full front body is visible; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/fairy-me\",\"name\":\"video-effects/fairy-me\",\"base_price\":0.2,\"formula\":\"\",\"description\":\"Fairy Me turns photos into enchanting Image-to-Video fairy clips with magical, ethereal effects for motion portraits. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/fairy-me\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Only supports single-person female photos; 3. Better results when the subject is standing, holding no props, and the full front body is visible; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.052', '2026-06-09 08:56:07.052', '2026-06-09 08:56:07.052');
