":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/pruna-ai/p-video/image-to-video\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"Video duration in seconds.\",\"maximum\":20,\"minimum\":1,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"image\":{\"description\":\"Input image URL for image-to-video generation.\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"prompt\":{\"description\":\"The positive prompt for generation.\",\"type\":\"string\",\"x-rows\":4,\"x-ui-component\":\"textarea\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Output video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"save_audio\":{\"default\":true,\"description\":\"Save the video with audio.\",\"type\":\"boolean\"},\"seed\":{\"default\":-1,\"description\":\"Random seed. -1 means random.\",\"type\":\"integer\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"duration\",\"resolution\",\"seed\",\"save_audio\"]}}]}}', '2026-06-09 08:56:05.526', '2026-06-09 08:56:05.526', '2026-06-09 08:56:05.526');
