:\"uploader\"},\"prompt\":{\"description\":\"Describe the scene, action, camera movement, and mood for the video.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The output video resolution.\",\"enum\":[\"480p\",\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"last_image\",\"aspect_ratio\",\"resolution\",\"duration\",\"enable_web_search\",\"generate_audio\"]}}]}}', '2026-06-09 08:56:05.413', '2026-06-09 08:56:05.413', '2026-06-09 08:56:05.413');
