INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('5f88eb22-5b8f-449d-a6a0-b5895902e5f0', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/walk-forward', 'video-effects/walk-forward', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/walk-forward\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single person photos, two-person photos, or group photos; 3. Best results when the main subject is a single person showing a full frontal body view; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/walk-forward\",\"name\":\"video-effects/walk-forward\",\"base_price\":0.2,\"formula\":\"\",\"description\":\"Turn photos into forward-walking videos with the Walk Forward image-to-video effect that adds natural forward motion to still images. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/walk-forward\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single person photos, two-person photos, or group photos; 3. Best results when the main subject is a single person showing a full frontal body view; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.134', '2026-06-09 08:56:07.134', '2026-06-09 08:56:07.134');
