"minimum\":0.5,\"step\":0.1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"temperature\":{\"default\":1,\"description\":\"The temperature to use for the generation. A higher value means more randomness in the output.\",\"maximum\":1.5,\"minimum\":0.7,\"step\":0.1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"text\":{\"description\":\"Text to synthesize into speech. Maximum input of 2,000 characters.\",\"maxLength\":2000,\"title\":\"Text\",\"type\":\"string\",\"x-rows\":8,\"x-ui-component\":\"textarea\"},\"voice_id\":{\"default\":\"Dennis\",\"description\":\"The voice to use for speech generation.\",\"enum\":[\"Alex\",\"Ashley\",\"Craig\",\"Deborah\",\"Dennis\",\"Edward\",\"Elizabeth\",\"Hades\",\"Julia\",\"Pixie\",\"Mark\",\"Olivia\",\"Priya\",\"Ronald\",\"Sarah\",\"Shaun\",\"Theodore\",\"Timothy\",\"Wendy\",\"Dominus\",\"Hana\",\"Clive\",\"Carter\",\"Blake\",\"Luna\",\"Yichen\",\"Xiaoyin\",\"Xinyi\",\"Jing\",\"Erik\",\"Katrien\",\"Lennart\",\"Lore\",\"Alain\",\"Hélène\",\"Mathieu\",\"Étienne\",\"Johanna\",\"Josef\",\"Gianni\",\"Orietta\",\"Asuka\",\"Satoshi\",\"Hyunwoo\",\"Minji\",\"Seojun\",\"Yoona\",\"Szymon\",\"Wojciech\",\"Heitor\",\"Maitê\",\"Diego\",\"Lupita\",\"Miguel\",\"Rafael\",\"Svetlana\",\"Elena\",\"Dmitry\",\"Nikolai\",\"Riya\",\"Manoj\",\"Yael\",\"Oren\",\"Nour\",\"Omar\"],\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"text\"],\"type\":\"object\",\"x-order-properties\":[\"text\",\"voice_id\",\"speaking_rate\",\"temperature\",\"output_format\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:06.135', '2026-06-09 08:56:06.135', '2026-06-09 08:56:06.135');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('604a18ce-a6f4-4bf1-a340-c23106260436', NULL, 'cmq0hadjp0000si8dckyresaj', 'vidu/q2-turbo/extend-video', 'vidu/q2-turbo/extend-video', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/vidu/q2-turbo/extend-video\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"Extended duration.\",\"maximum\":7,\"minimum\":1,\"step\":1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"image\":{\"description\":\"The model will use the image passed in this parameter as the final frame to extend the video.The aspect ratio of the images must be less than 1:4 or 4:1\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated media.\",\"enum\":[\"540p\",\"720p\",\"1080p\"],\"type\":\"string\"},\"video\":{\"description\":\"The video\'s duration cannot be less than 4 seconds and cannot exceed 1 minute.\",\"type\":\"string\"}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"image\",\"prompt\",\"duration\",\"resolution\"]}}]}', '{\"model_id\":\"vidu/q2-turbo/extend-video\",\"name\":\"vidu/q2-turbo/extend-video\",\"base_price\":0.2,\"formula\":\"{\\\"total_price\\\":($d:=$number(duration);resolution=\\\"540p\\\"?30000+($d-1)*10000:resolution=\\\"720p\\\"?($d=1?40000:($d-1)*50000):resolution=\\\"1080p\\\"?175000+($d-1)*50000:0)}\",\"description\":\"Vidu Q2 Turbo Extend Video seamlessly extends existing videos by 1-7 seconds with consistent motion and scene continuity.\",\"type\":\"video-extend\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/vidu/q2-turbo/extend-video\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"Extended duration.\",\"maximum\":7,\"minimum\":1,\"step\":1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"image\":{\"description\":\"The model will use the image passed in this parameter as the final frame to extend the video.The aspect ratio of the images must be less than 1:4 or 4:1\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated media.\",\"enum\":[\"540p\",\"720p\",\"1080p\"],\"type\":\"string\"},\"video\":{\"description\":\"The video\'s duration cannot be less than 4 seconds and cannot exceed 1 minute.\",\"type\":\"string\"}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"image\",\"prompt\",\"duration\",\"resolution\"]}}]}}', '2026-06-09 08:56:07.232', '2026-06-09 08:56:07.232', '2026-06-09 08:56:07.232');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('60d01101-7751-4681-a9b5-0bed3494a6d6', NULL, 'cmq0hadjp0000si8dckyresaj', 'google/nano-banana-pro/edit-ultra', 'google/nano-banana-pro/edit-ultra', 'IMAGE', 0.15, NULL, NULL, 9400, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/nano-banana-pro/edit-ultra\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"3:2\",\"2:3\",\"3:4\",\"4:3\",\"4:5\",\"5:4\",\"9:16\",\"16:9\",\"21:9\"],\"type\":\"string\",\"x-placeholder\":\"Select aspect ratio\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API. Due to variability in Google’s underlying compute resources, inference times can fluctuate significantly. As a result, synchronous requests may hit timeouts.\",\"disabled\":true,\"type\":\"boolean\"},\"images\":{\"description\":\"List of URLs of input images for editing. The maximum number of images is 14.\",\"items\":{\"type\":\"string\"},\"maxItems\":14,\"minItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"output_format\":{\"default\":\"png\",\"description\":\"The format of the output image.\",\"enum\":[\"png\",\"jpeg\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"4k\",\"description\":\"The resolution of the output image.\",\"enum\":[\"4k\",\"8k\"],\"type\":\"string\"}},\"required\":[\"prompt\",\"images\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"aspect_ratio\",\"resolution\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"google/nano-banana-pro/edit-ultra\",\"name\":\"google/nano-banana-pro/edit-ultra\",\"base_price\":0.15,\"formula\":\"{\\\"total_price\\\": base_price * (resolution = \\\"4k\\\" ? 1 : (resolution = \\\"8k\\\" ? 1.2 : 1))}\",\"description\":\"Google Nano Banana Pro (Gemini 3.0 Pro Image) Edit enables image editing with highres output. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":9400,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/nano-banana-pro/edit-ultra\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"3:2\",\"2:3\",\"3:4\",\"4:3\",\"4:5\",\"5:4\",\"9:16\",\"16:9\",\"21:9\"],\"type\":\"string\",\"x-placeholder\":\"Select aspect ratio\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API. Due to variability in Google’s underlying compute resources, inference times can fluctuate significantly. As a result, synchronous requests may hit timeouts.\",\"disabled\":true,\"type\":\"boolean\"},\"images\":{\"description\":\"List of URLs of input images for editing. The maximum number of images is 14.\",\"items\":{\"type\":\"string\"},\"maxItems\":14,\"minItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"output_format\":{\"default\":\"png\",\"description\":\"The format of the output image.\",\"enum\":[\"png\",\"jpeg\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"4k\",\"description\":\"The resolution of the output image.\",\"enum\":[\"4k\",\"8k\"],\"type\":\"string\"}},\"required\":[\"prompt\",\"images\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"aspect_ratio\",\"resolution\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:05.588', '2026-06-09 08:56:05.588', '2026-06-09 08:56:05.588');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('61d739d6-9488-4226-b701-20c921877d1a', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/longcat-avatar-1.5', 'wavespeed-ai/longcat-avatar-1.5', 'DIGITAL-HUMAN', 0.2, NULL, NULL, 4010, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/longcat-avatar-1.5\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"The audio for generating the output.\",\"type\":\"string\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"480p\",\"description\":\"The resolution of the output video.\",\"enum\":[\"480p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"audio\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"audio\",\"prompt\",\"resolution\",\"seed\"]}}]}', '{\"model_id\":\"wavespeed-ai/longcat-avatar-1.5\",\"name\":\"wavespeed-ai/longcat-avatar-1.5\",\"base_price\":0.2,\"formula\":\"{\\\"total_price\\\": $max([5, $min([$number(get_duration_v3(audio)), 64])]) / 5 * base_price * (resolution = \\\"720p\\\" ? 2 : 1)}\",\"description\":\"LongCat Avatar 1.5 is the upgraded version of LongCat Avatar with sharper lip sync and faster generation. Converts one photo + audio into audio-driven talking or singing avatar videos (Image-to-Video), capped at 64 seconds per clip. Ready-to-use REST API, no coldstarts, affordable pricing.\",\"type\":\"digital-human\",\"sort_order\":4010,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/longcat-avatar-1.5\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"The audio for generating the output.\",\"type\":\"string\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"480p\",\"description\":\"The resolution of the output video.\",\"enum\":[\"480p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"audio\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"audio\",\"prompt\",\"resolution\",\"seed\"]}}]}}', '2026-06-09 08:56:05.787', '2026-06-09 08:56:05.787', '2026-06-09 08:56:05.787');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('61f5509e-5cc4-4a83-94fe-0bc22b377c7c', NULL, 'cmq0hadjp0000si8dckyresaj', 'minimax/hailuo-02/t2v-pro', 'minimax/hailuo-02/t2v-pro', 'VIDEO', 0.48, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/hailuo-02/t2v-pro\",\"request_schema\":{\"properties\":{\"enable_prompt_expansion\":{\"default\":true,\"description\":\"The model automatically optimizes incoming prompts to enhance output quality. This also activates the safety checker, which ensures content safety by detecting and filtering potential risks.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"maxLength\":2000,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"enable_prompt_expansion\"]}}]}', '{\"model_id\":\"minimax/hailuo-02/t2v-pro\",\"name\":\"minimax/hailuo-02/t2v-pro\",\"base_price\":0.48,\"formula\":\"\",\"description\":\"Hailuo 02 T2V-Pro is a text-to-video model fine-tuned for ultra-clear 1080P video and responsive handling of physics-driven scenes. Ready-to-use REST API, no coldstarts, best performance, affordable pricing.\",\"type\":\"text-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/hailuo-02/t2v-pro\",\"request_schema\":{\"properties\":{\"enable_prompt_expansion\":{\"default\":true,\"description\":\"The model automatically optimizes incoming prompts to enhance output quality. This also activates the safety checker, which ensures content safety by detecting and filtering potential risks.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"maxLength\":2000,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"enable_prompt_expansion\"]}}]}}', '2026-06-09 08:56:06.779', '2026-06-09 08:56:06.779', '2026-06-09 08:56:06.779');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('6262cf03-7fe8-4192-830b-fb5e02249ff5', NULL, 'cmq0hadjp0000si8dckyresaj', 'pika/v2.2-pikaframes', 'pika/v2.2-pikaframes', 'IMAGE', 0.4, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/pika/v2.2-pikaframes\",\"request_schema\":{\"properties\":{\"images\":{\"description\":\"URL of ref images to use while generating the video.\",\"items\":{\"type\":\"string\"},\"maxItems\":5,\"minItems\":2,\"type\":\"array\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated video.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"transitions\":{\"description\":\"Configuration for each transition. Length must be len(image_urls) - 1. Total duration of all transitions must not exceed 25 seconds. If not provided, uses default 5-second transitions with the global prompt\",\"items\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"Duration of this transition in seconds\",\"maximum\":25,\"minimum\":5,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"prompt\":{\"description\":\"Specific prompt for this transition. Overrides the global prompt if provided.\",\"type\":\"string\"}},\"type\":\"object\"},\"maxItems\":5,\"type\":\"array\",\"x-ui-component\":\"array\"}},\"required\":[\"images\"],\"type\":\"object\",\"x-order-properties\":[\"images\",\"prompt\",\"transitions\",\"resolution\",\"duration\",\"seed\"]}}]}', '{\"model_id\":\"pika/v2.2-pikaframes\",\"name\":\"pika/v2.2-pikaframes\",\"base_price\":0.4,\"formula\":\"{\\\"total_price\\\": base_price * ($exists(transitions) and $count(transitions) > 0 ? $max([$sum(transitions.duration), 5]) : 5) / 5 * (resolution = \\\"1080p\\\" ? 0.75 : 0.5)}\",\"description\":\"Create precise keyframe-to-video sequences with Pika V2.2 Pikaframes. Upload up to 5 keyframes, set per-transition prompts and durations, and interpolate smooth motion for storyboards, camera moves, and style-consistent animation. Supports total runtimes up to 25 seconds. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/pika/v2.2-pikaframes\",\"request_schema\":{\"properties\":{\"images\":{\"description\":\"URL of ref images to use while generating the video.\",\"items\":{\"type\":\"string\"},\"maxItems\":5,\"minItems\":2,\"type\":\"array\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated video.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"transitions\":{\"description\":\"Configuration for each transition. Length must be len(image_urls) - 1. Total duration of all transitions must not exceed 25 seconds. If not provided, uses default 5-second transitions with the global prompt\",\"items\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"Duration of this transition in seconds\",\"maximum\":25,\"minimum\":5,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"prompt\":{\"description\":\"Specific prompt for this transition. Overrides the global prompt if provided.\",\"type\":\"string\"}},\"type\":\"object\"},\"maxItems\":5,\"type\":\"array\",\"x-ui-component\":\"array\"}},\"required\":[\"images\"],\"type\":\"object\",\"x-order-properties\":[\"images\",\"prompt\",\"transitions\",\"resolution\",\"duration\",\"seed\"]}}]}}', '2026-06-09 08:56:06.704', '2026-06-09 08:56:06.704', '2026-06-09 08:56:06.704');
