nerate_audio\",\"camera_fixed\",\"seed\"]}}]}', '{\"model_id\":\"bytedance/seedance-v1.5-pro/image-to-video\",\"name\":\"bytedance/seedance-v1.5-pro/image-to-video\",\"base_price\":0.26,\"formula\":\"{\\\"total_price\\\": $number(duration) * $number(base_price) * ( resolution = \\\"720p\\\" ? 1 : resolution = \\\"1080p\\\" ? 2 : 0.461538 ) / 5 * ( generate_audio ? 1 : 0.5 ) }\",\"description\":\"Seedance 1.5 Pro (Image-to-Video) generates cinematic, live-action–leaning clips from a text prompt plus a first-frame image, preserving the image’s subject and composition while adding expressive motion and stable aesthetics. It supports 4–12s duration control (including Smart Duration), adaptive aspect ratio that follows the input image, and reproducible outputs via seeds—ideal for ad creatives and short-drama shots that need a strong visual anchor.\",\"type\":\"image-to-video\",\"sort_order\":7800,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedance-v1.5-pro/image-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"21:9\",\"16:9\",\"4:3\",\"1:1\",\"3:4\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"camera_fixed\":{\"default\":false,\"description\":\"Whether to fix the camera position.\",\"type\":\"boolean\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"maximum\":12,\"minimum\":4,\"step\":1,\"type\":\"integer\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate audio.\",\"type\":\"boolean\"},\"image\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"last_image\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\",\"x-ui-component\":\"uploader\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Video resolution.\",\"enum\":[\"480p\",\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"image\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"last_image\",\"aspect_ratio\",\"duration\",\"resolution\",\"generate_audio\",\"camera_fixed\",\"seed\"]}}]}}', '2026-06-09 08:56:05.640', '2026-06-09 08:56:05.640', '2026-06-09 08:56:05.640');
