hema\":{\"properties\":{\"bgm\":{\"default\":true,\"description\":\"Enable or disable background music for the video.\",\"type\":\"boolean\"},\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Only single-person photos are supported; 3. Better results when the main subject is shown facing forward with upper body or full body visible; 4. Only images with an aspect ratio between 1:2 and 1:1.2 are supported; 5. Images can be provided via URLs or Base64 encode; 6. Supported codecs: PNG, JPEG, JPG, WebP; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\",\"bgm\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"bgm\"]}}]}}', '2026-06-09 08:56:07.020', '2026-06-09 08:56:07.020', '2026-06-09 08:56:07.020');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('67b3dbdf-4acd-46cb-b7e0-010928631567', NULL, 'cmq0hadjp0000si8dckyresaj', 'bytedance/seedance-2.0/image-to-video-turbo', 'bytedance/seedance-2.0/image-to-video-turbo', 'VIDEO', 0.7, NULL, NULL, 7500, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedance-2.0/image-to-video-turbo\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"description\":\"The aspect ratio of the generated video. If not specified, adapts to the input image.\",\"enum\":[\"16:9\",\"9:16\",\"4:3\",\"3:4\",\"1:1\",\"21:9\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated video in seconds (4-15s).\",\"maximum\":15,\"minimum\":4,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_web_search\":{\"default\":false,\"description\":\"Enable web search for real-time information.\",\"type\":\"boolean\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate native audio synchronized with the output video. Defaults to true.\",\"type\":\"boolean\"},\"image\":{\"description\":\"Start image URL to guide the video generation.\",\"type\":\"string\"},\"last_image\":{\"description\":\"Last frame image URL for video continuation.\",\"type\":\"string\",\"x-ui-component\":\"uploader\"},\"prompt\":{\"description\":\"Describe the scene, action, camera movement, and mood for the video.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The output video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"last_image\",\"aspect_ratio\",\"resolution\",\"duration\",\"enable_web_search\",\"generate_audio\"]}}]}', '{\"model_id\":\"bytedance/seedance-2.0/image-to-video-turbo\",\"name\":\"bytedance/seedance-2.0/image-to-video-turbo\",\"base_price\":0.7,\"formula\":\"{\\\"total_price\\\": (resolution = \\\"1080p\\\" ? 750000 : 700000) * $number(duration) / 5}\",\"description\":\"Seedance 2.0 (Image-to-Video Turbo) generates cinematic 720p/1080p videos from reference images and text prompts —delivering high-resolution output at near-480p speed with native audio-visual synchronization, director-level control, and exceptional motion stability. Built on ByteDance Seed\'s unified multimodal architecture.\",\"type\":\"image-to-video\",\"sort_order\":7500,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedance-2.0/image-to-video-turbo\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"description\":\"The aspect ratio of the generated video. If not specified, adapts to the input image.\",\"enum\":[\"16:9\",\"9:16\",\"4:3\",\"3:4\",\"1:1\",\"21:9\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated video in seconds (4-15s).\",\"maximum\":15,\"minimum\":4,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_web_search\":{\"default\":false,\"description\":\"Enable web search for real-time information.\",\"type\":\"boolean\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate native audio synchronized with the output video. Defaults to true.\",\"type\":\"boolean\"},\"image\":{\"description\":\"Start image URL to guide the video generation.\",\"type\":\"string\"},\"last_image\":{\"description\":\"Last frame image URL for video continuation.\",\"type\":\"string\",\"x-ui-component\":\"uploader\"},\"prompt\":{\"description\":\"Describe the scene, action, camera movement, and mood for the video.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The output video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"last_image\",\"aspect_ratio\",\"resolution\",\"duration\",\"enable_web_search\",\"generate_audio\"]}}]}}', '2026-06-09 08:56:05.647', '2026-06-09 08:56:05.647', '2026-06-09 08:56:05.647');
