000:(duration=6)?90000:(duration=7)?100000:(duration=8)?110000:0):((resolution=\\\"1080p\\\")?((duration=1)?80000:(duration=2)?100000:(duration=3)?120000:(duration=4)?140000:(duration=5)?160000:(duration=6)?180000:(duration=7)?200000:(duration=8)?220000:0):80000)}\",\"description\":\"Vidu Q2 Pro Fast Image to Video generates high-quality videos from a single image with faster generation speed. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/vidu/q2-pro/image-to-video-fast\",\"request_schema\":{\"properties\":{\"bgm\":{\"default\":true,\"description\":\"Whether to add background music to the output.\",\"type\":\"boolean\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated video in seconds.\",\"maximum\":8,\"minimum\":1,\"step\":1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"image\":{\"description\":\"The input image for generating the video.\",\"type\":\"string\"},\"movement_amplitude\":{\"default\":\"auto\",\"description\":\"The movement amplitude of objects in the frame.\",\"enum\":[\"auto\",\"small\",\"medium\",\"large\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"duration\",\"resolution\",\"bgm\",\"movement_amplitude\",\"seed\"]}}]}}', '2026-06-09 08:56:07.015', '2026-06-09 08:56:07.015', '2026-06-09 08:56:07.015');
