ription\":\"The positive prompt for the generation.\",\"minLength\":1,\"type\":\"string\"},\"quality\":{\"default\":\"medium\",\"description\":\"The quality of the generated image.\",\"enum\":[\"low\",\"medium\",\"high\"],\"type\":\"string\"},\"size\":{\"default\":\"auto\",\"description\":\"The size of the generated media in pixels (width*height).\",\"enum\":[\"auto\",\"1024*1024\",\"1024*1536\",\"1536*1024\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"size\",\"background\",\"quality\",\"input_fidelity\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"openai/gpt-image-1.5/edit\",\"name\":\"openai/gpt-image-1.5/edit\",\"base_price\":0.1,\"formula\":\"{\\\"total_price\\\": (quality = \\\"low\\\") ? ((size = \\\"1024*1024\\\") ? 70000 : ((size = \\\"1024*1536\\\" or size = \\\"1536*1024\\\") ? 70000 : 70000)) : (quality = \\\"medium\\\") ? ((size = \\\"1024*1024\\\") ? 100000 : ((size = \\\"1024*1536\\\" or size = \\\"1536*1024\\\") ? 120000 : 120000)) : ((size = \\\"1024*1024\\\") ? 200000 : ((size = \\\"1024*1536\\\" or size = \\\"1536*1024\\\") ? 300000 : 300000))}\",\"description\":\"GPT Image 1.5 Edit is OpenAI’s multimodal image editor for precise, natural-language edits. Add/remove objects, inpaint/outpaint, swap backgrounds, retouch faces, adjust colors/lighting, edit text/graphics, crop/resize, and apply hex color control. Supports optional masks and reference images for style/brand consistency. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/openai/gpt-image-1.5/edit\",\"request_schema\":{\"properties\":{\"background\":{\"default\":\"opaque\",\"description\":\"Background for the generated image\",\"enum\":[\"auto\",\"transparent\",\"opaque\"],\"title\":\"Background\",\"type\":\"string\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"images\":{\"description\":\"The images to edit.\",\"items\":{\"type\":\"string\"},\"maxItems\":10,\"minItems\":1,\"type\":\"array\"},\"input_fidelity\":{\"default\":\"high\",\"description\":\"input fidelity, which allows you to better preserve details from the input images in the output. This is especially useful when using images that contain elements like faces or logos that require accurate preservation in the generated image.\",\"enum\":[\"low\",\"high\"],\"type\":\"string\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"minLength\":1,\"type\":\"string\"},\"quality\":{\"default\":\"medium\",\"description\":\"The quality of the generated image.\",\"enum\":[\"low\",\"medium\",\"high\"],\"type\":\"string\"},\"size\":{\"default\":\"auto\",\"description\":\"The size of the generated media in pixels (width*height).\",\"enum\":[\"auto\",\"1024*1024\",\"1024*1536\",\"1536*1024\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"size\",\"background\",\"quality\",\"input_fidelity\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.745', '2026-06-09 08:56:06.745', '2026-06-09 08:56:06.745');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('6fd62600-d5fe-4b30-a439-18cb76750ddf', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/sam3-video', 'wavespeed-ai/sam3-video', 'VIDEO', 0.05, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/sam3-video\",\"request_schema\":{\"properties\":{\"apply_mask\":{\"default\":true,\"description\":\"Whether to apply mask to video\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"Text prompt for segmentation. Use commas to track multiple objects (e.g., \'person, cloth\').\",\"maxLength\":32,\"type\":\"string\"},\"video\":{\"description\":\"Video URL for segmented\",\"format\":\"uri\",\"type\":\"string\"}},\"required\":[\"video\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"apply_mask\"]}}]}', '{\"model_id\":\"wavespeed-ai/sam3-video\",\"name\":\"wavespeed-ai/sam3-video\",\"base_price\":0.05,\"formula\":\"{\\\"total_price\\\": $max([5, $min([$number(get_duration_v3(video)), 600])]) / 5 * base_price}\",\"description\":\"A unified foundation model for prompt-based segmentation in video\",\"type\":\"video-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/sam3-video\",\"request_schema\":{\"properties\":{\"apply_mask\":{\"default\":true,\"description\":\"Whether to apply mask to video\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"Text prompt for segmentation. Use commas to track multiple objects (e.g., \'person, cloth\').\",\"maxLength\":32,\"type\":\"string\"},\"video\":{\"description\":\"Video URL for segmented\",\"format\":\"uri\",\"type\":\"string\"}},\"required\":[\"video\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"apply_mask\"]}}]}}', '2026-06-09 08:56:06.720', '2026-06-09 08:56:06.720', '2026-06-09 08:56:06.720');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('7006a12e-503b-4490-babf-fca18680394b', NULL, 'cmq0hadjp0000si8dckyresaj', 'elevenlabs/turbo-v2.5', 'elevenlabs/turbo-v2.5', 'IMAGE', 0.05, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/elevenlabs/turbo-v2.5\",\"request_schema\":{\"properties\":{\"similarity\":{\"default\":1,\"description\":\"High enhancement boosts overall voice clarity and target speaker similarity. Very high values can cause artifacts, so adjusting this setting to find the optimal value is encouraged.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"stability\":{\"default\":0.5,\"description\":\"Voice stability (0-1) Default value: 0.5\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"text\":{\"default\":\"Welcome to our advanced text-to-speech system! Experience high-quality voice synthesis with natural pronunciation and clear articulation.\",\"description\":\"Text to convert to speech. Every character is 1 token. Maximum 10000 characters. Use <#x#> between words to control pause duration (0.01-99.99s).\",\"maxLength\":10000,\"minLength\":1,\"type\":\"string\",\"x-rows\":5,\"x-ui-component\":\"textarea\"},\"use_speaker_boost\":{\"default\":true,\"description\":\"This parameter supports English text normalization, which improves performance in number-reading scenarios.\",\"type\":\"boolean\"},\"voice_id\":{\"default\":\"Alice\",\"description\":\"The voice to use for speech generation\",\"minLength\":1,\"type\":\"string\",\"x-enum\":[\"Aria\",\"Roger\",\"Sarah\",\"Laura\",\"Charlie\",\"George\",\"Callum\",\"River\",\"Liam\",\"Charlotte\",\"Alice\",\"Matilda\",\"Will\",\"Jessica\",\"Eric\",\"Chris\",\"Brian\",\"Daniel\",\"Lily\",\"Bill\"],\"x-placeholder\":\"Please input your custom voice ID\",\"x-ui-component\":\"command\"}},\"required\":[\"text\",\"voice_id\"],\"type\":\"object\",\"x-order-properties\":[\"text\",\"voice_id\",\"similarity\",\"stability\",\"use_speaker_boost\"]}}]}', '{\"model_id\":\"elevenlabs/turbo-v2.5\",\"name\":\"elevenlabs/turbo-v2.5\",\"base_price\":0.05,\"formula\":\"{\\\"total_price\\\": base_price * $ceil($length(text) / 1000)}\",\"description\":\"ElevenLabs Turbo V2.5 is a text-to-speech model available via WaveSpeedAI, billed at $0.05 per 1000 characters for TTS requests. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-audio\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/elevenlabs/turbo-v2.5\",\"request_schema\":{\"properties\":{\"similarity\":{\"default\":1,\"description\":\"High enhancement boosts overall voice clarity and target speaker similarity. Very high values can cause artifacts, so adjusting this setting to find the optimal value is encouraged.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"stability\":{\"default\":0.5,\"description\":\"Voice stability (0-1) Default value: 0.5\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"text\":{\"default\":\"Welcome to our advanced text-to-speech system! Experience high-quality voice synthesis with natural pronunciation and clear articulation.\",\"description\":\"Text to convert to speech. Every character is 1 token. Maximum 10000 characters. Use <#x#> between words to control pause duration (0.01-99.99s).\",\"maxLength\":10000,\"minLength\":1,\"type\":\"string\",\"x-rows\":5,\"x-ui-component\":\"textarea\"},\"use_speaker_boost\":{\"default\":true,\"description\":\"This parameter supports English text normalization, which improves performance in number-reading scenarios.\",\"type\":\"boolean\"},\"voice_id\":{\"default\":\"Alice\",\"description\":\"The voice to use for speech generation\",\"minLength\":1,\"type\":\"string\",\"x-enum\":[\"Aria\",\"Roger\",\"Sarah\",\"Laura\",\"Charlie\",\"George\",\"Callum\",\"River\",\"Liam\",\"Charlotte\",\"Alice\",\"Matilda\",\"Will\",\"Jessica\",\"Eric\",\"Chris\",\"Brian\",\"Daniel\",\"Lily\",\"Bill\"],\"x-placeholder\":\"Please input your custom voice ID\",\"x-ui-component\":\"command\"}},\"required\":[\"text\",\"voice_id\"],\"type\":\"object\",\"x-order-properties\":[\"text\",\"voice_id\",\"similarity\",\"stability\",\"use_speaker_boost\"]}}]}}', '2026-06-09 08:56:07.118', '2026-06-09 08:56:07.118', '2026-06-09 08:56:07.118');
