ation) / 5 * ((resolution = \\\"720p\\\") ? 2 : (resolution = \\\"1080p\\\") ?  3 : 1)}\",\"description\":\"Alibaba WAN 2.5 Video-Extend turns short clips into longer videos with preserved or generated synchronized audio for continuity. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-extend\",\"sort_order\":5550,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.5/video-extend\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"Audio URL to guide generation (optional).\",\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[3,4,5,6,7,8,9,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"If set to true, the prompt optimizer will be enabled.\",\"type\":\"boolean\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated media.\",\"enum\":[\"480p\",\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"video\":{\"description\":\"The video for generating the output.\",\"type\":\"string\"}},\"required\":[\"video\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"audio\",\"negative_prompt\",\"resolution\",\"duration\",\"enable_prompt_expansion\",\"seed\"]}}]}}', '2026-06-09 08:56:05.714', '2026-06-09 08:56:05.714', '2026-06-09 08:56:05.714');
