d.ai\",\"api_path\":\"/api/v3/wavespeed-ai/hunyuan-avatar\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"The audio for generating the output.\",\"type\":\"string\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"480p\",\"description\":\"The resolution of the output video.\",\"enum\":[\"480p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"audio\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"audio\",\"prompt\",\"resolution\",\"seed\"]}}]}}', '2026-06-09 08:56:06.596', '2026-06-09 08:56:06.596', '2026-06-09 08:56:06.596');
