A-Large\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"video\":{\"description\":\"The URL of the input video to estimate depth for.\",\"format\":\"uri\",\"type\":\"string\"}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"model\"]}}]}}', '2026-06-09 08:56:07.150', '2026-06-09 08:56:07.150', '2026-06-09 08:56:07.150');
