INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('74e5d32e-a76d-475a-ae69-f2b6e5fd70d7', NULL, 'cmq0hadjp0000si8dckyresaj', 'bytedance/seedance-2.0-fast/text-to-video', 'bytedance/seedance-2.0-fast/text-to-video', 'VIDEO', 0.5, NULL, NULL, 9700, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedance-2.0-fast/text-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated video.\",\"enum\":[\"16:9\",\"9:16\",\"4:3\",\"3:4\",\"1:1\",\"21:9\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated video in seconds (4-15s).\",\"maximum\":15,\"minimum\":4,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_web_search\":{\"default\":false,\"description\":\"Enable web search for real-time information.\",\"type\":\"boolean\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate native audio synchronized with the output video. Defaults to true.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"Describe the scene, action, camera movement, and mood for the video.\",\"type\":\"string\"},\"reference_audios\":{\"description\":\"Reference audio URLs (total length must not exceed 15 seconds).\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"audio/*\"}},\"reference_images\":{\"description\":\"Reference image URLs to guide visual style, characters, or scene composition.\",\"items\":{\"type\":\"string\"},\"maxItems\":9,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"reference_videos\":{\"description\":\"Reference video URLs (total length must not exceed 15 seconds).\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"video/*\"}},\"resolution\":{\"default\":\"720p\",\"description\":\"The output video resolution.\",\"enum\":[\"480p\",\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"reference_images\",\"reference_videos\",\"reference_audios\",\"aspect_ratio\",\"resolution\",\"duration\",\"enable_web_search\",\"generate_audio\"]}}]}', '{\"model_id\":\"bytedance/seedance-2.0-fast/text-to-video\",\"name\":\"bytedance/seedance-2.0-fast/text-to-video\",\"base_price\":0.5,\"formula\":\"{\\\"total_price\\\": $count(reference_videos) > 0 ? 65000 * (resolution = \\\"1080p\\\" ? 5 : (resolution = \\\"720p\\\" ? 2 : 1)) * ($max([2, $ceil($min([$number(get_duration_v3(reference_videos)), 15]))]) + (duration ? $number(duration) : $max([4, $min([15, $ceil($number(get_duration_v3(reference_videos)))])]))) : 500000 * (resolution = \\\"1080p\\\" ? 5 : (resolution = \\\"720p\\\" ? 2 : 1)) * $number(duration) / 5}\",\"description\":\"Seedance 2.0 Fast (Text-to-Video) generates cinematic videos from text prompts with native audio-visual synchronization, director-level camera and lighting control, and exceptional motion stability — optimized for faster generation. Built on ByteDance Seed\'s unified multimodal architecture. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"text-to-video\",\"sort_order\":9700,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedance-2.0-fast/text-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated video.\",\"enum\":[\"16:9\",\"9:16\",\"4:3\",\"3:4\",\"1:1\",\"21:9\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated video in seconds (4-15s).\",\"maximum\":15,\"minimum\":4,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_web_search\":{\"default\":false,\"description\":\"Enable web search for real-time information.\",\"type\":\"boolean\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate native audio synchronized with the output video. Defaults to true.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"Describe the scene, action, camera movement, and mood for the video.\",\"type\":\"string\"},\"reference_audios\":{\"description\":\"Reference audio URLs (total length must not exceed 15 seconds).\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"audio/*\"}},\"reference_images\":{\"description\":\"Reference image URLs to guide visual style, characters, or scene composition.\",\"items\":{\"type\":\"string\"},\"maxItems\":9,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"reference_videos\":{\"description\":\"Reference video URLs (total length must not exceed 15 seconds).\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"video/*\"}},\"resolution\":{\"default\":\"720p\",\"description\":\"The output video resolution.\",\"enum\":[\"480p\",\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"reference_images\",\"reference_videos\",\"reference_audios\",\"aspect_ratio\",\"resolution\",\"duration\",\"enable_web_search\",\"generate_audio\"]}}]}}', '2026-06-09 08:56:05.580', '2026-06-09 08:56:05.580', '2026-06-09 08:56:05.580');
