INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('761d794e-e716-4a87-9b4a-4a9ad43f7acc', NULL, 'cmq0hadjp0000si8dckyresaj', 'skywork-ai/skyreels-v4/reference-to-video', 'skywork-ai/skyreels-v4/reference-to-video', 'VIDEO', 0.1, NULL, NULL, 10102, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/skywork-ai/skyreels-v4/reference-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"Aspect ratio of the generated video.\",\"enum\":[\"16:9\",\"9:16\",\"1:1\"],\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"Duration of the generated video in seconds.\",\"maximum\":15,\"minimum\":3,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"images\":{\"description\":\"Reference image URLs. Upload up to 3 images.\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"mode\":{\"default\":\"std\",\"description\":\"Quality/performance mode. Fast mode currently requires sound to be false.\",\"enum\":[\"std\",\"fast\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The prompt describing the generated video. Reference tags are added automatically when missing.\",\"type\":\"string\",\"x-rows\":4,\"x-ui-component\":\"textarea\"},\"ref_videos\":{\"description\":\"Optional reference video URL. Upload at most 1 video.\",\"items\":{\"type\":\"string\"},\"maxItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"video/*\"}},\"resolution\":{\"default\":\"1080p\",\"description\":\"Output video resolution.\",\"enum\":[\"480p\",\"720p\",\"1080p\"],\"type\":\"string\"},\"sound\":{\"default\":false,\"description\":\"Whether to generate sound effects with the video.\",\"type\":\"boolean\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"ref_videos\",\"aspect_ratio\",\"duration\",\"resolution\",\"sound\",\"mode\"]}}]}', '{\"model_id\":\"skywork-ai/skyreels-v4/reference-to-video\",\"name\":\"skywork-ai/skyreels-v4/reference-to-video\",\"base_price\":0.1,\"formula\":\"{\\\"total_price\\\": base_price * $number(duration) * (($exists(ref_videos) and $count(ref_videos) > 0) ? ((mode = \\\"fast\\\") ? ((resolution = \\\"1080p\\\") ? 5 : (resolution = \\\"720p\\\") ? 2 : 1.5) : ((resolution = \\\"1080p\\\") ? 6.25 : (resolution = \\\"720p\\\") ? 2.5 : 1.8)) : ((mode = \\\"fast\\\") ? ((resolution = \\\"1080p\\\") ? 2.75 : (resolution = \\\"720p\\\") ? 1.1 : 0.8) : ((resolution = \\\"1080p\\\") ? 3.5 : (resolution = \\\"720p\\\") ? 1.4 : 1.1)))}\",\"description\":\"SkyReels V4 Reference to Video generates videos from reference images or a reference video and a text prompt using the SkyReels V4 omni-video workflow.\",\"type\":\"image-to-video\",\"sort_order\":10102,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/skywork-ai/skyreels-v4/reference-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"Aspect ratio of the generated video.\",\"enum\":[\"16:9\",\"9:16\",\"1:1\"],\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"Duration of the generated video in seconds.\",\"maximum\":15,\"minimum\":3,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"images\":{\"description\":\"Reference image URLs. Upload up to 3 images.\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"mode\":{\"default\":\"std\",\"description\":\"Quality/performance mode. Fast mode currently requires sound to be false.\",\"enum\":[\"std\",\"fast\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The prompt describing the generated video. Reference tags are added automatically when missing.\",\"type\":\"string\",\"x-rows\":4,\"x-ui-component\":\"textarea\"},\"ref_videos\":{\"description\":\"Optional reference video URL. Upload at most 1 video.\",\"items\":{\"type\":\"string\"},\"maxItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\",\"x-ui-component-props\":{\"accept\":\"video/*\"}},\"resolution\":{\"default\":\"1080p\",\"description\":\"Output video resolution.\",\"enum\":[\"480p\",\"720p\",\"1080p\"],\"type\":\"string\"},\"sound\":{\"default\":false,\"description\":\"Whether to generate sound effects with the video.\",\"type\":\"boolean\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"ref_videos\",\"aspect_ratio\",\"duration\",\"resolution\",\"sound\",\"mode\"]}}]}}', '2026-06-09 08:56:05.351', '2026-06-09 08:56:05.351', '2026-06-09 08:56:05.351');
