 for better 3D reconstruction.\",\"type\":\"string\",\"x-accept\":\"image/*\",\"x-ui-component\":\"uploader\"},\"polygon_type\":{\"default\":\"triangle\",\"description\":\"Polygon type. Only takes effect when GenerateType is LowPoly.\",\"enum\":[\"triangle\",\"quadrilateral\"],\"type\":\"string\"},\"right_image\":{\"description\":\"Optional right view image URL for better 3D reconstruction.\",\"type\":\"string\",\"x-accept\":\"image/*\",\"x-ui-component\":\"uploader\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"back_image\",\"left_image\",\"right_image\",\"enable_pbr\",\"polygon_type\",\"face_count\",\"generate_type\"]}}]}}', '2026-06-09 08:56:06.751', '2026-06-09 08:56:06.751', '2026-06-09 08:56:06.751');
