"general\",\"anime\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"style\",\"resolution\",\"duration\",\"aspect_ratio\",\"movement_amplitude\",\"generate_audio\",\"bgm\",\"seed\"]}}]}}', '2026-06-09 08:56:05.637', '2026-06-09 08:56:05.637', '2026-06-09 08:56:05.637');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('7e0eeda2-d401-4d35-8c13-8f9c8faa0e87', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/muscling', 'video-effects/muscling', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/muscling\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports realistic style single person photos; 3. Best results when the person is half body, not showing hands, and the clothing is non high necked; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/muscling\",\"name\":\"video-effects/muscling\",\"base_price\":0.2,\"formula\":\"\",\"description\":\"Turn photos into 3s Image-to-Video muscle-effect clips with realistic anatomy, natural motion, and expressive emotion. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/muscling\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports realistic style single person photos; 3. Best results when the person is half body, not showing hands, and the clothing is non high necked; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.340', '2026-06-09 08:56:07.340', '2026-06-09 08:56:07.340');
