\"properties\":{\"duration\":{\"default\":5,\"description\":\"The duration of the generated video in seconds. Used when video is not provided.\",\"enum\":[5,10,15],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"image\":{\"description\":\"The URL of the input image (required).\",\"type\":\"string\"},\"style\":{\"default\":\"rooftop\",\"description\":\"Parkour style preset.\",\"enum\":[\"rooftop\",\"urban\",\"wall_run\",\"flip\",\"forest\",\"stairs\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"video\":{\"default\":\"\",\"description\":\"Reference parkour video URL. When provided, uses video-to-video animation (720p). When omitted, generates from image.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"video\",\"style\",\"duration\"]}}]}}', '2026-06-09 08:56:06.093', '2026-06-09 08:56:06.093', '2026-06-09 08:56:06.093');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('7e5b48d6-03a6-4efa-aee0-60612b5f2951', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/flux-dev-lora-trainer-turbo', 'wavespeed-ai/flux-dev-lora-trainer-turbo', 'IMAGE', 1.25, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-dev-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"URL to zip archive with images. Try to use at least 4 images in general the more the better.\\n\\n        In addition to images the archive can contain text files with captions. Each text file should have the same name as the image file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing images.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0004,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":16,\"maximum\":64,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":1000,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":10000,\"minimum\":1000,\"step\":10,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"Trigger word to be used in the captions. If None, a trigger word will not be used.\\n        If no captions are provide the trigger_word will be used instead of captions. If captions are the trigger word will not be used.\",\"nullable\":true,\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}', '{\"model_i