pe\":\"string\"}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"aspect_ratio\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"google/nano-banana/edit\",\"name\":\"google/nano-banana/edit\",\"base_price\":0.038,\"formula\":\"\",\"description\":\"Nano-Banana is an advanced image generation and editing model that produces photorealistic or stylized visuals and performs precise inpainting, outpainting, and background replacement. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":4000,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/nano-banana/edit\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"3:2\",\"2:3\",\"3:4\",\"4:3\",\"4:5\",\"5:4\",\"9:16\",\"16:9\",\"21:9\"],\"type\":\"string\",\"x-placeholder\":\"Select aspect ratio\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API. Due to variability in Google’s underlying compute resources, inference times can fluctuate significantly. As a result, synchronous requests may hit timeouts.\",\"disabled\":true,\"type\":\"boolean\"},\"images\":{\"description\":\"List of URLs of input images for editing. The maximum number of images is 10.\",\"items\":{\"type\":\"string\"},\"maxItems\":10,\"minItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"output_format\":{\"default\":\"png\",\"description\":\"The format of the output image.\",\"enum\":[\"png\",\"jpeg\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"aspect_ratio\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:05.793', '2026-06-09 08:56:05.793', '2026-06-09 08:56:05.793');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('7ebdf6d2-b3d0-4560-b161-3a51d976e615', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/squid-game', 'video-effects/squid-game', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/squid-game\",\"request_schema\":{\"properties\":{\"bgm\":{\"default\":true,\"description\":\"Enable or disable background music. Default is true.\",\"type\":\"boolean\"},\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports 1-2 people or pets, real and animated; 3. Best for front-facing subjects with clear photos; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"bgm\"]}}]}', '{\"model_id\":\"video-effects/squid-game\",\"name\":\"video-effects/squid-game\",\"base_price\":0.2,\"formula\":\"\",\"description\":\"Transform photos into Squid Game-themed videos with dynamic effects and immersive atmosphere, turning still images into viral-ready scenes. Ready-to-use REST API, top performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/squid-game\",\"request_schema\":{\"properties\":{\"bgm\":{\"default\":true,\"description\":\"Enable or disable background music. Default is true.\",\"type\":\"boolean\"},\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports 1-2 people or pets, real and animated; 3. Best for front-facing subjects with clear photos; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"bgm\"]}}]}}', '2026-06-09 08:56:07.310', '2026-06-09 08:56:07.310', '2026-06-09 08:56:07.310');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('7ec51fbb-d3a9-499b-96da-c3226c84daac', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/davinci-magihuman/text-to-video', 'wavespeed-ai/davinci-magihuman/text-to-video', 'VIDEO', 0.1, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/davinci-magihuman/text-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated video.\",\"enum\":[\"16:9\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"audio\":{\"description\":\"The audio URL for generating the output. If provided, the model will generate a video synchronized with the audio.\",\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated video in seconds.\",\"enum\":[5,6,7,8,9,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated video.\",\"enum\":[\"256p\",\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"audio\",\"aspect_ratio\",\"resolution\",\"duration\",\"seed\"]}}]}', '{\"model_id\":\"wavespeed-ai/davinci-magihuman/text-to-video\",\"name\":\"wavespeed-ai/davinci-magihuman/text-to-video\",\"base_price\":0.1,\"formula\":\"{\\\"total_price\\\": (resolution = \\\"1080p\\\" ? 200000 : resolution = \\\"720p\\\" ? 150000 : 100000) * $number(duration) / 5}\",\"description\":\"daVinci MagiHuman is a 15B parameter omni video generation model — the new open-source king on par with WAN 2.5. Generates high-quality AI videos from text prompts with optional audio input. Supports digital humans, talking heads, and general video generation.\",\"type\":\"text-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/davinci-magihuman/text-to-video\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"16:9\",\"description\":\"The aspect ratio of the generated video.\",\"enum\":[\"16:9\",\"9:16\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"audio\":{\"description\":\"The audio URL for generating the output. If provided, the model will generate a video synchronized with the audio.\",\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated video in seconds.\",\"enum\":[5,6,7,8,9,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated video.\",\"enum\":[\"256p\",\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"audio\",\"aspect_ratio\",\"resolution\",\"duration\",\"seed\"]}}]}}', '2026-06-09 08:56:07.278', '2026-06-09 08:56:07.278', '2026-06-09 08:56:07.278');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('7efa7e40-a72a-4d76-85ae-18f59d7150fb', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/wan-2.2/image-to-video', 'wavespeed-ai/wan-2.2/image-to-video', 'VIDEO', 0.15, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/wan-2.2/image-to-video\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[5,8],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"last_image\":{\"description\":\"The last image for generating the output.\",\"type\":\"string\",\"x-accept\":\"image/*\",\"x-ui-component\":\"uploader\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"480p\",\"description\":\"The resolution of the generated media.\",\"enum\":[\"480p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"resolution\",\"negative_prompt\",\"last_image\",\"duration\",\"seed\"]}}]}', '{\"model_id\":\"wavespeed-ai/wan-2.2/image-to-video\",\"name\":\"wavespeed-ai/wan-2.2/image-to-video\",\"base_price\":0.15,\"formula\":\"{\\\"total_price\\\": base_price * $number(duration) / 5 * ((resolution = \\\"720p\\\") ? 2 : 1)} \",\"description\":\"Wan 2.2 Image-to-Video turns a single image into smooth, cinematic motion with clean detail—ideal for storyboards, mood shots, and product demos. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/wan-2.2/image-to-video\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[5,8],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"last_image\":{\"description\":\"The last image for generating the output.\",\"type\":\"string\",\"x-accept\":\"image/*\",\"x-ui-component\":\"uploader\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"480p\",\"description\":\"The resolution of the generated media.\",\"enum\":[\"480p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"resolution\",\"negative_prompt\",\"last_image\",\"duration\",\"seed\"]}}]}}', '2026-06-09 08:56:06.547', '2026-06-09 08:56:06.547', '2026-06-09 08:56:06.547');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('7f90ff36-34f4-4367-b73e-a6506c2ebf23', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/hidream-o1-image-dev/text-to-image', 'wavespeed-ai/hidream-o1-image-dev/text-to-image', 'IMAGE', 0.02, NULL, NULL, 2150, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/hidream-o1-image-dev/text-to-image\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"Output image format.\",\"enum\":[\"png\",\"jpeg\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"Text prompt for image generation.\",\"type\":\"string\",\"x-ui-component\":\"textarea\"},\"seed\":{\"type\":\"integer\",\"x-hidden\":true},\"size\":{\"default\":\"2048*2048\",\"description\":\"Specify the width and height pixel values of the generated image.Total pixel value range: [2560*1440, 4096*4096]\",\"maximum\":4096,\"minimum\":256,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"output_format\",\"seed\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"wavespeed-ai/hidream-o1-image-dev/text-to-image\",\"name\":\"wavespeed-ai/hidream-o1-image-dev/text-to-image\",\"base_price\":0.02,\"formula\":\"\",\"description\":\"Kling O3 is Kuaishou\'s advanced AI image generation model with 4K resolution support.\",\"type\":\"text-to-image\",\"sort_order\":2150,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/hidream-o1-image-dev/text-to-image\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"Output image format.\",\"enum\":[\"png\",\"jpeg\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"Text prompt for image generation.\",\"type\":\"string\",\"x-ui-component\":\"textarea\"},\"seed\":{\"type\":\"integer\",\"x-hidden\":true},\"size\":{\"default\":\"2048*2048\",\"description\":\"Specify the width and height pixel values of the generated image.Total pixel value range: [2560*1440, 4096*4096]\",\"maximum\":4096,\"minimum\":256,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"output_format\",\"seed\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:05.964', '2026-06-09 08:56:05.964', '2026-06-09 08:56:05.964');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('7fb5a59f-098b-4127-bc04-376e661c8454', NULL, 'cmq0hadjp0000si8dckyresaj', 'alibaba/wan-2.7/text-to-image', 'alibaba/wan-2.7/text-to-image', 'IMAGE', 0.03, NULL, NULL, 6500, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.7/text-to-image\",\"request_schema\":{\"properties\":{\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated image in pixels (width*height). Range: 512-4096 per dimension. Total pixels must be between 768*768 and 2048*2048. Aspect ratio must be between 1:8 and 8:1.\",\"maximum\":4096,\"minimum\":512,\"type\":\"string\"},\"thinking_mode\":{\"default\":true,\"description\":\"Enable thinking mode for enhanced reasoning and better image quality. Increases generation time.\",\"type\":\"boolean\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"thinking_mode\",\"seed\"]}}]}', '{\"model_id\":\"alibaba/wan-2.7/text-to-image\",\"name\":\"alibaba/wan-2.7/text-to-image\",\"base_price\":0.03,\"formula\":\"{\\\"total_price\\\":base_price * num_images}\",\"description\":\"Alibaba WAN 2.7 Text-to-Image generates high-quality images from text prompts with thinking mode for enhanced image quality. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":6500,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.7/text-to-image\",\"request_schema\":{\"properties\":{\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated image in pixels (width*height). Range: 512-4096 per dimension. Total pixels must be between 768*768 and 2048*2048. Aspect ratio must be between 1:8 and 8:1.\",\"maximum\":4096,\"minimum\":512,\"type\":\"string\"},\"thinking_mode\":{\"default\":true,\"description\":\"Enable thinking mode for enhanced reasoning and better image quality. Increases generation time.\",\"type\":\"boolean\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"thinking_mode\",\"seed\"]}}]}}', '2026-06-09 08:56:05.679', '2026-06-09 08:56:05.679', '2026-06-09 08:56:05.679');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('7fd6ef06-9f67-4d32-89b5-6ba58a6fc50b', NULL, 'cmq0hadjp0000si8dckyresaj', 'kwaivgi/kling-v1-ai-avatar-standard', 'kwaivgi/kling-v1-ai-avatar-standard', 'DIGITAL-HUMAN', 0.25, NULL, NULL, 1800, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/kwaivgi/kling-v1-ai-avatar-standard\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"The audio for generating the output.\",\"type\":\"string\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"}},\"required\":[\"audio\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"audio\",\"prompt\"]}}]}', '{\"model_id\":\"kwaivgi/kling-v1-ai-avatar-standard\",\"name\":\"kwaivgi/kling-v1-ai-avatar-standard\",\"base_price\":0.25,\"formula\":\"{\\\"total_price\\\": $max([5, $min([$number(get_duration_v3(audio)), 600])]) / 5 * base_price}\",\"description\":\"Kling AI Avatar produces stunning AI-generated video avatars for digital identity and content creation, with on-demand video billed at $0.25 per 5 seconds. Ready-to-use REST API, no coldstarts, affordable pricing.\",\"type\":\"digital-human\",\"sort_order\":1800,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/kwaivgi/kling-v1-ai-avatar-standard\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"The audio for generating the output.\",\"type\":\"string\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"}},\"required\":[\"audio\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"audio\",\"prompt\"]}}]}}', '2026-06-09 08:56:06.017', '2026-06-09 08:56:06.017', '2026-06-09 08:56:06.017');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('8007003c-c1f9-42cc-97c1-4e4be276c3ae', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/ltx-2-19b/ic-lora-trainer', 'wavespeed-ai/ltx-2-19b/ic-lora-trainer', 'IMAGE', 0.75, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/ltx-2-19b/ic-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"Upload a zip file containing paired reference and target videos for IC-LoRA training. Reference videos must be named with \'_ref.mp4\' suffix (e.g., \'video1_ref.mp4\' pairs with \'video1.mp4\'). Reference and target videos must have identical resolution and length. Each text file should have the same name as the video file it corresponds to for captions.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing paired videos (target.mp4 + target_ref.mp4).\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0002,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":32,\"maximum\":128,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":500,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":20000,\"minimum\":100,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"The phrase that will trigger the model to generate a video.\",\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}', '{\"model_id\":\"wavespeed-ai/ltx-2-19b/ic-lora-trainer\",\"name\":\"wavespeed-ai/ltx-2-19b/ic-lora-trainer\",\"base_price\":0.75,\"formula\":\"{\\\"total_price\\\":base_price * (steps / 100)}\",\"description\":\"Train custom LTX-2 IC-LoRA (In-Context LoRA) models for video-to-video transformations. Train depth/pose adapters, video restoration, style transfer models. Upload a ZIP file containing paired videos (target.mp4 + target_ref.mp4) to start!\",\"type\":\"training\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/ltx-2-19b/ic-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"Upload a zip file containing paired reference and target videos for IC-LoRA training. Reference videos must be named with \'_ref.mp4\' suffix (e.g., \'video1_ref.mp4\' pairs with \'video1.mp4\'). Reference and target videos must have identical resolution and length. Each text file should have the same name as the video file it corresponds to for captions.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing paired videos (target.mp4 + target_ref.mp4).\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0002,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":32,\"maximum\":128,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":500,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":20000,\"minimum\":100,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"The phrase that will trigger the model to generate a video.\",\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}}', '2026-06-09 08:56:06.873', '2026-06-09 08:56:06.873', '2026-06-09 08:56:06.873');
