:\"integer\",\"x-hidden\":true,\"x-ui-component\":\"slider\"},\"enable_web_search\":{\"default\":false,\"description\":\"Enable web search for real-time information.\",\"type\":\"boolean\"},\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate native audio for the edited output. Defaults to true. When set to false, the input video\'s audio track is preserved on the output instead.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"Describe the edit you want applied to the input video. The prefix \\\"Edit the input video.\\\" is added automatically.\",\"type\":\"string\"},\"reference_audios\":{\"description\":\"Optional reference audio URLs to guide audio generation.\",\"items\":{\"type\":\"string\"},\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"reference_images\":{\"description\":\"Optional reference image URLs to guide the edit (subject identity, style, etc.).\",\"items\":{\"type\":\"string\"},\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Output video resolution.\",\"enum\":[\"480p\",\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"video\":{\"description\":\"URL of the input video to edit. Videos longer than 15s are trimmed to 15s.\",\"type\":\"string\",\"x-ui-component\":\"uploader\"}},\"required\":[\"prompt\",\"video\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"reference_images\",\"reference_audios\",\"aspect_ratio\",\"resolution\",\"duration\",\"enable_web_search\",\"generate_audio\"]}}]}}', '2026-06-09 08:56:05.544', '2026-06-09 08:56:05.544', '2026-06-09 08:56:05.544');
