mage.\",\"enum\":[\"png\",\"jpeg\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"1k\",\"description\":\"The resolution of the output image.\",\"enum\":[\"1k\",\"2k\",\"4k\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"resolution\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:05.780', '2026-06-09 08:56:05.780', '2026-06-09 08:56:05.780');
