"num_samples\":{\"default\":2,\"description\":\"Number of sound effects to generate\",\"maximum\":4,\"minimum\":2,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"prompt\":{\"description\":\"Text prompt to guide sound effect generation\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"video\":{\"description\":\"The video for generating the output.\",\"type\":\"string\"}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"prompt\",\"num_samples\",\"seed\"]}}]}}', '2026-06-09 08:56:06.411', '2026-06-09 08:56:06.411', '2026-06-09 08:56:06.411');
