INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('89967040-32d3-41f7-9153-5aa4270846e0', NULL, 'cmq0hadjp0000si8dckyresaj', 'google/imagen3', 'google/imagen3', 'IMAGE', 0.038, NULL, NULL, 310, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/imagen3\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"1:1\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"16:9\",\"9:16\",\"4:3\",\"3:4\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"num_images\":{\"default\":1,\"description\":\"The number of images to generate.\",\"maximum\":4,\"minimum\":1,\"type\":\"integer\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"num_images\",\"negative_prompt\",\"seed\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"google/imagen3\",\"name\":\"google/imagen3\",\"base_price\":0.038,\"formula\":\"{\\\"total_price\\\":base_price * num_images}\",\"description\":\"Imagen3 is Google\'s highest-quality text-to-image model, generating highly detailed, beautifully lit and photoreal images from text prompts. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":310,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/imagen3\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"1:1\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"16:9\",\"9:16\",\"4:3\",\"3:4\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"num_images\":{\"default\":1,\"description\":\"The number of images to generate.\",\"maximum\":4,\"minimum\":1,\"type\":\"integer\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"num_images\",\"negative_prompt\",\"seed\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.191', '2026-06-09 08:56:06.191', '2026-06-09 08:56:06.191');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('89e5afa8-f6fa-4ab2-8b0a-a85190e6788b', NULL, 'cmq0hadjp0000si8dckyresaj', 'minimax/speech-2.8-hd', 'minimax/speech-2.8-hd', 'AUDIO', 0.1, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/speech-2.8-hd\",\"request_schema\":{\"properties\":{\"bitrate\":{\"description\":\"Bitrate of generated sound.\",\"enum\":[32000,64000,128000,256000],\"type\":\"integer\",\"x-placeholder\":\"Select the bitrate\"},\"channel\":{\"description\":\"The number of channels of the generated audio. 1: mono, 2: stereo.\",\"enum\":[\"1\",\"2\"],\"type\":\"string\",\"x-placeholder\":\"Select the channel\"},\"emotion\":{\"default\":\"happy\",\"description\":\"The emotion of the generated speech.\",\"enum\":[\"happy\",\"sad\",\"angry\",\"fearful\",\"disgusted\",\"surprised\",\"neutral\"],\"type\":\"string\",\"x-placeholder\":\"Select the emotion\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"english_normalization\":{\"default\":false,\"description\":\"This parameter supports English text normalization, which improves performance in number-reading scenarios.\",\"type\":\"boolean\"},\"format\":{\"description\":\"Format of generated sound.\",