:\"The number of images to generate.\",\"maximum\":4,\"minimum\":1,\"type\":\"integer\"},\"num_inference_steps\":{\"default\":28,\"description\":\"The number of inference steps to perform.\",\"maximum\":50,\"minimum\":1,\"type\":\"integer\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\",\"x-hidden\":true}},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"size\",\"num_inference_steps\",\"guidance_scale\",\"num_images\",\"seed\",\"output_format\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:07.443', '2026-06-09 08:56:07.443', '2026-06-09 08:56:07.443');
