INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('9961d87f-aad7-4bc0-86c8-734010458afd', NULL, 'cmq0hadjp0000si8dckyresaj', 'pixverse/pixverse-v5.6/image-to-video', 'pixverse/pixverse-v5.6/image-to-video', 'VIDEO', 0.35, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/pixverse/pixverse-v5.6/image-to-video\",\"request_schema\":{\"allOf\":[{\"if\":{\"properties\":{\"resolution\":{\"const\":\"1080p\"}},\"required\":[\"resolution\"]},\"then\":{\"properties\":{\"duration\":{\"default\":5,\"enum\":[5,8],\"type\":\"integer\"}}}},{\"if\":{\"properties\":{\"resolution\":{\"enum\":[\"360p\",\"540p\",\"720p\"]}},\"required\":[\"resolution\"]},\"then\":{\"properties\":{\"duration\":{\"default\":5,\"enum\":[5,8,10],\"type\":\"integer\"}}}}],\"properties\":{\"duration\":{\"default\":5,\"description\":\"The duration of the generated media.\",\"enum\":[5,8,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"generate_audio_switch\":{\"default\":false,\"description\":\"Enable audio generation for the video.\",\"type\":\"boolean\"},\"image\":{\"description\":\"First frame of the video; Supported image formats include.jpg/.jpeg/.png; The image file size cannot exceed 10MB, and the image resolution should not be less than 300*300px, and the aspect ratio of the image should be between 1:2.5 ~ 2.5:1.\",\"type\":\"string\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\",\"x-hidden\":true},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"540p\",\"description\":\"The resolution of the generated media.\",\"enum\":[\"360p\",\"540p\",\"720p\",\"1080p\"],\"type\"