INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('9e0dbd7d-1ac1-4ac7-9a80-678618f1e142', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/void-video-inpainting/mask', 'wavespeed-ai/void-video-inpainting/mask', 'VIDEO', 0.05, NULL, NULL, 1, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/void-video-inpainting/mask\",\"request_schema\":{\"properties\":{\"enable_pass2_refinement\":{\"default\":false,\"description\":\"Run VOID Pass 2 warped-noise refinement after Pass 1. This is slower but can improve temporal consistency on longer clips.\",\"type\":\"boolean\"},\"guidance_scale\":{\"default\":1,\"description\":\"Classifier-free guidance scale.\",\"maximum\":20,\"minimum\":0,\"step\":1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"mask_prompt\":{\"description\":\"Text description of what should be masked in the input video, such as the object or person to remove. Used to generate a temporary mask video with SAM-3 when `quad_mask_video_url` is not provided.\",\"type\":\"string\"},\"mask_video\":{\"description\":\"URL of a mask video for the removal target. For best results this should be a VOID-style quadmask video with 4 grayscale values: 0=object to remove, 63=overlap, 127=affected region, 255=background to keep. A simple binary mask (0=remove, 255=keep) also works. If omitted, the app will generate a temporary mask video from `mask_prompt` using the SAM-3 video endpoint and convert it to a quadmask automatically.\",\"type\":\"string\",\"x-accept\":\"video/*\",\"x-ui-component\":\"uploader\"},\"negative_prompt\":{\"description\":\"Negative prompt to guide generation away from undesired outputs.\",\"type\":\"string\"},\"num_frames\":{\"default\":85,\"description\":\"Temporal window size for inference. The backend snaps this to the nearest CogVideoX-safe value that works with temporal compression and patching. Valid outputs are 69, 77, 85, ..., 197.\",\"maximum\":197,\"minimum\":1,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"num_inference_steps\":{\"default\":30,\"description\":\"Number of denoising steps. Higher values improve quality but increase latency.\",\"maximum\":50,\"minimum\":1,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"prompt\":{\"description\":\"Text description of the desired background after object removal.\",\"type\":\"string\"},\"seed\":{\"description\":\"Random seed for reproducibility.\",\"type\":\"integer\"},\"strength\":{\"default\":1,\"description\":\"Denoising strength. 1.0 means full denoising.\",\"maximum\":1,\"minimum\":0,\"step\":1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"video\":{\"description\":\"URL of the input video containing the object to remove.\",\"type\":\"string\"}},\"required\":[\"video\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"mask_video\",\"mask_prompt\",\"enable_pass2_refinement\",\"negative_prompt\",\"num_inference_steps\",\"guidance_scale\",\"strength\",\"num_frames\",\"seed\"]}}]}', '{\"model_id\":\"wavespeed-ai/void-video-inpainting/mask\",\"name\":\"wavespeed-ai/void-video-inpainting/mask\",\"base_price\":0.05,\"formula\":\"{\\\"total_price\\\":base_price*(enable_pass2_refinement?2:1)+(mask_video?50000:0)}\",\"description\":\"Baidu ERNIE Image generates high-quality images from text prompts in English, Chinese, and Japanese, with flexible sizing and LLM-enhanced prompt expansion. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-to-video\",\"sort_order\":1,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/void-video-inpainting/mask\",\"request_schema\":{\"properties\":{\"enable_pass2_refinement\":{\"default\":false,\"description\":\"Run VOID Pass 2 warped-noise refinement after Pass 1. This is slower but can improve temporal consistency on longer clips.\",\"type\":\"boolean\"},\"guidance_scale\":{\"default\":1,\"description\":\"Classifier-free guidance scale.\",\"maximum\":20,\"minimum\":0,\"step\":1,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"mask_prompt\":{\"description\":\"Text description of what should be masked in the input video, such as the object or person to remove. Used to generate a temporary mask video with SAM-3 when `quad_mask_video_url` is not provided.\",\"type\":\"string\"},\"mask_video\":{\"description\":\"URL of a mask video for the removal target. For best results this should be a VOID-style quadmask video with 4 grayscale values: 0=object to remove, 63=overlap, 127=affected region, 255=background to keep. A simple binary mask (0=remove, 255=keep) also works. If omitted, the app will generate a temporary mask video from `mask_prompt` using the SAM-3 video endpoint and convert it to a quadmask automatically.\",\"type\":\"string\",\"x-accept\":\"video/*\",\"x-ui-component\":\"uploader\"},\"negative_prompt\":{\"description\":\"Negative prompt to guide generation away from undesired outputs.\",\"type\":\"string\"},\"num_frames\":{\"default\":85,\"description\":\"Temporal window size for inference. The backend snaps this to the nearest CogVideoX-safe value that works with temporal compression and patching. Valid outputs are 69, 77, 85, ..., 197.\",\"maximum\":197,\"minimum\":1,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"num_inference_steps\":{\"default\":30,\"description\":\"Number of denoising steps. Higher values improve quality but increase latency.\",\"maximum\":50,\"minimum\":1,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"prompt\":{\"description\":\"Text description of the desired background after object removal.\",\"type\":\"s