s\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"loras\",\"size\",\"seed\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}', '{\"model_id\":\"wavespeed-ai/flux-2-dev/edit-lora\",\"name\":\"wavespeed-ai/flux-2-dev/edit-lora\",\"base_price\":0.03,\"formula\":\"\",\"description\":\"FLUX.2 [dev] Edit with LoRA support enables precise image-to-image editing with natural-language instructions, hex color control, and personalized styles via custom LoRA adapters. Extends FLUX.2 [dev] Edit with up to 4 LoRAs for consistent, brand-specific results. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"lora-support\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-2-dev/edit-lora\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"images\":{\"description\":\"List of URLs of input images for editing. The maximum number of images is 3.\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"minItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"loras\":{\"default\":[],\"description\":\"List of LoRAs to apply (max 3).\",\"items\":{\"$ref\":\"#/components/schemas/LoraWeight\"},\"maxItems\":3,\"type\":\"array\"},\"prompt\":{\"description\":\"The prompt describing the desired edits to the image.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"des