e,\"description\":\"Whether to generate textures for the model.\",\"type\":\"boolean\"},\"texture_quality\":{\"default\":\"standard\",\"description\":\"Quality level for textures. \'detailed\' produces higher-resolution textures.\",\"enum\":[\"standard\",\"detailed\"],\"type\":\"string\"},\"texture_seed\":{\"description\":\"Seed for texture generation reproducibility.\",\"type\":\"integer\",\"x-hidden\":true}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"negative_prompt\",\"texture\",\"pbr\",\"texture_quality\",\"geometry_quality\",\"auto_size\",\"quad\",\"face_limit\",\"model_seed\",\"image_seed\",\"texture_seed\"]}}]}', '{\"model_id\":\"tripo3d/h3.1/text-to-3d\",\"name\":\"tripo3d/h3.1/text-to-3d\",\"base_price\":0.1,\"formula\":\"{\\\"total_price\\\":base_price*(texture?(texture_quality=\\\"detailed\\\"?3:2):1)+(geometry_quality=\\\"detailed\\\"?base_price*2:0)+(quad?base_price*0.5:0)}\",\"description\":\"Tripo3D H3.1 Text-to-3D generates high-quality 3D models from text descriptions with optional textures and PBR materials.\",\"type\":\"text-to-3d\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/tripo3d/h3.1/text-to-3d\",\"request_schema\":{\"properties\":{\"auto_size\":{\"default\":false,\"description\":\"Auto-scale the model to real-world dimensions.\",\"type\":\"boolean\"},\"face_limit\":{\"description\":\"Target number of faces for the generated mesh. If not set, the model adaptively determines the count.\",\"maximum\":2000000,\"minimum\":1000,\"type\":\"integer\",\"x-hidden\":true,\"x-ui-component\":\"slider\"},\"geometry_quality\":{\"default\":\"standard\",\"description\":\"Quality level for geometry.\",\"enum\":[\"standard\",\"detailed\"],\"title\":\"Geometry Quality\",\"type\":\"string\"},\"image_seed\":{\"description\":\"Seed for the text-to-image step.\",\"type\":\"integer\",\"x-hidden\":true},\"model_see