INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('a826f611-19ca-46fe-b3f8-3c57c084c4dd', NULL, 'cmq0hadjp0000si8dckyresaj', 'hyper3d/rodin-v2.5/image-to-3d', 'hyper3d/rodin-v2.5/image-to-3d', '3D', 0.4, NULL, NULL, 2010, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/hyper3d/rodin-v2.5/image-to-3d\",\"request_schema\":{\"properties\":{\"addons\":{\"description\":\"Optional HighPack add-on for 4K textures and higher-poly geometry.\",\"enum\":[\"HighPack\"],\"type\":\"string\"},\"geometry_file_format\":{\"default\":\"glb\",\"description\":\"Output geometry file format.\",\"enum\":[\"glb\",\"usdz\",\"fbx\",\"obj\",\"stl\"],\"type\":\"string\"},\"geometry_instruct_mode\":{\"default\":\"faithful\",\"description\":\"Faithful follows the input closely; creative allows more variation.\",\"enum\":[\"faithful\",\"creative\"],\"type\":\"string\"},\"hd_texture\":{\"default\":false,\"description\":\"Enable enhanced texture post-processing.\",\"type\":\"boolean\"},\"images\":{\"description\":\"Reference images for generating the 3D model. Up to 5 images are allowed.\",\"items\":{\"format\":\"uri\",\"type\":\"string\"},\"maxItems\":5,\"minItems\":1,\"type\":\"array\"},\"is_micro\":{\"default\":false,\"description\":\"Generate finer micro-scale geometric detail. Only effective with Extreme-High tier.\",\"type\":\"boolean\"},\"is_symmetric\":{\"default\":\"unknown\",\"description\":\"Symmetry mode for the generated mesh.\",\"enum\":[\"symmetric\",\"balanced\",\"asymmetric\",\"unknown\"],\"type\":\"string\"},\"material\":{\"default\":\"All\",\"description\":\"Material output type.\",\"enum\":[\"PBR\",\"Shaded\",\"All\",\"None\"],\"type\":\"string\"},\"preview_render\":{\"default\":false,\"description\":\"Generate a preview render image of the 3D model.\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"Optional text prompt. If empty, the model auto-generates a prompt from the images.\",\"maxLength\":1024,\"type\":\"string\"},\"quality_and_mesh\":{\"default\":\"500K Triangle\",\"description\":\"Combined quality and mesh type selection.\",\"enum\":[\"4K Quad\",\"8K Quad\",\"18K Quad\",\"50K Quad\",\"2K Triangle\",\"20K Triangle\",\"150K Triangle\",\"500K Triangle\"],\"type\":\"string\"},\"ta_pose\":{\"default\":false,\"description\":\"Generate characters in T-pose or A-pose format.\",\"title\":\"T/A Pose\",\"type\":\"boolean\"},\"texture_delight\":{\"default\":false,\"description\":\"Remove baked lighting and highlights from generated textures.\",\"type\":\"boolean\"},\"texture_mode\":{\"description\":\"Texture generation quality. Leave empty to let the provider choose.\",\"enum\":[\"legacy\",\"extreme-low\",\"low\",\"medium\",\"high\"],\"type\":\"string\"},\"tier\":{\"default\":\"Gen-2.5-Medium\",\"description\":\"Generation tier. Extreme-High bills at double the base rate.\",\"enum\":[\"Gen-2.5-Extreme-Low\",\"Gen-2.5-Low\",\"Gen-2.5-Medium\",\"Gen-2.5-High\",\"Gen-2.5-Extreme-High\"],\"type\":\"string\"},\"use_original_alpha\":{\"default\":false,\"description\":\"Preserve the transparency channel from input images.\",\"type\":\"boolean\"}},\"required\":[\"images\"],\"type\":\"object\",\"x-order-properties\":[\"images\",\"prompt\",\"tier\",\"use_original_alpha\",\"geometry_file_format\",\"material\",\"quality_and_mesh\",\"texture_mode\",\"geometry_instruct_mode\",\"hd_texture\",\"texture_delight\",\"is_symmetric\",\"is_micro\",\"ta_pose\",\"addons\",\"preview_render\"]}}]}', '{\"model_id\":\"hyper3d/rodin-v2.5/image-to-3d\",\"name\":\"hyper3d/rodin-v2.5/image-to-3d\",\"base_price\":0.4,\"formula\":\"{\\\"total_price\\\": base_price * (tier = \\\"Gen-2.5-Extreme-High\\\" ? 2 : 1) + (addons = \\\"HighPack\\\" ? base_price * 2 : 0)}\",\"description\":\"Hyper3