\":\"500K Triangle\",\"description\":\"Combined quality and mesh type selection.\",\"enum\":[\"4K Quad\",\"8K Quad\",\"18K Quad\",\"50K Quad\",\"2K Triangle\",\"20K Triangle\",\"150K Triangle\",\"500K Triangle\"],\"type\":\"string\"},\"ta_pose\":{\"default\":false,\"description\":\"Generate characters in T-pose or A-pose format.\",\"title\":\"T/A Pose\",\"type\":\"boolean\"},\"texture_delight\":{\"default\":false,\"description\":\"Remove baked lighting and highlights from generated textures.\",\"type\":\"boolean\"},\"texture_mode\":{\"description\":\"Texture generation quality. Leave empty to let the provider choose.\",\"enum\":[\"legacy\",\"extreme-low\",\"low\",\"medium\",\"high\"],\"type\":\"string\"},\"tier\":{\"default\":\"Gen-2.5-Medium\",\"description\":\"Generation tier. Extreme-High bills at double the base rate.\",\"enum\":[\"Gen-2.5-Extreme-Low\",\"Gen-2.5-Low\",\"Gen-2.5-Medium\",\"Gen-2.5-High\",\"Gen-2.5-Extreme-High\"],\"type\":\"string\"},\"use_original_alpha\":{\"default\":false,\"description\":\"Preserve the transparency channel from input images.\",\"type\":\"boolean\"}},\"required\":[\"images\"],\"type\":\"object\",\"x-order-properties\":[\"images\",\"prompt\",\"tier\",\"use_original_alpha\",\"geometry_file_format\",\"material\",\"quality_and_mesh\",\"texture_mode\",\"geometry_instruct_mode\",\"hd_texture\",\"texture_delight\",\"is_symmetric\",\"is_micro\",\"ta_pose\",\"addons\",\"preview_render\"]}}]}}', '2026-06-09 08:56:05.989', '2026-06-09 08:56:05.989', '2026-06-09 08:56:05.989');
