age-face-swap\",\"name\":\"wavespeed-ai/image-face-swap\",\"base_price\":0.01,\"formula\":\"\",\"description\":\"Instantly swap faces in photos online with no watermark using Image Face Swap. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"portrait-transfer\",\"sort_order\":2950,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/image-face-swap\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"face_image\":{\"description\":\"The face image as reference.\",\"type\":\"string\",\"x-ui-component\":\"uploader\"},\"image\":{\"description\":\"The image that contains the face to be replaced.\",\"type\":\"string\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\",\"webp\"],\"type\":\"string\"},\"target_index\":{\"default\":0,\"description\":\"0 = largest face. To switch to another target face - switch to index 1, e.t.c.\",\"maximum\":10,\"minimum\":0,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"}},\"required\":[\"image\",\"face_image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"face_image\",\"target_index\",\"output_format\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:05.872', '2026-06-09 08:56:05.872', '2026-06-09 08:56:05.872');
