"description\":\"Output geometry file format.\",\"enum\":[\"glb\",\"usdz\",\"fbx\",\"obj\",\"stl\"],\"type\":\"string\"},\"geometry_instruct_mode\":{\"default\":\"faithful\",\"description\":\"Faithful follows the prompt closely; creative allows more variation.\",\"enum\":[\"faithful\",\"creative\"],\"type\":\"string\"},\"hd_texture\":{\"default\":false,\"description\":\"Enable enhanced texture post-processing.\",\"type\":\"boolean\"},\"is_micro\":{\"default\":false,\"description\":\"Generate finer micro-scale geometric detail. Only effective with Extreme-High tier.\",\"type\":\"boolean\"},\"is_symmetric\":{\"default\":\"unknown\",\"description\":\"Symmetry mode for the generated mesh.\",\"enum\":[\"symmetric\",\"balanced\",\"asymmetric\",\"unknown\"],\"type\":\"string\"},\"material\":{\"default\":\"All\",\"description\":\"Material output type.\",\"enum\":[\"PBR\",\"Shaded\",\"All\",\"None\"],\"type\":\"string\"},\"prompt\":{\"description\":\"A text prompt describing the 3D asset to generate.\",\"maxLength\":1024,\"minLength\":1,\"type\":\"string\"},\"quality_and_mesh\":{\"default\":\"18K Quad\",\"description\":\"Combined quality and mesh type selection.\",\"enum\":[\"4K Quad\",\"8K Quad\",\"18K Quad\",\"50K Quad\",\"2K Triangle\",\"20K Triangle\",\"150K Triangle\",\"500K Triangle\"],\"type\":\"string\"},\"ta_pose\":{\"default\":false,\"description\":\"Generate characters in T-pose or A-pose format.\",\"title\":\"T/A Pose\",\"type\":\"boolean\"},\"texture_delight\":{\"default\":false,\"description\":\"Remove baked lighting and highlights from generated textures.\",\"type\":\"boolean\"},\"texture_mode\":{\"description\":\"Texture generation quality. Leave empty to let the provider choose.\",\"enum\":[\"legacy\",\"extreme-low\",\"low\",\"medium\",\"high\"],\"type\":\"string\"},\"tier\":{\"default\":\"Gen-2.5-Medium\",\"description\":\"Generation tier. Extreme-High bills at double the base rate.\",\"enum\":[\"Gen-2.5-Extreme-Low\",\"Gen-2.5-Low\",\"Gen-2.5-Medium\",\"Ge