"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"mask_image\",\"style\",\"aspect_ratio\",\"reference_images\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:07.199', '2026-06-09 08:56:07.199', '2026-06-09 08:56:07.199');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('b4c5011e-8f0a-4fd9-8921-6e05491d9dd9', NULL, 'cmq0hadjp0000si8dckyresaj', 'google/nano-banana-2/edit-fast', 'google/nano-banana-2/edit-fast', 'IMAGE', 0.045, NULL, NULL, 9300, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/nano-banana-2/edit-fast\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"3:2\",\"2:3\",\"3:4\",\"4:3\",\"4:5\",\"5:4\",\"9:16\",\"16:9\",\"21:9\",\"1:4\",\"4:1\",\"1:8\",\"8:1\"],\"type\":\"string\",\"x-placeholder\":\"Select aspect ratio\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API. Due to variability in Google’s underlying compute resources, inference times can fluctuate significantly. As a result, synchronous requests may hit timeouts.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_web_search\":{\"default\":false,\"description\":\"If enabled, the model will use web search to enhance the generation with real-time information.\",\"type\":\"boolean\"},\"images\":{\"description\":\"List of URLs of input images for editing. The maximum number of images is 14.\",\"items\":{\"type\":\"string\"},\"maxItems\":14,\"minItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"output_format\":{\"default\":\"png\",\"description\":\"The format of the output image.\",\"enum\":[\"png\",\"jpeg\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"2k\",\"description\":\"The resolution of the output image.\",\"enum\":[\"2k\",\"4k\"],\"type\":\"string\"}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"aspect_ratio\",\"resolution\",\"enable_web_search\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"google/nano-banana-2/edit-fast\",\"name\":\"google/nano-banana-2/edit-fast\",\"base_price\":0.045,\"formula\":\"{\\\"total_price\\\": ((resolution = \\\"4k\\\" ? 50000 : base_price) + (enable_web_search ? 14000 : 0))}\",\"description\":\"Google Nano Banana 2 Fast (Gemini 3.1 Flash Image) Edit enables fast image editing with 2K default and 4K-capable output. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":9300,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/nano-banana-2/edit-fast\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"3:2\",\"2:3\",\"3:4\",\"4:3\",\"4:5\",\"5:4\",\"9:16\",\"16:9\",\"21:9\",\"1:4\",\"4:1\",\"1:8\",\"8:1\"],\"type\":\"string\",\"x-placeholder\":\"Select aspect ratio\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API. Due to variability in Google’s underlying compute resources, inference times can fluctuate significantly. As a result, synchronous requests may hit timeouts.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_web_search\":{\"default\":false,\"description\":\"If enabled, the model will use web search to enhance the generation with real-time information.\",\"type\":\"boolean\"},\"images\":{\"description\":\"List of URLs of input images for editing. The maximum number of images is 14.\",\"items\":{\"type\":\"string\"},\"maxItems\":14,\"minItems\":1,\"type\":\"array\",\"x-ui-component\":\"uploaders\"},\"output_format\":{\"default\":\"png\",\"description\":\"The format of the output image.\",\"enum\":[\"png\",\"jpeg\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"2k\",\"description\":\"The resolution of the output image.\",\"enum\":[\"2k\",\"4k\"],\"type\":\"string\"}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"aspect_ratio\",\"resolution\",\"enable_web_search\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:05.591', '2026-06-09 08:56:05.591', '2026-06-09 08:56:05.591');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('b4fe6461-0867-4a8c-b0cd-7fb3b0a0beee', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/flux-v1-pro/erase', 'wavespeed-ai/flux-v1-pro/erase', 'IMAGE', 0.08, NULL, NULL, 10000, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-v1-pro/erase\",\"request_schema\":{\"properties\":{\"dilate_pixels\":{\"default\":10,\"description\":\"Number of pixels to expand the mask edges by. Higher values can produce cleaner erase results around the masked region.\",\"maximum\":100,\"minimum\":0,\"title\":\"Dilate Pixels\",\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"image\":{\"description\":\"The input image to erase content from.\",\"title\":\"Image\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"mask_image\":{\"description\":\"Black/white mask image. White pixels mark the region to erase, black pixels mark the region to keep. The mask must match the input image dimensions.\",\"title\":\"Mask Image\",\"type\":\"string\",\"x-ui-component\":\"mask\",\"x-ui-component-props\":{\"accept\":\"image/*\",\"image\":\"image\"}},\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the generated image.\",\"enum\":[\"jpeg\",\"png\"],\"title\":\"Output Format\",\"type\":\"string\"}},\"required\":[\"image\",\"mask_image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"mask_image\",\"dilate_pixels\",\"output_format\"]}}]}', '{\"model_id\":\"wavespeed-ai/flux-v1-pro/erase\",\"name\":\"wavespeed-ai/flux-v1-pro/erase\",\"base_price\":0.08,\"formula\":\"\",\"description\":\"FLUX.1 Pro Erase removes unwanted regions from images using a black and white mask, then reconstructs the erased area with natural detail.\",\"type\":\"ai-remover\",\"sort_order\":10000,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-v1-pro/erase\",\"request_schema\":{\"properties\":{\"dilate_pixels\":{\"default\":10,\"description\":\"Number of pixels to expand the mask edges by. Higher values can produce cleaner erase results around the masked region.\",\"maximum\":100,\"minimum\":0,\"title\":\"Dilate Pixels\",\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"image\":{\"description\":\"The input image to erase content from.\",\"title\":\"Image\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"mask_image\":{\"description\":\"Black/white mask image. White pixels mark the region to erase, black pixels mark the region to keep. The mask must match the input image dimensions.\",\"title\":\"Mask Image\",\"type\":\"string\",\"x-ui-component\":\"mask\",\"x-ui-component-props\":{\"accept\":\"image/*\",\"image\":\"image\"}},\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the generated image.\",\"enum\":[\"jpeg\",\"png\"],\"title\":\"Output Format\",\"type\":\"string\"}},\"required\":[\"image\",\"mask_image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"mask_image\",\"dilate_pixels\",\"output_format\"]}}]}}', '2026-06-09 08:56:05.418', '2026-06-09 08:56:05.418', '2026-06-09 08:56:05.418');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('b60bd91e-ec56-42ad-8efc-7280e214bd0c', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/flux-2-flash/text-to-image', 'wavespeed-ai/flux-2-flash/text-to-image', 'IMAGE', 0.008, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-2-flash/text-to-image\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"seed\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"wavespeed-ai/flux-2-flash/text-to-image\",\"name\":\"wavespeed-ai/flux-2-flash/text-to-image\",\"base_price\":0.008,\"formula\":\"\",\"description\":\"Text-to-image generation with FLUX.2 [flash] from Black Forest Labs. Enhanced realism, crisper text generation, and native editing capabilities.\",\"type\":\"text-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-2-flash/text-to-image\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"seed\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.767', '2026-06-09 08:56:06.767', '2026-06-09 08:56:06.767');
