Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-dubbing\",\"sort_order\":1700,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/mmaudio-v2\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":8,\"description\":\"The duration of the generated media in seconds.\",\"maximum\":30,\"minimum\":1,\"step\":1,\"type\":\"integer\"},\"guidance_scale\":{\"default\":4.5,\"description\":\"The guidance scale to use for the generation.\",\"maximum\":20,\"minimum\":0,\"type\":\"number\"},\"mask_away_clip\":{\"default\":false,\"description\":\"Whether to mask away the clip.\",\"type\":\"boolean\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"num_inference_steps\":{\"default\":25,\"description\":\"The number of inference steps to perform.\",\"maximum\":50,\"minimum\":4,\"type\":\"integer\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"video\":{\"description\":\"The URL of the video to generate the audio for.\",\"type\":\"string\"}},\"required\":[\"video\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"video\",\"negative_prompt\",\"num_inference_steps\",\"duration\",\"guidance_scale\",\"mask_away_clip\"]}}]}}', '2026-06-09 08:56:06.034', '2026-06-09 08:56:06.034', '2026-06-09 08:56:06.034');
