m\":[\"1280*720\",\"720*1280\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"negative_prompt\",\"size\",\"duration\",\"loras\",\"high_noise_loras\",\"low_noise_loras\",\"seed\"]}}]}}', '2026-06-09 08:56:07.472', '2026-06-09 08:56:07.472', '2026-06-09 08:56:07.472');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('b6a215d8-d411-4ffd-ba52-46be765e826c', NULL, 'cmq0hadjp0000si8dckyresaj', 'minimax/hailuo-2.3/fast', 'minimax/hailuo-2.3/fast', 'IMAGE', 0.19, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/hailuo-2.3/fast\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":6,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[6,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":true,\"description\":\"The model automatically optimizes incoming prompts to enhance output quality. This also activates the safety checker, which ensures content safety by detecting and filtering potential risks.\",\"type\":\"boolean\"},\"go_fast\":{\"default\":true,\"description\":\"Prioritize faster video generation speed with a moderate trade-off in visual quality\",\"type\":\"boolean\"},\"image\":{\"description\":\"The model generates video with the picture passed in as the first frame.Base64 encoded strings in data:image/jpeg; base64,{data} format for incoming images, or URLs accessible via the public network. The uploaded image needs to meet the following conditions: Format is JPG/JPEG/PNG; The aspect ratio is greater than 2:5 and less than 5:2; Short side pixels greater than 300px; The image file size cannot exceed 20MB.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"maxLength\":2000,\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"prompt\",\"duration\",\"enable_prompt_expansion\",\"go_fast\"]}}]}', '{\"model_id\":\"minimax/hailuo-2.3/fast\",\"name\":\"minimax/hailuo-2.3/fast\",\"base_price\":0.19,\"formula\":\"{\\\"total_price\\\": (duration = 10) ? 320000: 190000}\",\"description\":\"Hailuo 2.3 Fast by minimax generates high-quality 6s and 10s image-to-video clips at 768p, optimized for creators and marketers. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/hailuo-2.3/fast\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":6,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[6,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":true,\"description\":\"The model automatically optimizes incoming prompts to enhance output quality. This also activates the safety checker, which ensures content safety by detecting and filtering potential risks.\",\"type\":\"boolean\"},\"go_fast\":{\"default\":true,\"description\":\"Prioritize faster video generation speed with a moderate trade-off in visual quality\",\"type\":\"boolean\"},\"image\":{\"description\":\"The model generates video with the picture passed in as the first frame.Base64 encoded strings in data:image/jpeg; base64,{data} format for incoming images, or URLs accessible via the public network. The uploaded image needs to meet the following conditions: Format is JPG/JPEG/PNG; The aspect ratio is greater than 2:5 and less than 5:2; Short side pixels greater than 300px; The image file size cannot exceed 20MB.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"maxLength\":2000,\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"prompt\",\"duration\",\"enable_prompt_expansion\",\"go_fast\"]}}]}}', '2026-06-09 08:56:06.468', '2026-06-09 08:56:06.468', '2026-06-09 08: