INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('ba061587-a400-49d7-b9fe-7795f450a31e', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/balloon-flyaway', 'video-effects/balloon-flyaway', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/balloon-flyaway\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single-subject, dual-subject, and multi-subject in realistic style characters and animals; 3. Best results achieved when subjects are fully visible and not too close to each other; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/balloon-flyaway\",\"name\":\"video-effects/balloon-flyaway\",\"base_price\":0.2,\"formula\":\"\",\"description\":\"Transform photos into playful balloon flyaway videos with an image-to-video effect that makes subjects float away with charming motion. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/balloon-flyaway\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single-subject, dual-subject, and multi-subject in realistic style characters and animals; 3. Best results achieved when subjects are fully visible and not too close to each other; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.399', '2026-06-09 08:56:07.399', '2026-06-09 08:56:07.399');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('ba81a03a-866f-4569-ba53-8919cac11a5a', NULL, 'cmq0hadjp0000si8dckyresaj', 'alibaba/wan-2.6/image-to-video-spicy', 'alibaba/wan-2.6/image-to-video-spicy', 'VIDEO', 0.5, NULL, NULL, 6200, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.6/image-to-video-spicy\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"Audio URL to guide generation (optional).\",\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[5,10,15],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"If set to true, the prompt optimizer will be enabled.\",\"type\":\"boolean\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated media.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"shot_type\":{\"default\":\"single\",\"description\":\"The type of shots to generate.\",\"enum\":[\"single\",\"multi\"],\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"audio\",\"prompt\",\"negative_prompt\",\"resolution\",\"duration\",\"shot_type\",\"enable_prompt_expansion\",\"seed\"]}}]}', '{\"model_id\":\"alibaba/wan-2.6/image-to-video-spicy\",\"name\":\"alibaba/wan-2.6/image-to-video-spicy\",\"base_price\":0.5,\"formula\":\"{\\\"total_price\\\": base_price * $number(duration) / 5 * ((resolution = \\\"1080p\\\") ? 1.5 : 1)}\",\"description\":\"Alibaba WAN 2.6 Spicy converts images into unlimited high-quality videos with smooth animations optimized for scalable content generation. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":6200,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.6/image-to-video-spicy\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"Audio URL to guide generation (optional).\",\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[5,10,15],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"If set to true, the prompt optimizer will be enabled.\",\"type\":\"boolean\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated media.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"shot_type\":{\"default\":\"single\",\"description\":\"The type of shots to generate.\",\"enum\":[\"single\",\"multi\"],\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"audio\",\"prompt\",\"negative_prompt\",\"resolution\",\"duration\",\"shot_type\",\"enable_prompt_expansion\",\"seed\"]}}]}}', '2026-06-09 08:56:05.686', '2026-06-09 08:56:05.686', '2026-06-09 08:56:05.686');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('bbb14c36-44bf-4317-b579-099307e74001', NULL, 'cmq0hadjp0000si8dckyresaj', 'openai/gpt-image-1', 'openai/gpt-image-1', 'IMAGE', 0.042, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/openai/gpt-image-1\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"image\":{\"description\":\"The image to edit.\",\"type\":\"string\"},\"mask_image\":{\"description\":\"An additional image whose fully transparent areas (e.g. where alpha is zero) indicate where image should be edited. If there are multiple images provided, the mask will be applied on the first image. Must be a valid PNG file\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"minLength\":1,\"type\":\"string\"},\"quality\":{\"default\":\"medium\",\"description\":\"The quality of the generated image.\",\"enum\":[\"high\",\"medium\",\"low\"],\"type\":\"string\"},\"size\":{\"default\":\"auto\",\"description\":\"The size of the generated media in pixels (width*height).\",\"enum\":[\"auto\",\"1024*1024\",\"1024*1536\",\"1536*1024\"],\"type\":\"string\"}},\"required\":[\"image\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"quality\",\"mask_image\",\"size\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"openai/gpt-image-1\",\"name\":\"openai/gpt-image-1\",\"base_price\":0.042,\"formula\":\"{\\\"total_price\\\": (quality = \\\"low\\\") ? ((size = \\\"1024x1024\\\") ? 11000 : ((size = \\\"1024x1536\\\" or size = \\\"1536x1024\\\") ? 16000 : 11000)) : (quality = \\\"medium\\\") ? ((size = \\\"1024x1024\\\") ? 42000 : ((size = \\\"1024x1536\\\" or size = \\\"1536x1024\\\") ? 63000 : 42000)) : ((size = \\\"1024x1024\\\") ? 167000 : ((size = \\\"1024x1536\\\" or size = \\\"1536x1024\\\") ? 250000 : 167000))}\",\"description\":\"OpenAI\'s gpt-image-1 enables image generation and image editing via OpenAI\'s image API, ideal for creating and refining images. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/openai/gpt-image-1\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"image\":{\"description\":\"The image to edit.\",\"type\":\"string\"},\"mask_image\":{\"description\":\"An additional image whose fully transparent areas (e.g. where alpha is zero) indicate where image should be edited. If there are multiple images provided, the mask will be applied on the first image. Must be a valid PNG file\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"minLength\":1,\"type\":\"string\"},\"quality\":{\"default\":\"medium\",\"description\":\"The quality of the generated image.\",\"enum\":[\"high\",\"medium\",\"low\"],\"type\":\"string\"},\"size\":{\"default\":\"auto\",\"description\":\"The size of the generated media in pixels (width*height).\",\"enum\":[\"auto\",\"1024*1024\",\"1024*1536\",\"1536*1024\"],\"type\":\"string\"}},\"required\":[\"image\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"quality\",\"mask_image\",\"size\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:07.381', '2026-06-09 08:56:07.381', '2026-06-09 08:56:07.381');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('bbc3148e-c9f7-47b9-a3d2-cc009235d061', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/cap-walk', 'video-effects/cap-walk', 'VIDEO', 0.3, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/cap-walk\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Only supports single-person photos; 3. Best for half-body or full-body photos; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/cap-walk\",\"name\":\"video-effects/cap-walk\",\"base_price\":0.3,\"formula\":\"\",\"description\":\"Turn a photo into an epic shield-bearing warrior video featuring cinematic walk cycles and heroic styling. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/cap-walk\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Only supports single-person photos; 3. Best for half-body or full-body photos; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.062', '2026-06-09 08:56:07.062', '2026-06-09 08:56:07.062');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('bbd5ac11-d887-4ee0-884f-7a4ac3d90598', NULL, 'cmq0hadjp0000si8dckyresaj', 'google/veo3.1/reference-to-video', 'google/veo3.1/reference-to-video', 'VIDEO', 3.2, NULL, NULL, 6900, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/veo3.1/reference-to-video\",\"request_schema\":{\"properties\":{\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate audio.\",\"type\":\"boolean\"},\"images\":{\"description\":\"The model will use the provided images as references to generate a video with consistent subjects. For fields that accept images: Accepts 1 to 3 images; Images Assets can be provided via URLs or Base64 encode; You must use one of the following codecs: PNG, JPEG, JPG, WebP; The dimensions of the images must be at least 128*128 pixels; All images are limited to 50MB; The length of the base64 decode must be under 50MB, and it must include an appropriate content type string.\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"minItems\":1,\"type\":\"array\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"1080p\",\"description\":\"Video resolution.\",\"enum\":[\"720p\",\"1080p\",\"4k\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"}},\"required\":[\"prompt\",\"images\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"aspect_ratio\",\"duration\",\"resolution\",\"generate_audio\",\"negative_prompt\",\"seed\"]}}]}', '{\"model_id\":\"google/veo3.1/reference-to-video\",\"name\":\"google/veo3.1/reference-to-video\",\"base_price\":3.2,\"formula\":\"{ \\\"total_price\\\": ((generate_audio ? 3200000 : 1600000) * 8 / 8) }\",\"description\":\"Google Veo3.1 Reference-to-Video performs image-to-video generation that preserves a specific subject\'s appearance and identity from provided reference images, enabling consistent character or product motion across frames. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":6900,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/google/veo3.1/reference-to-video\",\"request_schema\":{\"properties\":{\"generate_audio\":{\"default\":true,\"description\":\"Whether to generate audio.\",\"type\":\"boolean\"},\"images\":{\"description\":\"The model will use the provided images as references to generate a video with consistent subjects. For fields that accept images: Accepts 1 to 3 images; Images Assets can be provided via URLs or Base64 encode; You must use one of the following codecs: PNG, JPEG, JPG, WebP; The dimensions of the images must be at least 128*128 pixels; All images are limited to 50MB; The length of the base64 decode must be under 50MB, and it must include an appropriate content type string.\",\"items\":{\"type\":\"string\"},\"maxItems\":3,\"minItems\":1,\"type\":\"array\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"1080p\",\"description\":\"Video resolution.\",\"enum\":[\"720p\",\"1080p\",\"4k\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"}},\"required\":[\"prompt\",\"images\"],\"seed\":{\"title\":\"Seed\",\"type\":\"integer\"},\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"aspect_ratio\",\"duration\",\"resolution\",\"generate_audio\",\"negative_prompt\",\"seed\"]}}]}}', '2026-06-09 08:56:05.662', '2026-06-09 08:56:05.662', '2026-06-09 08:56:05.662');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('bc00f339-83e6-43d7-a730-cd7c38304474', NULL, 'cmq0hadjp0000si8dckyresaj', 'minimax/voice-clone', 'minimax/voice-clone', 'IMAGE', 0.5, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/voice-clone\",\"request_schema\":{\"properties\":{\"accuracy\":{\"default\":0.7,\"description\":\"Uploading this parameter will set the text validation accuracy threshold, with a value range of [0,1]. If not provided, the default value for this parameter is 0.7.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"audio\":{\"description\":\"The uploaded file is cloned and supports formats such as MP3, M4A, and WAV.\",\"type\":\"string\",\"x-accept\":\".mp3,.m4a,.wav\",\"x-placeholder\":\"Upload your audio file\",\"x-ui-component\":\"uploader\"},\"custom_voice_id\":{\"description\":\"Custom user-defined ID. Minimum 8 characters; must include letters and numbers and start with a letter (e.g., WaveSpeed001). Duplicate voice-ids will throw an error.\",\"type\":\"string\",\"x-hint\":\"Custom user-defined ID: Must be at least 8 characters long, starting with a letter, and include both letters and numbers (e.g., WaveSpeed-20250717-1050). Duplicate voice IDs will result in an error. This ID can be used with the following models:minimax/speech-02-hd minimax/speech-02-turbo\",\"x-placeholder\":\"Enter your custom voice ID, Minimum 8 characters\"},\"language_boost\":{\"description\":\"Enhance the ability to recognize specified languages and dialects.\",\"enum\":[\"Chinese\",\"Chinese,Yue\",\"English\",\"Arabic\",\"Russian\",\"Spanish\",\"French\",\"Portuguese\",\"German\",\"Turkish\",\"Dutch\",\"Ukrainian\",\"Vietnamese\",\"Indonesian\",\"Japanese\",\"Italian\",\"Korean\",\"Thai\",\"Polish\",\"Romanian\",\"Greek\",\"Czech\",\"Finnish\",\"Hindi\",\"auto\"],\"type\":\"string\",\"x-placeholder\":\"Select the language\"},\"model\":{\"default\":\"speech-02-hd\",\"description\":\"Specify the TTS model to be used for the preview. This is only a preview after cloning. Once the model is generated, any Minimax Turbo or HD voice model can be used for inference.\",\"enum\":[\"speech-02-hd\",\"speech-02-turbo\",\"speech-2.5-hd-preview\",\"speech-2.5-turbo-preview\",\"speech-2.6-hd\",\"speech-2.6-turbo\",\"speech-2.8-hd\",\"speech-2.8-turbo\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"need_noise_reduction\":{\"default\":false,\"description\":\"Enable noise reduction. Default is false (no noise reduction).\",\"type\":\"boolean\"},\"need_volume_normalization\":{\"default\":false,\"description\":\"Specify whether to enable volume normalization. If not provided, the default value is false.\",\"type\":\"boolean\"},\"text\":{\"default\":\"Hello! Welcome to Wavespeed! This is a preview of your cloned voice. I hope you enjoy it!\",\"description\":\"Text for audio preview. Limited to 2000 characters.\",\"maxLength\":2000,\"type\":\"string\",\"x-rows\":3,\"x-ui-component\":\"textarea\"}},\"required\":[\"audio\",\"custom_voice_id\",\"model\"],\"type\":\"object\",\"x-order-properties\":[\"audio\",\"custom_voice_id\",\"model\",\"need_noise_reduction\",\"need_volume_normalization\",\"accuracy\",\"text\",\"language_boost\"]}}]}', '{\"model_id\":\"minimax/voice-clone\",\"name\":\"minimax/voice-clone\",\"base_price\":0.5,\"formula\":\"\",\"description\":\"Minimax Voice Clone creates high-quality voice clones from short reference clips, closely matching tone, accent, and speaking style. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"audio-to-audio\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/voice-clone\",\"request_schema\":{\"properties\":{\"accuracy\":{\"default\":0.7,\"description\":\"Uploading this parameter will set the text validation accuracy threshold, with a value range of [0,1]. If not provided, the default value for this parameter is 0.7.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"audio\":{\"description\":\"The uploaded file is cloned and supports formats such as MP3, M4A, and WAV.\",\"type\":\"string\",\"x-accept\":\".mp3,.m4a,.wav\",\"x-placeholder\":\"Upload your audio file\",\"x-ui-component\":\"uploader\"},\"custom_voice_id\":{\"description\":\"Custom user-defined ID. Minimum 8 characters; must include letters and numbers and start with a letter (e.g., WaveSpeed001). Duplicate voice-ids will throw an error.\",\"type\":\"string\",\"x-hint\":\"Custom user-defined ID: Must be at least 8 characters long, starting with a letter, and include both letters and numbers (e.g., WaveSpeed-20250717-1050). Duplicate voice IDs will result in an error. This ID can be used with the following models:minimax/speech-02-hd minimax/speech-02-turbo\",\"x-placeholder\":\"Enter your custom voice ID, Minimum 8 characters\"},\"language_boost\":{\"description\":\"Enhance the ability to recognize specified languages and dialects.\",\"enum\":[\"Chinese\",\"Chinese,Yue\",\"English\",\"Arabic\",\"Russian\",\"Spanish\",\"French\",\"Portuguese\",\"German\",\"Turkish\",\"Dutch\",\"Ukrainian\",\"Vietnamese\",\"Indonesian\",\"Japanese\",\"Italian\",\"Korean\",\"Thai\",\"Polish\",\"Romanian\",\"Greek\",\"Czech\",\"Finnish\",\"Hindi\",\"auto\"],\"type\":\"string\",\"x-placeholder\":\"Select the language\"},\"model\":{\"default\":\"speech-02-hd\",\"description\":\"Specify the TTS model to be used for the preview. This is only a preview after cloning. Once the model is generated, any Minimax Turbo or HD voice model can be used for inference.\",\"enum\":[\"speech-02-hd\",\"speech-02-turbo\",\"speech-2.5-hd-preview\",\"speech-2.5-turbo-preview\",\"speech-2.6-hd\",\"speech-2.6-turbo\",\"speech-2.8-hd\",\"speech-2.8-turbo\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"need_noise_reduction\":{\"default\":false,\"description\":\"Enable noise reduction. Default is false (no noise reduction).\",\"type\":\"boolean\"},\"need_volume_normalization\":{\"default\":false,\"description\":\"Specify whether to enable volume normalization. If not provided, the default value is false.\",\"type\":\"boolean\"},\"text\":{\"default\":\"Hello! Welcome to Wavespeed! This is a preview of your cloned voice. I hope you enjoy it!\",\"description\":\"Text for audio preview. Limited to 2000 characters.\",\"maxLength\":2000,\"type\":\"string\",\"x-rows\":3,\"x-ui-component\":\"textarea\"}},\"required\":[\"audio\",\"custom_voice_id\",\"model\"],\"type\":\"object\",\"x-order-properties\":[\"audio\",\"custom_voice_id\",\"model\",\"need_noise_reduction\",\"need_volume_normalization\",\"accuracy\",\"text\",\"language_boost\"]}}]}}', '2026-06-09 08:56:06.640', '2026-06-09 08:56:06.640', '2026-06-09 08:56:06.640');
