tring\"},\"strength\":{\"default\":0.6,\"description\":\"Controls the strength of the transformation. Higher values produce outputs more different from the input image.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\"}},\"required\":[\"image\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"loras\",\"size\",\"strength\",\"seed\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"wavespeed-ai/z-image-turbo/image-to-image-lora\",\"name\":\"wavespeed-ai/z-image-turbo/image-to-image-lora\",\"base_price\":0.01,\"formula\":\"\",\"description\":\"Z-Image-Turbo Image-to-Image LoRA transforms reference images with custom LoRA styles in sub-second time. Apply up to 3 LoRAs for personalized image transformation. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"lora-support\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/z-image-turbo/image-to-image-lora\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"image\":{\"description\":\"Reference image URL to guide the generation style or composition.\",\"format\":\"uri\",\"type\":\"string\"},\"loras\":{\"default\":[],\"description\":\"List of LoRAs to apply (maximum 3).\",\"items\":{\"$ref\":\"#/components/schemas/LoraWeight\"},\"maxItems\":3,\"type\":\"array\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"},\"strength\":{\"default\":0.6,\"description\":\"Controls the strength of the transformation. Higher values produce outputs more different from the input image.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\"}},\"required\":[\"image\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"loras\",\"size\",\"strength\",\"seed\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.846', '2026-06-09 08:56:06.846', '2026-06-09 08:56:06.846');
