\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"aspect_ratio\"]}}]}}', '2026-06-09 08:56:06.316', '2026-06-09 08:56:06.316', '2026-06-09 08:56:06.316');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('c0115fd1-f24e-40c7-9ffd-1a6f58db68aa', NULL, 'cmq0hadjp0000si8dckyresaj', 'ideogram-ai/ideogram-v2-turbo', 'ideogram-ai/ideogram-v2-turbo', 'IMAGE', 0.05, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/ideogram-ai/ideogram-v2-turbo\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"1:1\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"16:9\",\"9:16\",\"4:3\",\"3:4\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"image\":{\"description\":\"The image to generate an image from.\",\"type\":\"string\"},\"mask_image\":{\"description\":\"The mask image tells the model where to generate new pixels (white) and where to preserve the original image (black). It acts as a stencil or guide for targeted image editing.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"style\":{\"default\":\"Auto\",\"description\":\"The style of the generated image.\",\"enum\":[\"Auto\",\"General\",\"Realistic\",\"Design\",\"Render 3D\",\"Anime\"],\"type\":\"string\",\"x-placeholder\":\"Select Style\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"mask_image\",\"style\",\"aspect_ratio\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"ideogram-ai/ideogram-v2-turbo\",\"name\":\"ideogram-ai/ideogram-v2-turbo\",\"base_price\":0.05,\"formula\":\"\",\"description\":\"Ideogram v2 turbo is an image model that excels at inpainting, prompt comprehension, and accurate on-image text rendering. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/ideogram-ai/ideogram-v2-turbo\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"1:1\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"16:9\",\"9:16\",\"4:3\",\"3:4\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"image\":{\"description\":\"The image to generate an image from.\",\"type\":\"string\"},\"mask_image\":{\"description\":\"The mask image tells the model where to generate new pixels (white) and where to preserve the original image (black). It acts as a stencil or guide for targeted image editing.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"style\":{\"default\":\"Auto\",\"description\":\"The style of the generated image.\",\"enum\":[\"Auto\",\"General\",\"Realistic\",\"Design\",\"Render 3D\",\"Anime\"],\"type\":\"string\",\"x-placeholder\":\"Select Style\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"mask_image\",\"style\",\"aspect_ratio\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.634', '2026-06-09 08:56:06.634', '2026-06-09 08:56:06.634');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('c01cc278-5387-4dd1-a87c-8eb34f6d61e6', NULL, 'cmq0hadjp0000si8dckyresaj', 'alibaba/wan-2.6/reference-to-video-flash', 'alibaba/wan-2.6/reference-to-video-flash', 'VIDEO', 0.125, NULL, NULL, 6150, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.6/reference-to-video-flash\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"Audio URL to guide generation (optional).\",\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[5,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_audio\":{\"default\":true,\"description\":\"Whether to generate audio for the video. Set to false to generate video without audio.\",\"type\":\"boolean\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"If set to true, the prompt optimizer will be enabled.\",\"type\":\"boolean\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"reference_urls\":{\"description\":\"Array of URLs to reference images or videos. Images: 0-5, Videos: 0-3, Total: ≤5.\",\"items\":{\"description\":\"URL to reference image or video.\",\"type\":\"string\"},\"maxItems\":5,\"minItems\":1,\"type\":\"array\",\"x-accept\":\"image/*,video/*\",\"x-ui-component\":\"uploaders\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"shot_type\":{\"default\":\"single\",\"description\":\"The type of shots to generate.\",\"enum\":[\"single\",\"multi\"],\"type\":\"string\"},\"size\":{\"default\":\"1280*720\",\"description\":\"The size of the generated media in pixels (width*height).\",\"enum\":[\"1280*720\",\"720*1280\",\"1920*1080\",\"1080*1920\"],\"type\":\"string\"}},\"required\":[\"reference_urls\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"reference_urls\",\"prompt\",\"audio\",\"negative_prompt\",\"size\",\"duration\",\"shot_type\",\"enable_audio\",\"enable_prompt_expansion\",\"seed\"]}}]}', '{\"model_id\":\"alibaba/wan-2.6/reference-to-video-flash\",\"name\":\"alibaba/wan-2.6/reference-to-video-flash\",\"base_price\":0.125,\"formula\":\"{\\\"total_price\\\": base_price * $number(duration + 5) / 5 * ((size = \\\"1920*1080\\\" or size = \\\"1080*1920\\\") ? 1.6 : 1) * ((enable_audio = true) ? 2 : 1)}\",\"description\":\"Alibaba WAN 2.6 Reference-to-Video Flash turns character, prop, or scene references from images or videos into new video shots with preserved identity, style, and layout plus smooth, coherent motion. Flash version with faster generation speed. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":6150,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.6/reference-to-video-flash\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"Audio URL to guide generation (optional).\",\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[5,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_audio\":{\"default\":true,\"description\":\"Whether to generate audio for the video. Set to false to generate video without audio.\",\"type\":\"boolean\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"If set to true, the prompt optimizer will be enabled.\",\"type\":\"boolean\"},\"negative_prompt\":