INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('c1a39353-989b-4c4f-b466-afb967ff36f4', NULL, 'cmq0hadjp0000si8dckyresaj', 'pixverse/swap', 'pixverse/swap', 'IMAGE', 0.09, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/pixverse/swap\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"The model generates video with the picture passed in as the first frame.Base64 encoded strings in data:image/jpeg; base64,{data} format for incoming images, or URLs accessible via the public network. The uploaded image needs to meet the following conditions: Format is JPG/JPEG/PNG; The aspect ratio is greater than 2:5 and less than 5:2; Short side pixels greater than 300px; The image file size cannot exceed 20MB.\",\"type\":\"string\"},\"mode\":{\"default\":\"person\",\"description\":\"The swap mode to use Default value: person\",\"enum\":[\"person\",\"object\",\"background\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Video quality (360p/540p/720p).\",\"enum\":[\"360p\",\"540p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"video\":{\"description\":\"The video to be swapped.\",\"type\":\"string\"}},\"required\":[\"video\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"video\",\"resolution\",\"mode\"]}}]}', '{\"model_id\":\"pixverse/swap\",\"name\":\"pixverse/swap\",\"base_price\":0.09,\"formula\":\"{\\\"total_price\\\": (((resolution = \\\"360p\\\" or resolution = \\\"540p\\\") ? 90000 : ((resolution = \\\"720p\\\") ? 120000 : 200000)) * $number(get_duration_v3(video)) ) + 20000}\",\"description\":\"PixVerse Swap replaces backgrounds, people, and objects directly inside existing videos for quick scene changes and creative edits with natural-looking results. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"portrait-transfer\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/pixverse/swap\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"The model generates video with the picture passed in as the first frame.Base64 encoded strings in data:image/jpeg; base64,{data} format for incoming images, or URLs accessible via the public network. The uploaded image needs to meet the following conditions: Format is JPG/JPEG/PNG; The aspect ratio is greater than 2:5 and less than 5:2; Short side pixels greater than 300px; The image file size cannot exceed 20MB.\",\"type\":\"string\"},\"mode\":{\"default\":\"person\",\"description\":\"The swap mode to use Default value: person\",\"enum\":[\"person\",\"object\",\"background\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Video quality (360p/540p/720p).\",\"enum\":[\"360p\",\"540p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"video\":{\"description\":\"The video to be swapped.\",\"type\":\"string\"}},\"required\":[\"video\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"video\",\"resolution\",\"mode\"]}}]}}', '2026-06-09 08:56:06.552', '2026-06-09 08:56:06.552', '2026-06-09 08:56:06.552');
