Additional text for texture guidance (full mode only)\",\"type\":\"string\"},\"topology\":{\"default\":\"triangle\",\"description\":\"Specify the topology of the generated model. Quad for smooth surfaces, Triangle for detailed geometry.\",\"enum\":[\"quad\",\"triangle\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"mode\",\"art_style\",\"topology\",\"target_polycount\",\"symmetry_mode\",\"should_remesh\",\"enable_pbr\",\"ta_pose\",\"enable_prompt_expansion\",\"texture_prompt\",\"texture_image\"]}}]}', '{\"model_id\":\"wavespeed-ai/meshy6/text-to-3d\",\"name\":\"wavespeed-ai/meshy6/text-to-3d\",\"base_price\":0.8,\"formula\":\"\",\"description\":\"Meshy 6 generates high-quality 3D models from text descriptions with accurate geometry and superior texture quality.\",\"type\":\"text-to-3d\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/meshy6/text-to-3d\",\"request_schema\":{\"properties\":{\"art_style\":{\"default\":\"realistic\",\"description\":\"Desired artistic style of the generated model\",\"enum\":[\"realistic\",\"sculpture\"],\"type\":\"string\"},\"enable_pbr\":{\"default\":false,\"description\":\"Generate PBR maps (metallic, roughness, normal)\",\"type\":\"boolean\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"Use LLM to expand prompt details for better results\",\"type\":\"boolean\"},\"prompt\":{\"description\":\"Describe what kind of object the 3D model is. Maximum 600 characters.\",\"maxLength\":600,\"type\":\"string\"},\"should_remesh\":{\"default\":true,\"description\":\"Enable remesh phase for cleaner topology\",\"type\":\"boolean\"},\"symmetry_mode\":{\"default\":\"auto\",\"description\":\"Controls symmetry behavior of the generated model\",\"enum\":[\"off\",\"auto\",\"on\"],\"type\":\"string\"},\"ta_pose\":{\"default\":false,\"description\":\"Generate model in A/T pose for rigging\",\"type\":\"boolean\"},\"target_polycount\":{\"default\":30000,\"description\":\"Target polygon count in generated model\",\"maximum\":300000,\"minimum\":100,\"type\":\"integer\"},\"texture_image\":{\"description\":\"2D image for texture guidance (full mode only)\",\"format\":\"uri\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"texture_prompt\":{\"description\":\"Additional text for texture guidance (full mode only)\",\"type\":\"string\"},\"topology\":{\"default\":\"triangle\",\"description\":\"Specify the topology of the generated model. Quad for smooth surfaces, Triangle for detailed geometry.\",\"enum\":[\"quad\",\"triangle\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"mode\",\"art_style\",\"topology\",\"target_polycount\",\"symmetry_mode\",\"should_remesh\",\"enable_pbr\",\"ta_pose\",\"enable_prompt_expansion\",\"texture_prompt\",\"texture_image\"]}}]}}', '2026-06-09 08:56:06.933', '2026-06-09 08:56:06.933', '2026-06-09 08:56:06.933');
