\",\"4k\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"resolution\",\"quality\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"openai/gpt-image-2/text-to-image\",\"name\":\"openai/gpt-image-2/text-to-image\",\"base_price\":0.06,\"formula\":\"{\\\"total_price\\\": (quality = \\\"low\\\" ? 10000 : (quality = \\\"high\\\" ? 220000 : 60000)) * (resolution = \\\"4k\\\" ? 3 : (resolution = \\\"2k\\\" ? 2 : 1))}\",\"description\":\"OpenAI\'s GPT Image 2 Text-to-Image generates high-quality images from natural-language prompts. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":9995,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/openai/gpt-image-2/text-to-image\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"description\":\"The aspect ratio of the generated image.\",\"enum\":[\"1:1\",\"1:2\",\"2:1\",\"1:3\",\"3:1\",\"2:3\",\"3:2\",\"3:4\",\"4:3\",\"4:5\",\"5:4\",\"9:16\",\"16:9\",\"9:21\",\"21:9\"],\"type\":\"string\",\"x-placeholder\":\"Select aspect ratio\"},\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"output_format\":{\"default\":\"png\",\"description\":\"The format of the output image.\",\"enum\":[\"png\",\"jpeg\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"quality\":{\"default\":\"medium\",\"description\":\"The quality of the generated image. Higher quality costs more.\",\"enum\":[\"low\",\"medium\",\"high\"],\"type\":\"string\"},\"resolution\":{\"default\":\"1k\",\"description\":\"The resolution of the output image.\",\"enum\":[\"1k\",\"2k\",\"4k\"],\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"aspect_ratio\",\"resolution\",\"quality\",\"output_format\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:05.541', '2026-06-09 08:56:05.541', '2026-06-09 08:56:05.541');
