omponent\":\"uploader\"},\"prompt\":{\"description\":\"Describe the scene, action, camera movement, and mood for the video.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The output video resolution.\",\"enum\":[\"480p\",\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"last_image\",\"aspect_ratio\",\"resolution\",\"duration\",\"enable_web_search\",\"generate_audio\"]}}]}}', '2026-06-09 08:56:05.575', '2026-06-09 08:56:05.575', '2026-06-09 08:56:05.575');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('c5b92dea-b968-4b07-a076-1276d6fa71cd', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/body-shake', 'video-effects/body-shake', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/body-shake\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single-person photos in realistic or anime style; 3. Best results when the person is fully visible from above the thighs; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/body-shake\",\"name\":\"video-effects/body-shake\",\"base_price\":0.2,\"formula\":\"\",\"description\":\"Turn photos into realistic body-shaking dance videos with natural motion and expressive emotion. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/body-shake\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports single-person photos in realistic or anime style; 3. Best results when the person is fully visible from above the thighs; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.346', '2026-06-09 08:56:07.346', '2026-06-09 08:56:07.346');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('c607b924-8d6d-4d5d-8a16-d93e4723c1e3', NULL, 'cmq0hadjp0000si8dckyresaj', 'bytedance/seedream-v5.0-lite/sequential', 'bytedance/seedream-v5.0-lite/sequential', 'IMAGE', 0.035, NULL, NULL, 3400, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedream-v5.0-lite/sequential\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"max_images\":{\"default\":1,\"description\":\"The maximum number of images that can be generated (up to 15). This value must align with the number of images specified in the prompt above.\",\"maximum\":15,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"output_format\":{\"description\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\",\"x-rows\":10,\"x-ui-component\":\"textarea\"},\"size\":{\"default\":\"2048*2048\",\"description\":\"Specify the width and height pixel values of the generated image.Total pixel value range: [2560*1440, 4096*4096]\",\"maximum\":8192,\"minimum\":1440,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"max_images\",\"output_format\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}', '{\"model_id\":\"bytedance/seedream-v5.0-lite/sequential\",\"name\":\"bytedance/seedream-v5.0-lite/sequential\",\"base_price\":0.035,\"formula\":\"{\\\"total_price\\\":base_price * max_images}\",\"description\":\"Seedream 5.0-lite is a state-of-art image model by Bytedance. Seedream 5.0-lite: Surpassing nano banana\\n\\nin every aspect.\",\"type\":\"text-to-image\",\"sort_order\":3400,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedream-v5.0-lite/sequential\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"max_images\":{\"default\":1,\"description\":\"The maximum number of images that can be generated (up to 15). This value must align with the number of images specified in the prompt above.\",\"maximum\":15,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"output_format\":{\"description\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\",\"x-rows\":10,\"x-ui-component\":\"textarea\"},\"size\":{\"default\":\"2048*2048\",\"description\":\"Specify the width and height pixel values of the generated image.Total pixel value range: [2560*1440, 4096*4096]\",\"maximum\":8192,\"minimum\":1440,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"max_images\",\"output_format\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:05.827', '2026-06-09 08:56:05.827', '2026-06-09 08:56:05.827');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('c609c4a9-4434-4139-a3ff-fe0a958ab86a', NULL, 'cmq0hadjp0000si8dckyresaj', 'pruna-ai/p-video/animate', 'pruna-ai/p-video/animate', 'VIDEO', 0.03, NULL, NULL, 10000, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/pruna-ai/p-video/animate\",\"request_schema\":{\"properties\":{\"fps\":{\"default\":\"original\",\"description\":\"Target output frame rate.\",\"enum\":[\"original\",\"24\",\"48\"],\"type\":\"string\"},\"image\":{\"description\":\"Reference image URL for the subject or scene to animate.\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"prompt\":{\"default\":\"Animate the reference subject using the motion from the source video.\",\"description\":\"Optional instruction describing how the image should follow the source video motion.\",\"type\":\"string\",\"x-rows\":3,\"x-ui-component\":\"textarea\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Output video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"save_audio\":{\"default\":true,\"description\":\"Save the output video with audio.\",\"type\":\"boolean\"},\"seed\":{\"default\":-1,\"description\":\"Random seed for reproducible generations.\",\"type\":\"integer\"},\"video\":{\"description\":\"Source motion video URL.\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"video/*\"}}},\"required\":[\"video\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"image\",\"prompt\",\"resolution\",\"fps\",\"save_audio\",\"seed\"]}}]}', '{\"model_id\":\"pruna-ai/p-video/animate\",\"name\":\"pruna-ai/p-video/animate\",\"base_price\":0.03,\"formula\":\"{\\\"total_price\\\": base_price * $max([1, $ceil($min([$number(get_duration_v3(video)), 20]))]) * (resolution = \\\"1080p\\\" ? 2 : 1)}\",\"description\":\"Pruna p-video-animate model running on RunPod.\",\"type\":\"motion-control\",\"sort_order\":10000,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/pruna-ai/p-video/animate\",\"request_schema\":{\"properties\":{\"fps\":{\"default\":\"original\",\"description\":\"Target output frame rate.\",\"enum\":[\"original\",\"24\",\"48\"],\"type\":\"string\"},\"image\":{\"description\":\"Reference image URL for the subject or scene to animate.\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"image/*\"}},\"prompt\":{\"default\":\"Animate the reference subject using the motion from the source video.\",\"description\":\"Optional instruction describing how the image should follow the source video motion.\",\"type\":\"string\",\"x-rows\":3,\"x-ui-component\":\"textarea\"},\"resolution\":{\"default\":\"720p\",\"description\":\"Output video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"save_audio\":{\"default\":true,\"description\":\"Save the output video with audio.\",\"type\":\"boolean\"},\"seed\":{\"default\":-1,\"description\":\"Random seed for reproducible generations.\",\"type\":\"integer\"},\"video\":{\"description\":\"Source motion video URL.\",\"type\":\"string\",\"x-ui-component\":\"uploader\",\"x-ui-component-props\":{\"accept\":\"video/*\"}}},\"required\":[\"video\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"image\",\"prompt\",\"resolution\",\"fps\",\"save_audio\",\"seed\"]}}]}}', '2026-06-09 08:56:05.400', '2026-06-09 08:56:05.400', '2026-06-09 08:56:05.400');
