\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/vidu/text-to-video-2.0\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[5,8],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"movement_amplitude\":{\"default\":\"auto\",\"description\":\"The movement amplitude of objects in the frame. Defaults to auto, accepted value: auto small medium large.\",\"enum\":[\"auto\",\"small\",\"medium\",\"large\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated media.\",\"enum\":[\"720p\"],\"type\":\"string\"},\"seed\":{\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"duration\",\"resolution\",\"movement_amplitude\",\"seed\"]}}]}}', '2026-06-09 08:56:06.249', '2026-06-09 08:56:06.249', '2026-06-09 08:56:06.249');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('c7853bf8-e9cf-4a54-86bd-5bc065f4d20a', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/ltx-2-19b/video-lora-trainer', 'wavespeed-ai/ltx-2-19b/video-lora-trainer', 'VIDEO', 0.35, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/ltx-2-19b/video-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"Upload a zip file containing videos with optional audio latents for audio-video LoRA training. Each text file should have the same name as the video file it corresponds to for captions.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing videos.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0002,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":32,\"maximum\":128,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":500,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":20000,\"minimum\":100,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"The phrase that will trigger the model to generate a video.\",\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}', '{\"model_id\":\"wavespeed-ai/ltx-2-19b/video-lora-trainer\",\"name\":\"wavespeed-ai/ltx-2-19b/video-lora-trainer\",\"base_price\":0.35,\"formula\":\"{\\\"total_price\\\":base_price * (steps / 100)}\",\"description\":\"Train custom LTX-2 Audio-Video LoRA models with synchronized audio-video generation support. Train action, motion, and video effect models. Upload a ZIP file containing videos with optional audio to start!\",\"type\":\"training\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/ltx-2-19b/video-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"Upload a zip file containing videos with optional audio latents for audio-video LoRA training. Each text file should have the same name as the video file it corresponds to for captions.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing videos.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0002,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":32,\"maximum\":128,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":500,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":20000,\"minimum\":100,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"The phrase that will trigger the model to generate a video.\",\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}}', '2026-06-09 08:56:06.870', '2026-06-09 08:56:06.870', '2026-06-09 08:56:06.870');
