INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('c848e35c-7be8-4263-a5c2-6a00ac6cdfe3', NULL, 'cmq0hadjp0000si8dckyresaj', 'tripo3d/h3.1/multiview-to-3d', 'tripo3d/h3.1/multiview-to-3d', '3D', 0.1, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/tripo3d/h3.1/image-to-3d\",\"request_schema\":{\"properties\":{\"auto_size\":{\"default\":false,\"description\":\"Auto-scale the model to real-world dimensions.\",\"type\":\"boolean\"},\"face_limit\":{\"description\":\"Target number of faces for the generated mesh. If not set, the model adaptively determines the count.\",\"maximum\":2000000,\"minimum\":1000,\"type\":\"integer\",\"x-hidden\":true,\"x-ui-component\":\"slider\"},\"geometry_quality\":{\"default\":\"standard\",\"description\":\"Quality level for geometry.\",\"enum\":[\"standard\",\"detailed\"],\"title\":\"Geometry Quality\",\"type\":\"string\"},\"images\":{\"description\":\"2 to 4 image URLs of the same object from different angles. Order: [front, left, back, right]. Front view is required.\",\"items\":{\"type\":\"string\"},\"maxItems\":4,\"minItems\":2,\"type\":\"array\"},\"model_seed\":{\"description\":\"Seed for geometry generation reproducibility.\",\"type\":\"integer\",\"x-hidden\":true},\"orientation\":{\"default\":\"default\",\"description\":\"Model orientation. \'align_image\' auto-rotates to match the input image.\",\"enum\":[\"default\",\"align_image\"],\"type\":\"string\"},\"pbr\":{\"default\":true,\"description\":\"Whether to generate PBR (Physically Based Rendering) materials. If true, texture is also enabled.\",\"type\":\"boolean\"},\"quad\":{\"default\":false,\"description\":\"Generate quad (4-sided) mesh topology instead of triangles.\",\"type\"