"},\"geometry_quality\":{\"default\":\"standard\",\"description\":\"Quality level for geometry.\",\"enum\":[\"standard\",\"detailed\"],\"title\":\"Geometry Quality\",\"type\":\"string\"},\"images\":{\"description\":\"2 to 4 image URLs of the same object from different angles. Order: [front, left, back, right]. Front view is required.\",\"items\":{\"type\":\"string\"},\"maxItems\":4,\"minItems\":2,\"type\":\"array\"},\"model_seed\":{\"description\":\"Seed for geometry generation reproducibility.\",\"type\":\"integer\",\"x-hidden\":true},\"orientation\":{\"default\":\"default\",\"description\":\"Model orientation. \'align_image\' auto-rotates to match the input image.\",\"enum\":[\"default\",\"align_image\"],\"type\":\"string\"},\"pbr\":{\"default\":true,\"description\":\"Whether to generate PBR (Physically Based Rendering) materials. If true, texture is also enabled.\",\"type\":\"boolean\"},\"quad\":{\"default\":false,\"description\":\"Generate quad (4-sided) mesh topology instead of triangles.\",\"type\":\"boolean\"},\"texture\":{\"default\":true,\"description\":\"Whether to generate textures for the model.\",\"type\":\"boolean\"},\"texture_alignment\":{\"default\":\"original_image\",\"description\":\"How textures are aligned. \'original_image\' aligns to input image, \'geometry\' aligns to generated geometry.\",\"enum\":[\"original_image\",\"geometry\"],\"type\":\"string\"},\"texture_quality\":{\"default\":\"standard\",\"description\":\"Quality level for textures. \'detailed\' produces higher-resolution textures.\",\"enum\":[\"standard\",\"detailed\"],\"type\":\"string\"},\"texture_seed\":{\"description\":\"Seed for texture generation reproducibility.\",\"type\":\"integer\",\"x-hidden\":true}},\"required\":[\"images\"],\"type\":\"object\",\"x-order-properties\":[\"images\",\"texture\",\"pbr\",\"texture_quality\",\"geometry_quality\",\"texture_alignment\",\"auto_size\",\"orientation\",\"quad\",\"face_limit\",\"model_seed\",\"texture_seed\"]}}]}}', '2026-06-09 08:56: