 Text to Video generation\",\"format\":\"float\",\"maximum\":2,\"minimum\":0.8,\"step\":0.1,\"type\":\"number\",\"x-ui-component\":\"slider\"}},\"required\":[\"video\",\"text\",\"voice_id\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"text\",\"voice_id\",\"voice_language\",\"voice_speed\"]}}]}', '{\"model_id\":\"kwaivgi/kling-lipsync/text-to-video\",\"name\":\"kwaivgi/kling-lipsync/text-to-video\",\"base_price\":0.14,\"formula\":\"\",\"description\":\"Kling TextToVideo by Kwaivgi creates videos with lifelike lip movements that precisely sync to input text for natural speaking visuals. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"digital-human\",\"sort_order\":1950,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/kwaivgi/kling-lipsync/text-to-video\",\"request_schema\":{\"properties\":{\"text\":{\"description\":\"Text Content for Lip-Sync Video Generation. Max 120 characters.\",\"type\":\"string\"},\"video\":{\"description\":\"The URL of the video file for generating synchronized lip movements. Video files support .mp4/.mov, file size does not exceed 100MB, video length does not exceed 10s and is not shorter than 2s, only 720p and 1080p are supported, length and width dimensions should both be between 720px and 1920px.\",\"type\":\"string\"},\"voice_id\":{\"default\":\"genshin_klee2\",\"description\":\"Voice ID to use for speech synthesis\",\"enum\":[\"genshin_vindi2\",\"zhinen_xuesheng\",\"AOT\",\"ai_shatang\",\"genshin_klee2\",\"genshin_kirara\",\"ai_kaiya\",\"oversea_male1\",\"ai_chenjiahao_712\",\"girlfriend_4_speech02\",\"chat1_female_new-3\",\"chat_0407_5-1\",\"cartoon-boy-07\",\"uk_boy1\",\"cartoon-girl-01\",\"PeppaPig_platform\",\"ai_huangzhong_712\",\"ai_huangyaoshi_712\",\"ai_laoguowang_712\",\"chengshu_jiejie\",\"you_pingjing\",\"calm_story1\",\"uk_man2\",\"laopopo_speech02\",\"heainainai_speech02\"],\