esolution\":{\"default\":\"480p\",\"description\":\"The resolution of the output video.\",\"enum\":[\"480p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"video\":{\"description\":\"URL to the video to use as the input for the generation.\",\"type\":\"string\"}},\"required\":[\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"resolution\",\"seed\"]}}]}}', '2026-06-09 08:56:06.473', '2026-06-09 08:56:06.473', '2026-06-09 08:56:06.473');
