ame\":\"bytedance/seedream-v4.5/sequential\",\"base_price\":0.04,\"formula\":\"{\\\"total_price\\\":base_price * max_images}\",\"description\":\"Seedream 4.5 Sequential generates multi-image sets with consistent characters and objects, unifying palette, lighting, and style across all outputs. Supports up to 4K results for campaigns, storyboards, and product lines. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":3500,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedream-v4.5/sequential\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"max_images\":{\"default\":1,\"description\":\"The maximum number of images that can be generated (up to 15). This value must align with the number of images specified in the prompt above.\",\"maximum\":15,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\",\"x-rows\":10,\"x-ui-component\":\"textarea\"},\"size\":{\"default\":\"2048*2048\",\"description\":\"Specify the width and height pixel values of the generated image.\",\"maximum\":8192,\"minimum\":512,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"max_images\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:05.822', '2026-06-09 08:56:05.822', '2026-06-09 08:56:05.822');
