es to generate.\",\"maximum\":4,\"minimum\":1,\"type\":\"integer\"},\"output_format\":{\"default\":\"jpeg\",\"description\":\"The format of the output image.\",\"enum\":[\"jpeg\",\"png\",\"webp\"],\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"},\"strength\":{\"default\":0.8,\"description\":\"Strength indicates extent to transform the reference image.\",\"maximum\":1,\"minimum\":0,\"step\":0.01,\"type\":\"number\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"mask_image\",\"strength\",\"size\",\"num_images\",\"seed\",\"output_format\",\"enable_base64_output\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:07.731', '2026-06-09 08:56:07.731', '2026-06-09 08:56:07.731');
