INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('de9818bd-e82e-462c-8d99-cb9ccb55481b', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/wan-2.2-i2v-lora-trainer', 'wavespeed-ai/wan-2.2-i2v-lora-trainer', 'VIDEO', 5, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/wan-2.2-i2v-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"To train a WAN I2V LoRA, you need to upload a zip file containing videos. In addition to videos the archive can contain text files with captions. Each text file should have the same name as the video file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing videos.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0002,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":32,\"maximum\":128,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":100,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":1500,\"minimum\":50,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"The phrase that will trigger the model to generate an video.\",\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}', '{\"model_id\":\"wavespeed-ai/wan-2.2-i2v-lora-trainer\",\"name\":\"wavespeed-ai/wan-2.2-i2v-lora-trainer\",\"base_price\":5,\"formula\":\"{\\\"total_price\\\":base_price * (steps / 100)}\",\"description\":\"Train custom Wan 2.2 I2V LoRA models 10x faster. Action training, motion training, video efect training. From concept to model in minutes, not hours. Upload a ZIP file containing videos to start!\",\"type\":\"training\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/wan-2.2-i2v-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"To train a WAN I2V LoRA, you need to upload a zip file containing videos. In addition to videos the archive can contain text files with captions. Each text file should have the same name as the video file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing videos.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0002,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":32,\"maximum\":128,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":100,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":1500,\"minimum\":50,\"step\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"The phrase that will trigger the model to generate an video.\",\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}}', '2026-06-09 08:56:07.371', '2026-06-09 08:56:07.371', '2026-06-09 08:56:07.371');
