u\",\"sv\",\"sw\",\"ta\",\"te\",\"tg\",\"th\",\"tk\",\"tl\",\"tr\",\"tt\",\"uk\",\"ur\",\"uz\",\"vi\",\"yi\",\"yo\",\"zh\",\"yue\"],\"type\":\"string\"},\"prompt\":{\"description\":\"An optional text to provide as a prompt to guide the model\'s style or continue a previous audio segment. The prompt should be in the same language as the audio.\",\"type\":\"string\",\"x-placeholder\":\"Enter a prompt to guide transcription\"}},\"required\":[\"audio\"],\"type\":\"object\",\"x-order-properties\":[\"audio\",\"language\",\"prompt\",\"enable_sync_mode\"]}}]}', '{\"model_id\":\"wavespeed-ai/openai-whisper-turbo\",\"name\":\"wavespeed-ai/openai-whisper-turbo\",\"base_price\":0.0007,\"formula\":\"{\\\"total_price\\\": $max([1, $number(get_duration_v3(audio))]) * base_price}\",\"description\":\"Accurate speech-to-text with OpenAI Whisper Large v3 Turbo: multilingual transcripts with auto language detection and punctuation. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"speech-to-text\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/openai-whisper\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"Audio file to transcribe. Provide an HTTPS URL or upload a file (MP3, WAV, FLAC up to 60 minutes).\",\"type\":\"string\",\"x-accept\":\"audio/mpeg,audio/mp3,audio/wav,audio/x-wav,audio/flac\",\"x-placeholder\":\"Upload or link to an audio file\",\"x-ui-component\":\"uploader\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"language\":{\"default\":\"auto\",\"description\":\"Language spoken in the audio. Set to \'auto\' for automatic language detection (default).\",\"enum\":[\"auto\",\"af\",\"am\",\"ar\",\"as\",\"az\",\"ba\",\"be\",\"bg\",\"bn\",\"bo\",\"br\",\"bs\",\"ca\",\"cs\",\"cy\",\"da\",\"de\",\"el\",\"en\",\"es\",\"et\",\"eu\",\"fa\",\"fi\",\"fo\",\"fr\",\"gl\",\"gu\",\"ha\",\"haw\",\"he\",\"hi\",\"hr\",\"ht\",\"hu\",\"hy\",\"id\",\"is\",\"it\",\"ja\",\"jw\",\"ka\",\"kk\",\"km\",\"kn\",\"ko\",\"la\",\"lb\",\"ln\",\"lo\",\"lt\",\"lv\",\"mg\",\"mi\",\"mk\",\"ml\",\"mn\",\"mr\",\"ms\",\"mt\",\"my\",\"ne\",\"nl\",\"nn\",\"no\",\"oc\",\"pa\",\"pl\",\"ps\",\"pt\",\"ro\",\"ru\",\"sa\",\"sd\",\"si\",\"sk\",\"sl\",\"sn\",\"so\",\"sq\",\"sr\",\"su\",\"sv\",\"sw\",\"ta\",\"te\",\"tg\",\"th\",\"tk\",\"tl\",\"tr\",\"tt\",\"uk\",\"ur\",\"uz\",\"vi\",\"yi\",\"yo\",\"zh\",\"yue\"],\"type\":\"string\"},\"prompt\":{\"description\":\"An optional text to provide as a prompt to guide the model\'s style or continue a previous audio segment. The prompt should be in the same language as the audio.\",\"type\":\"string\",\"x-placeholder\":\"Enter a prompt to guide transcription\"}},\"required\":[\"audio\"],\"type\":\"object\",\"x-order-properties\":[\"audio\",\"language\",\"prompt\",\"enable_sync_mode\"]}}]}}', '2026-06-09 08:56:06.373', '2026-06-09 08:56:06.373', '2026-06-09 08:56:06.373');
