,\"size\",\"num_inference_steps\",\"duration\",\"guidance_scale\",\"flow_shift\",\"seed\"]}}]}}', '2026-06-09 08:56:07.720', '2026-06-09 08:56:07.720', '2026-06-09 08:56:07.720');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('e0560c38-c9b4-4ddd-9cf9-43aadcc84c3a', NULL, 'cmq0hadjp0000si8dckyresaj', 'kwaivgi/kling-lipsync/audio-to-video', 'kwaivgi/kling-lipsync/audio-to-video', 'DIGITAL-HUMAN', 0.15, NULL, NULL, 2000, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/kwaivgi/kling-lipsync/audio-to-video\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"The URL pointing to the audio file that will be used for generating synchronized lip movements. Supported audio file formats: .mp3/.wav/.m4a/.aac, with a maximum file size of 5MB.\",\"type\":\"string\"},\"video\":{\"description\":\"The URL of the video file for generating synchronized lip movements. Video files support .mp4/.mov, file size does not exceed 100MB, video length does not exceed 10s and is not shorter than 2s, only 720p and 1080p are supported, length and width dimensions should both be between 720px and 1920px.\",\"type\":\"string\"}},\"required\":[\"audio\",\"video\"],\"type\":\"object\",\"x-order-properties\":[\"audio\",\"video\"]}}]}', '{\"model_id\":\"kwaivgi/kling-lipsync/audio-to-video\",\"name\":\"kwaivgi/kling-lipsync/audio-to-video\",\"base_price\":0.15,\"formula\":\"{\\\"total_price\\\": $max([5, $min([$number(get_duration_v3(audio)), 600])]) / 5 * base_price}\",\"description\":\"Kling LipSync converts audio into talking head video by generating lifelike lip movements perfectly synced to the input audio. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"digital-human\",\"sort_order\":2000,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/kwaivgi/kling-lipsync/audio-to-video\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"The URL pointing to the audio file that will be used for generating synchronized lip movements. Supported audio file formats: .mp3/.wav/.m4a/.aac, with a maximum file size of 5MB.\",\"type\":\"string\"},\"video\":{\"description\":\"The URL of the video file for generating synchronized lip movements. Video files support .mp4/.mov, file size does not exceed 100MB, video length does not exceed 10s and is not shorter than 2s, only 720p and 1080p are supported, length and width dimensions should both be between 720px and 1920px.\",\"type\":\"string\"}},\"required\":[\"audio\",\"video\"],\"type\":\"object\",\"x-order-properties\":[\"audio\",\"video\"]}}]}}', '2026-06-09 08:56:05.993', '2026-06-09 08:56:05.993', '2026-06-09 08:56:05.993');
