INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('e2e46691-51dc-47c9-a5ca-c11c54681609', NULL, 'cmq0hadjp0000si8dckyresaj', 'alibaba/wan-2.5/image-to-video-fast', 'alibaba/wan-2.5/image-to-video-fast', 'VIDEO', 0.34, NULL, NULL, 5700, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.5/image-to-video-fast\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"Audio URL to guide generation (optional).\",\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[3,4,5,6,7,8,9,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"If set to true, the prompt optimizer will be enabled.\",\"type\":\"boolean\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated media.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"image\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"audio\",\"negative_prompt\",\"resolution\",\"duration\",\"enable_prompt_expansion\",\"seed\"]}}]}', '{\"model_id\":\"alibaba/wan-2.5/image-to-video-fast\",\"name\":\"alibaba/wan-2.5/image-to-video-fast\",\"base_price\":0.34,\"formula\":\"{\\\"total_price\\\": base_price * $number(duration) / 5 * ((resolution = \\\"720p\\\") ? 1 : (resolution = \\\"1080p\\\") ?  1.5 : 0.5)}\",\"description\":\"Alibaba WAN 2.5 Fast converts text or images into synchronized-audio videos in 480p, 720p, or 1080p, offering faster, more affordable generation compared to Google Veo3. REST API, no coldstarts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":5700,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/alibaba/wan-2.5/image-to-video-fast\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"Audio URL to guide generation (optional).\",\"type\":\"string\"},\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[3,4,5,6,7,8,9,10],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"enable_prompt_expansion\":{\"default\":false,\"description\":\"If set to true, the prompt optimizer will be enabled.\",\"type\":\"boolean\"},\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The resolution of the generated media.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"image\",\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"audio\",\"negative_prompt\",\"resolution\",\"duration\",\"enable_prompt_expansion\",\"seed\"]}}]}}', '2026-06-09 08:56:05.710', '2026-06-09 08:56:05.710', '2026-06-09 08:56:05.710');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('e32497c6-0e66-4bfc-b809-fe15cd050489', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/flux-2-dev/text-to-image', 'wavespeed-ai/flux-2-dev/text-to-image', 'IMAGE', 0.012, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-2-dev/text-to-image\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"seed\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"wavespeed-ai/flux-2-dev/text-to-image\",\"name\":\"wavespeed-ai/flux-2-dev/text-to-image\",\"base_price\":0.012,\"formula\":\"\",\"description\":\"FLUX.2 [dev] from Black Forest Labs delivers fast, studio-quality text-to-image generation with enhanced realism, crisper text rendering, and native editing for rapid iteration. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-2-dev/text-to-image\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"seed\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.605', '2026-06-09 08:56:06.605', '2026-06-09 08:56:06.605');
