ing\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"num_images\",\"seed\",\"prompt_optimizer\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"minimax/image-01/text-to-image\",\"name\":\"minimax/image-01/text-to-image\",\"base_price\":0.0035,\"formula\":\"{\\\"total_price\\\":base_price * num_images}\",\"description\":\"Minimax Image 01 to generate images from text input.. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/minimax/image-01/text-to-image\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"num_images\":{\"default\":1,\"description\":\"The number of images to generate.\",\"maximum\":9,\"minimum\":1,\"type\":\"integer\"},\"prompt\":{\"description\":\"Text description of the image, max length 1500 characters.\",\"type\":\"string\",\"x-rows\":3,\"x-ui-component\":\"textarea\"},\"prompt_optimizer\":{\"default\":false,\"description\":\"Enable automatic optimization of prompt. \",\"type\":\"boolean\"},\"seed\":{\"description\":\"Random seed. Using the same seed and parameters produces reproducible images. If not provided, a random seed is generated for each image.\",\"type\":\"integer\",\"x-hidden\":true},\"size\":{\"default\":\"1024*1024\",\"description\":\"Specify the width and height pixel values of the generated image. Must be divisible by 8\",\"maximum\":2048,\"minimum\":512,\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"num_images\",\"seed\",\"prompt_optimizer\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.918', '2026-06-09 08:56:06.918', '2026-06-09 08:56:06.918');
