"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_timestamps\":{\"default\":false,\"description\":\"Enable to generate word-level timestamps for the transcription. Note: This may increase processing time.\",\"type\":\"boolean\"},\"language\":{\"default\":\"auto\",\"description\":\"Language spoken in the audio. Set to \'auto\' for automatic language detection (default).\",\"enum\":[\"auto\",\"af\",\"am\",\"ar\",\"as\",\"az\",\"ba\",\"be\",\"bg\",\"bn\",\"bo\",\"br\",\"bs\",\"ca\",\"cs\",\"cy\",\"da\",\"de\",\"el\",\"en\",\"es\",\"et\",\"eu\",\"fa\",\"fi\",\"fo\",\"fr\",\"gl\",\"gu\",\"ha\",\"haw\",\"he\",\"hi\",\"hr\",\"ht\",\"hu\",\"hy\",\"id\",\"is\",\"it\",\"ja\",\"jw\",\"ka\",\"kk\",\"km\",\"kn\",\"ko\",\"la\",\"lb\",\"ln\",\"lo\",\"lt\",\"lv\",\"mg\",\"mi\",\"mk\",\"ml\",\"mn\",\"mr\",\"ms\",\"mt\",\"my\",\"ne\",\"nl\",\"nn\",\"no\",\"oc\",\"pa\",\"pl\",\"ps\",\"pt\",\"ro\",\"ru\",\"sa\",\"sd\",\"si\",\"sk\",\"sl\",\"sn\",\"so\",\"sq\",\"sr\",\"su\",\"sv\",\"sw\",\"ta\",\"te\",\"tg\",\"th\",\"tk\",\"tl\",\"tr\",\"tt\",\"uk\",\"ur\",\"uz\",\"vi\",\"yi\",\"yo\",\"zh\",\"yue\"],\"type\":\"string\"},\"prompt\":{\"description\":\"An optional text to provide as a prompt to guide the model\'s style or continue a previous audio segment. The prompt should be in the same language as the audio.\",\"type\":\"string\",\"x-placeholder\":\"Enter a prompt to guide transcription\"},\"task\":{\"default\":\"transcribe\",\"description\":\"The task to perform. \'transcribe\' to the source language or \'translate\' to English.\",\"enum\":[\"transcribe\",\"translate\"],\"type\":\"string\"}},\"required\":[\"audio\"],\"type\":\"object\",\"x-order-properties\":[\"audio\",\"language\",\"task\",\"enable_timestamps\"