INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('ea918452-1bd2-4a56-9219-75fa15595ae8', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/infinitetalk-fast/multi', 'wavespeed-ai/infinitetalk-fast/multi', 'DIGITAL-HUMAN', 0.075, NULL, NULL, 1900, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/infinitetalk-fast/multi\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"left_audio\":{\"description\":\"The audio of the persion on the left for generating the output.\",\"type\":\"string\",\"x-accept\":\"audio/*\",\"x-ui-component\":\"uploader\"},\"order\":{\"default\":\"meanwhile\",\"description\":\"The order of the two audio sources in the output video, \\\"meanwhile\\\" means both audio sources will play at the same time, \\\"left_right\\\" means the left audio will play first then the right audio will play, \\\"right_left\\\" means the right audio will play first then the left audio will play.\",\"enum\":[\"meanwhile\",\"left_right\",\"right_left\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"right_audio\":{\"description\":\"The audio of the persion on the right for generating the output.\",\"type\":\"string\",\"x-accept\":\"audio/*\",\"x-ui-component\":\"uploader\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"left_audio\",\"right_audio\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"left_audio\",\"right_audio\",\"prompt\",\"order\",\"seed\"]}}]}', '{\"model_id\":\"wavespeed-ai/infinitetalk-fast/multi\",\"name\":\"wavespeed-ai/infinitetalk-fast/multi\",\"base_price\":0.075,\"formula\":\"{\\\"total_price\\\": $max([5, $min([order = \\\"meanwhile\\\" ? $max([$number(get_duration_v3(left_audio)), $number(get_duration_v3(right_audio))]) : ($number(get_duration_v3(left_audio)) + $number(get_duration_v3(right_audio))), 600])]) / 5 * base_price}\",\"description\":\"InfiniteTalk fast multi converts a single image and two audio inputs into multi-character talking or singing videos. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"digital-human\",\"sort_order\":1900,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/infinitetalk-fast/multi\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"The image for generating the output.\",\"type\":\"string\"},\"left_audio\":{\"description\":\"The audio of the persion on the left for generating the output.\",\"type\":\"string\",\"x-accept\":\"audio/*\",\"x-ui-component\":\"uploader\"},\"order\":{\"default\":\"meanwhile\",\"description\":\"The order of the two audio sources in the output video, \\\"meanwhile\\\" means both audio sources will play at the same time, \\\"left_right\\\" means the left audio will play first then the right audio will play, \\\"right_left\\\" means the right audio will play first then the left audio will play.\",\"enum\":[\"meanwhile\",\"left_right\",\"right_left\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"right_audio\":{\"description\":\"The audio of the persion on the right for generating the output.\",\"type\":\"string\",\"x-accept\":\"audio/*\",\"x-ui-component\":\"uploader\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"}},\"required\":[\"left_audio\",\"right_audio\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\",\"left_audio\",\"right_audio\",\"prompt\",\"order\",\"seed\"]}}]}}', '2026-06-09 08:56:06.006', '2026-06-09 08:56:06.006', '2026-06-09 08:56:06.006');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('eaefa7aa-1eec-40bf-8912-2284f5d4e3b1', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/z-image-lora-trainer', 'wavespeed-ai/z-image-lora-trainer', 'IMAGE', 1.25, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/z-image-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"URL to zip archive with images. Try to use at least 4 images in general the more the better.\\n\\n        In addition to images the archive can contain text files with captions. Each text file should have the same name as the image file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing images.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0001,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":16,\"maximum\":64,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":1000,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":10000,\"minimum\":500,\"step\":10,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"Trigger word to be used in the captions. If None, a trigger word will not be used.\\n        If no captions are provide the trigger_word will be used instead of captions. If captions are the trigger word will not be used.\",\"nullable\":true,\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}', '{\"model_id\":\"wavespeed-ai/z-image-lora-trainer\",\"name\":\"wavespeed-ai/z-image-lora-trainer\",\"base_price\":1.25,\"formula\":\"{\\\"total_price\\\":base_price * (steps / 1000)}\",\"description\":\"Z-Image-LoRA-Trainer – train custom image LoRA models from your own dataset, with zip uploads, auto-tuned defaults and fast iteration for brand, character or IP looks. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"training\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/z-image-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"URL to zip archive with images. Try to use at least 4 images in general the more the better.\\n\\n        In addition to images the archive can contain text files with captions. Each text file should have the same name as the image file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing images.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0001,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":16,\"maximum\":64,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":1000,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":10000,\"minimum\":500,\"step\":10,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"Trigger word to be used in the captions. If None, a trigger word will not be used.\\n        If no captions are provide the trigger_word will be used instead of captions. If captions are the trigger word will not be used.\",\"nullable\":true,\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}}', '2026-06-09 08:56:06.680', '2026-06-09 08:56:06.680', '2026-06-09 08:56:06.680');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('eb50135f-688e-41d1-b6b7-9a7c4d5a8684', NULL, 'cmq0hadjp0000si8dckyresaj', 'video-effects/zoom-in-fast', 'video-effects/zoom-in-fast', 'VIDEO', 0.2, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/zoom-in-fast\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports product images, scene images, and portraits; 3. Best for medium or wide shots of products and scenes; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}', '{\"model_id\":\"video-effects/zoom-in-fast\",\"name\":\"video-effects/zoom-in-fast\",\"base_price\":0.2,\"formula\":\"\",\"description\":\"Create dramatic AI zoom-in videos from photos with smooth camera motion & cinematic style—ideal for intros, reveals and social posts. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"video-effects\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/video-effects/zoom-in-fast\",\"request_schema\":{\"properties\":{\"image\":{\"description\":\"An image to be used as the start frame of the generated video. Requirements: 1. Only accepts 1 image; 2. Supports product images, scene images, and portraits; 3. Best for medium or wide shots of products and scenes; 4. Images can be provided via URLs or Base64 encode; 5. Supported codecs: PNG, JPEG, JPG, WebP; 6. Image aspect ratio must be less than 1:4 or 4:1; 7. Maximum file size: 50MB; 8. Base64 decode length must be under 50MB with appropriate content type string.\",\"type\":\"string\"}},\"required\":[\"image\"],\"type\":\"object\",\"x-order-properties\":[\"image\"]}}]}}', '2026-06-09 08:56:07.102', '2026-06-09 08:56:07.102', '2026-06-09 08:56:07.102');
