:{\"description\":\"Describe the scene, action, camera movement, and mood for the video.\",\"type\":\"string\"},\"resolution\":{\"default\":\"720p\",\"description\":\"The output video resolution.\",\"enum\":[\"720p\",\"1080p\"],\"type\":\"string\",\"x-ui-component\":\"select\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"last_image\",\"aspect_ratio\",\"resolution\",\"duration\",\"enable_web_search\",\"generate_audio\"]}}]}}', '2026-06-09 08:56:05.681', '2026-06-09 08:56:05.681', '2026-06-09 08:56:05.681');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('ecc0a659-4e73-4f87-b4c8-9f0b01e292b4', NULL, 'cmq0hadjp0000si8dckyresaj', 'midjourney/text-to-image', 'midjourney/text-to-image', 'IMAGE', 0.1, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/midjourney/text-to-image\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"1:1\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"9:16\",\"16:9\",\"4:3\",\"3:4\",\"2:3\",\"3:2\",\"9:21\",\"21:9\"],\"type\":\"string\",\"x-placeholder\":\"Select Aspect Ratio\",\"x-ui-component\":\"select\"},\"chaos\":{\"default\":0,\"description\":\"Use the chaos parameter to add variety to your image results (0-100). Higher values produce more unusual and unexpected results.\",\"maximum\":100,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_base64_output\":{\"default\":false,\"description\":\"The random seed to use for the generation.\",\"disabled\":true,\"type\":\"boolean\"},\"hd\":{\"default\":false,\"description\":\"Enable native 2k HD generation for version 8.1.\",\"type\":\"boolean\"},\"niji\":{\"default\":\"close\",\"description\":\"Use the Niji model focused on anime and Eastern aesthetics.\",\"enum\":[\"0\",\"5\",\"6\",\"7\",\"close\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"prompt\":{\"description\":\"The text prompt describing the image you want to generate.\",\"type\":\"string\"},\"quality\":{\"default\":1,\"description\":\"Use the quality parameter to control image detail and processing time.\",\"enum\":[0.25,0.5,1,2],\"type\":\"number\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"Use the seed parameter for testing and experimentation. Use the same seed and prompt to get similar results.\",\"type\":\"integer\"},\"sref\":{\"description\":\"URL of the image to use as a reference for the image generation.\",\"type\":\"string\",\"x-accept\":\"image/*\",\"x-ui-component\":\"uploader\"},\"stylize\":{\"default\":0,\"description\":\"Use the stylize parameter to control the artistic style in the image (0-1000).\",\"maximum\":1000,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"version\":{\"default\":\"8.1\",\"description\":\"Use the version parameter to explore and switch between Midjourney model versions. Version 8.1 supports optional HD generation.\",\"enum\":[\"6\",\"6.1\",\"7\",\"8.1\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"weird\":{\"default\":0,\"description\":\"Use the weird parameter to make your images quirky and unconventional (0-3000).\",\"maximum\":3000,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"sref\",\"aspect_ratio\",\"quality\",\"stylize\",\"chaos\",\"weird\",\"version\",\"hd\",\"niji\",\"seed\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"midjourney/text-to-image\",\"name\":\"midjourney/text-to-image\",\"base_price\":0.1,\"formula\":\"{\\\"total_price\\\": base_price * ((version = \\\"8.1\\\" and hd) ? 1.5 : 1)}\",\"description\":\"Create high-quality, artistic images from text prompts using Midjourney\'s renowned creative interpretation. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"text-to-image\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/midjourney/text-to-image\",\"request_schema\":{\"properties\":{\"aspect_ratio\":{\"default\":\"1:1\",\"description\":\"The aspect ratio of the generated media.\",\"enum\":[\"1:1\",\"9:16\",\"16:9\",\"4:3\",\"3:4\",\"2:3\",\"3:2\",\"9:21\",\"21:9\"],\"type\":\"string\",\"x-placeholder\":\"Select Aspect Ratio\",\"x-ui-component\":\"select\"},\"chaos\":{\"default\":0,\"description\":\"Use the chaos parameter to add variety to your image results (0-100). Higher values produce more unusual and unexpected results.\",\"maximum\":100,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"enable_base64_output\":{\"default\":false,\"description\":\"The random seed to use for the generation.\",\"disabled\":true,\"type\":\"boolean\"},\"hd\":{\"default\":false,\"description\":\"Enable native 2k HD generation for version 8.1.\",\"type\":\"boolean\"},\"niji\":{\"default\":\"close\",\"description\":\"Use the Niji model focused on anime and Eastern aesthetics.\",\"enum\":[\"0\",\"5\",\"6\",\"7\",\"close\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"prompt\":{\"description\":\"The text prompt describing the image you want to generate.\",\"type\":\"string\"},\"quality\":{\"default\":1,\"description\":\"Use the quality parameter to control image detail and processing time.\",\"enum\":[0.25,0.5,1,2],\"type\":\"number\",\"x-ui-component\":\"select\"},\"seed\":{\"default\":-1,\"description\":\"Use the seed parameter for testing and experimentation. Use the same seed and prompt to get similar results.\",\"type\":\"integer\"},\"sref\":{\"description\":\"URL of the image to use as a reference for the image generation.\",\"type\":\"string\",\"x-accept\":\"image/*\",\"x-ui-component\":\"uploader\"},\"stylize\":{\"default\":0,\"description\":\"Use the stylize parameter to control the artistic style in the image (0-1000).\",\"maximum\":1000,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"version\":{\"default\":\"8.1\",\"description\":\"Use the version parameter to explore and switch between Midjourney model versions. Version 8.1 supports optional HD generation.\",\"enum\":[\"6\",\"6.1\",\"7\",\"8.1\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"weird\":{\"default\":0,\"description\":\"Use the weird parameter to make your images quirky and unconventional (0-3000).\",\"maximum\":3000,\"minimum\":0,\"type\":\"integer\",\"x-ui-component\":\"slider\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"sref\",\"aspect_ratio\",\"quality\",\"stylize\",\"chaos\",\"weird\",\"version\",\"hd\",\"niji\",\"seed\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.417', '2026-06-09 08:56:06.417', '2026-06-09 08:56:06.417');
