INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('eda9a9f0-47f4-4a2a-9cc5-39a9c3e7f0b6', NULL, 'cmq0hadjp0000si8dckyresaj', 'sync/lipsync-3', 'sync/lipsync-3', 'DIGITAL-HUMAN', 0.134, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/sync/lipsync-3\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"The audio to be used for generation\",\"type\":\"string\"},\"sync_mode\":{\"default\":\"cut_off\",\"description\":\"Defines how to handle duration mismatches between video and audio inputs. See the Media Content Tips guide https://docs.sync.so/compatibility-and-tips/media-content-tips#sync-mode-options for a brief overview, or the SyncMode enum below for detailed explanations of each option.\",\"enum\":[\"bounce\",\"loop\",\"cut_off\",\"silence\",\"remap\"],\"type\":\"string\"},\"video\":{\"description\":\"The video to be used for generation\",\"type\":\"string\"}},\"required\":[\"audio\",\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"audio\",\"sync_mode\"]}}]}', '{\"model_id\":\"sync/lipsync-3\",\"name\":\"sync/lipsync-3\",\"base_price\":0.134,\"formula\":\"{\\\"total_price\\\": $number(get_duration_v3(video)) * $number(base_price)}\",\"description\":\"Sync Lipsync 3 synchronizes lip movements in any video to supplied audio using zero-shot lip-sync technology.\",\"type\":\"digital-human\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/sync/lipsync-3\",\"request_schema\":{\"properties\":{\"audio\":{\"description\":\"The audio to be used for generation\",\"type\":\"string\"},\"sync_mode\":{\"default\":\"cut_off\",\"description\":\"Defines how to handle duration mismatches between video and audio inputs. See the Media Content Tips guide https://docs.sync.so/compatibility-and-tips/media-content-tips#sync-mode-options for a brief overview, or the SyncMode enum below for detailed explanations of each option.\",\"enum\":[\"bounce\",\"loop\",\"cut_off\",\"silence\",\"remap\"],\"type\":\"string\"},\"video\":{\"description\":\"The video to be used for generation\",\"type\":\"string\"}},\"required\":[\"audio\",\"video\"],\"type\":\"object\",\"x-order-properties\":[\"video\",\"audio\",\"sync_mode\"]}}]}}', '2026-06-09 08:56:07.353', '2026-06-09 08:56:07.353', '2026-06-09 08:56:07.353');
