INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('f7d8a1d8-06c2-460c-8600-34f815fc6b29', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/z-image/base-lora-trainer', 'wavespeed-ai/z-image/base-lora-trainer', 'IMAGE', 1.25, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/z-image/base-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"URL to zip archive with images. Try to use at least 4 images in general the more the better. In addition to images the archive can contain text files with captions. Each text file should have the same name as the image file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing images.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0001,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":16,\"maximum\":64,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":1000,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":10000,\"minimum\":500,\"step\":10,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"Trigger word to be used in the captions. If None, a trigger word will not be used. If no captions are provided the trigger_word will be used instead of captions.\",\"nullable\":true,\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}', '{\"model_id\":\"wavespeed-ai/z-image/base-lora-trainer\",\"name\":\"wavespeed-ai/z-image/base-lora-trainer\",\"base_price\":1.25,\"formula\":\"{\\\"total_price\\\":base_price * (steps / 1000)}\",\"description\":\"Z-Image Base LoRA Trainer – train custom image LoRA models from your own dataset, with zip uploads, auto-tuned defaults and fast iteration for brand, character or IP looks. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"training\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/z-image/base-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"URL to zip archive with images. Try to use at least 4 images in general the more the better. In addition to images the archive can contain text files with captions. Each text file should have the same name as the image file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing images.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0001,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":16,\"maximum\":64,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":1000,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":10000,\"minimum\":500,\"step\":10,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"Trigger word to be used in the captions. If None, a trigger word will not be used. If no captions are provided the trigger_word will be used instead of captions.\",\"nullable\":true,\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}}', '2026-06-09 08:56:06.966', '2026-06-09 08:56:06.966', '2026-06-09 08:56:06.966');
INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('f881d419-5be8-4406-984d-90f5d3acc331', NULL, 'cmq0hadjp0000si8dckyresaj', 'bytedance/seedream-v4.5/edit', 'bytedance/seedream-v4.5/edit', 'IMAGE', 0.04, NULL, NULL, 9200, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedream-v4.5/edit\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"images\":{\"description\":\"The images to edit. A maximum of 10 reference images can be uploaded.\",\"items\":{\"type\":\"string\"},\"maxItems\":10,\"minItems\":1,\"type\":\"array\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"minLength\":1,\"type\":\"string\"},\"size\":{\"description\":\"Specify the width and height pixel values of the generated image.\",\"maximum\":8192,\"minimum\":512,\"type\":\"string\",\"x-hidden\":true}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"size\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"bytedance/seedream-v4.5/edit\",\"name\":\"bytedance/seedream-v4.5/edit\",\"base_price\":0.04,\"formula\":\"\",\"description\":\"ByteDance Seedream 4.5 Edit preserves facial features, lighting, and color tone from reference images, delivering professional, high-fidelity edits up to 4K with strong prompt adherence. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"image-to-image\",\"sort_order\":9200,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/bytedance/seedream-v4.5/edit\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"images\":{\"description\":\"The images to edit. A maximum of 10 reference images can be uploaded.\",\"items\":{\"type\":\"string\"},\"maxItems\":10,\"minItems\":1,\"type\":\"array\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"minLength\":1,\"type\":\"string\"},\"size\":{\"description\":\"Specify the width and height pixel values of the generated image.\",\"maximum\":8192,\"minimum\":512,\"type\":\"string\",\"x-hidden\":true}},\"required\":[\"prompt\",\"images\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"images\",\"size\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:05.593', '2026-06-09 08:56:05.593', '2026-06-09 08:56:05.593');
