ation\",\"loras\",\"high_noise_loras\",\"low_noise_loras\",\"seed\"]}}]}', '{\"model_id\":\"wavespeed-ai/wan-2.2/t2v-720p-lora\",\"name\":\"wavespeed-ai/wan-2.2/t2v-720p-lora\",\"base_price\":0.35,\"formula\":\"{\\\"total_price\\\": base_price * $number(duration) / 5}\",\"description\":\"Wan 2.2 T2V 720p with custom LoRA support turns text prompts into 720p AI videos and enables unlimited video generation. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"lora-support\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/wan-2.2/t2v-720p-lora\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"The duration of the generated media in seconds.\",\"enum\":[5,8],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"high_noise_loras\":{\"description\":\"List of high noise LoRAs to apply (max 3).\",\"items\":{\"$ref\":\"#/components/schemas/LoraWeight\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"loras\"},\"loras\":{\"description\":\"List of LoRAs to apply (max 3).\",\"items\":{\"$ref\":\"#/components/schemas/LoraWeight\"},\"maxItems\":3,\"type\":\"array\"},\"low_noise_loras\":{\"description\":\"List of low noise LoRAs to apply (max 3).\",\"items\":{\"$ref\":\"#/components/schemas/LoraWeight\"},\"maxItems\":3,\"type\":\"array\",\"x-ui-component\":\"loras\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1280*720\",\"description\":\"The size of the generated media in pixels (width*height).\",\"enum\":[\"1280*720\",\"720*1280\"],\"type\":\"string\"}},\"