ce * $number(number_of_songs)}\",\"description\":\"mureka ai / mureka v7.6 / generate song via Mureka official API.\",\"type\":\"text-to-audio\",\"sort_order\":10000,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/mureka-ai/mureka-v7.6/generate-song\",\"request_schema\":{\"properties\":{\"lyrics\":{\"description\":\"Lyrics for the generated song. Official limit: up to 3000 characters.\",\"type\":\"string\",\"x-rows\":8,\"x-ui-component\":\"textarea\"},\"melody_id\":{\"description\":\"Optional Mureka uploaded melody file ID.\",\"type\":\"string\"},\"number_of_songs\":{\"default\":1,\"description\":\"Number of generations. Mureka charges per generated item.\",\"maximum\":3,\"minimum\":1,\"title\":\"Number of Songs\",\"type\":\"integer\"},\"output_format\":{\"default\":\"mp3\",\"description\":\"Output audio format after re-uploading to WaveSpeed CDN.\",\"enum\":[\"mp3\",\"wav\",\"flac\"],\"type\":\"string\"},\"prompt\":{\"description\":\"Optional style prompt for the song. Official limit: up to 1024 characters.\",\"type\":\"string\",\"x-rows\":4,\"x-ui-component\":\"textarea\"},\"reference_id\":{\"description\":\"Optional Mureka uploaded reference file ID.\",\"type\":\"string\"},\"vocal_id\":{\"description\":\"Optional Mureka uploaded vocal file ID.\",\"type\":\"string\"}},\"required\":[\"lyrics\"],\"type\":\"object\",\"x-order-properties\":[\"lyrics\",\"prompt\",\"number_of_songs\",\"output_format\",\"reference_id\",\"vocal_id\",\"melody_id\"]}}]}}', '2026-06-09 08:56:05.491', '2026-06-09 08:56:05.491', '2026-06-09 08:56:05.491');
