INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('fa4e43e7-bb75-4e29-a10d-2e5caa6f8ab9', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/flux-2-klein-9b/text-to-image-lora', 'wavespeed-ai/flux-2-klein-9b/text-to-image-lora', 'IMAGE', 0.015, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-2-klein-9b/text-to-image-lora\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"loras\":{\"default\":[],\"description\":\"List of LoRAs to apply (maximum 3).\",\"items\":{\"$ref\":\"#/components/schemas/LoraWeight\"},\"maxItems\":3,\"type\":\"array\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"loras\",\"seed\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}', '{\"model_id\":\"wavespeed-ai/flux-2-klein-9b/text-to-image-lora\",\"name\":\"wavespeed-ai/flux-2-klein-9b/text-to-image-lora\",\"base_price\":0.015,\"formula\":\"\",\"description\":\"FLUX.2 [klein] 9B with LoRA support is a high-quality text-to-image model with 9B parameters, offering enhanced realism, crisper text generation, and fast LoRA customization. Ready-to-use REST inference API, best performance, no cold starts, affordable pricing.\",\"type\":\"lora-support\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/flux-2-klein-9b/text-to-image-lora\",\"request_schema\":{\"properties\":{\"enable_base64_output\":{\"default\":false,\"description\":\"If enabled, the output will be encoded into a BASE64 string instead of a URL. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"enable_sync_mode\":{\"default\":false,\"description\":\"If set to true, the function will wait for the result to be generated and uploaded before returning the response. It allows you to get the result directly in the response. This property is only available through the API.\",\"disabled\":true,\"type\":\"boolean\"},\"loras\":{\"default\":[],\"description\":\"List of LoRAs to apply (maximum 3).\",\"items\":{\"$ref\":\"#/components/schemas/LoraWeight\"},\"maxItems\":3,\"type\":\"array\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"type\":\"string\"},\"seed\":{\"default\":-1,\"description\":\"The random seed to use for the generation. -1 means a random seed will be used.\",\"type\":\"integer\"},\"size\":{\"default\":\"1024*1024\",\"description\":\"The size of the generated media in pixels (width*height).\",\"type\":\"string\"}},\"required\":[\"prompt\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"size\",\"loras\",\"seed\",\"enable_sync_mode\",\"enable_base64_output\"]}}]}}', '2026-06-09 08:56:06.896', '2026-06-09 08:56:06.896', '2026-06-09 08: