INSERT INTO `provider_model_snapshot` (`id`, `merchant_id`, `provider_id`, `model_id`, `name`, `model_type`, `base_price`, `discount_rate`, `promotion_discount_rate`, `sort_order`, `api_schema_json`, `raw_json`, `synced_at`, `created_at`, `updated_at`) VALUES ('faa83c2e-2e92-4f8d-b435-d04a7ea5950f', NULL, 'cmq0hadjp0000si8dckyresaj', 'wavespeed-ai/qwen-image-lora-trainer', 'wavespeed-ai/qwen-image-lora-trainer', 'IMAGE', 1, NULL, NULL, 100, '{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/qwen-image-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"URL to zip archive with images. Try to use at least 4 images in general the more the better.\\n\\n        In addition to images the archive can contain text files with captions. Each text file should have the same name as the image file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing images.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0004,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":16,\"maximum\":64,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":1000,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":10000,\"minimum\":500,\"step\":10,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"Trigger word to be used in the captions. If None, a trigger word will not be used.\\n        If no captions are provide the trigger_word will be used instead of captions. If captions are the trigger word will not be used.\",\"nullable\":true,\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}', '{\"model_id\":\"wavespeed-ai/qwen-image-lora-trainer\",\"name\":\"wavespeed-ai/qwen-image-lora-trainer\",\"base_price\":1,\"formula\":\"{\\\"total_price\\\":base_price * (steps / 1000)}\",\"description\":\"Train custom Qwen-Image LoRA models 10x faster. Style training, character training, object training. From concept to model in minutes, not hours. Upload a ZIP file containing images to start!\",\"type\":\"training\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/wavespeed-ai/qwen-image-lora-trainer\",\"request_schema\":{\"properties\":{\"data\":{\"description\":\"URL to zip archive with images. Try to use at least 4 images in general the more the better.\\n\\n        In addition to images the archive can contain text files with captions. Each text file should have the same name as the image file it corresponds to.\",\"type\":\"string\",\"x-accept\":\"application/zip\",\"x-placeholder\":\"Please upload a zip file containing images.\",\"x-ui-component\":\"uploader\"},\"learning_rate\":{\"default\":0.0004,\"maximum\":1,\"minimum\":0,\"step\":0.00001,\"type\":\"number\",\"x-ui-component\":\"slider\"},\"lora_rank\":{\"default\":16,\"maximum\":64,\"minimum\":1,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"steps\":{\"default\":1000,\"description\":\"Number of steps to train the LoRA on.\",\"maximum\":10000,\"minimum\":500,\"step\":10,\"type\":\"integer\",\"x-ui-component\":\"slider\"},\"trigger_word\":{\"default\":\"p3r5on\",\"description\":\"Trigger word to be used in the captions. If None, a trigger word will not be used.\\n        If no captions are provide the trigger_word will be used instead of captions. If captions are the trigger word will not be used.\",\"nullable\":true,\"type\":\"string\"}},\"required\":[\"data\"],\"type\":\"object\",\"x-order-properties\":[\"data\",\"trigger_word\",\"steps\",\"learning_rate\",\"lora_rank\"]}}]}}', '2026-06-09 08:56:07.475', '2026-06-09 08:56:07.475', '2026-06-09 08:56:07.475');
