solution = \\\"720p\\\" ? 700000 * 2 : 700000 * 2)) : (resolution = \\\"360p\\\") ? 500000 : (resolution = \\\"540p\\\" ? 500000 : (resolution = \\\"720p\\\" ? 700000 : 700000))}\",\"description\":\"Pixverse V4.5 I2V Fast converts images or text into high-quality videos with multi-resolution, aspect-ratio and motion-mode control. Ready-to-use REST inference API, best performance, no coldstarts, affordable pricing.\",\"type\":\"image-to-video\",\"sort_order\":100,\"api_schema\":{\"api_schemas\":[{\"type\":\"model_run\",\"method\":\"POST\",\"server\":\"https://api.wavespeed.ai\",\"api_path\":\"/api/v3/pixverse/pixverse-v4.5-i2v-fast\",\"request_schema\":{\"properties\":{\"duration\":{\"default\":5,\"description\":\"Video duration in seconds.\",\"enum\":[5],\"type\":\"integer\",\"x-ui-component\":\"select\"},\"image\":{\"description\":\"First frame of the video; Supported image formats include.jpg/.jpeg/.png; The image file size cannot exceed 10MB, and the image resolution should not be less than 300*300px, and the aspect ratio of the image should be between 1:2.5 ~ 2.5:1.\",\"type\":\"string\"},\"negative_prompt\":{\"description\":\"The negative prompt for the generation.\",\"maxLength\":2048,\"type\":\"string\"},\"prompt\":{\"description\":\"The positive prompt for the generation.\",\"maxLength\":2048,\"type\":\"string\"},\"resolution\":{\"default\":\"540p\",\"description\":\"Video quality (360p/540p/720p/1080p).\",\"enum\":[\"360p\",\"540p\",\"720p\"],\"type\":\"string\",\"x-ui-component\":\"select\"},\"seed\":{\"description\":\"The random seed to use for the generation.\",\"type\":\"integer\"}},\"required\":[\"prompt\",\"image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"resolution\",\"duration\",\"negative_prompt\",\"seed\"]}}]}}', '2026-06-09 08:56:06.694', '2026-06-09 08:56:06.694', '2026-06-09 08:56:06.694');
