\",\"image\",\"last_image\"],\"type\":\"object\",\"x-order-properties\":[\"prompt\",\"image\",\"last_image\",\"duration\",\"resolution\",\"bgm\",\"generate_audio\",\"movement_amplitude\",\"seed\"]}}]}}', '2026-06-09 08:56:05.757', '2026-06-09 08:56:05.757', '2026-06-09 08:56:05.757');
